    "premium_bms_battery_connected",
    "premium_bms_charge_allowed",
    "premium_bms_discharge_allowed",
    "premium_bms_force_ac_charge",
    "premium_q1_fan_locked",

    // ancien champ supprimé
    "premium_q1_converter_temperature"
  ];

  legacyDiagKeys.forEach((k) => {
    if (k in data.diag) delete data.diag[k];
