return [
  {
    topic: `voltronic/${inv}/state`,
    payload: JSON.stringify(data),
    retain: true
  },
  {
    topic: `voltronic/${inv}/availability`,
    payload: "online",
    retain: true
  }
];

const inv = msg.inverterNum ?? 1;

const qKey = `inv${inv}_queue`;
const inFlightKey = `inv${inv}_inflight`;
const pausePollingUntilKey = `inv${inv}_pause_polling_until`;

let q = flow.get(qKey);
if (!Array.isArray(q)) q = [];

const inFlight = flow.get(inFlightKey);
const now = Date.now();

// -------------------------------------------------
// Helpers
// -------------------------------------------------
function getQpigs2State() {
    const qpKey = `inv${inv}_qpigs2_state`;
    let st = flow.get(qpKey);

    if (!st || typeof st !== "object") {
        st = {
            fail_count: 0,
            disabled: false,
            last_try: 0,
            last_ok: 0,
            last_fail: 0,
            reason: ""
        };
        flow.set(qpKey, st);
    }

    return st;
}

function asArray(input) {
    if (Array.isArray(input)) return input;
    if (Array.isArray(input?.payload) && input.payload?.[0]?.command) return input.payload;
    return [input];
}

function cleanStr(v) {
    return String(v ?? "").trim();
}

function normalizeCmd(m) {
    if (!m || typeof m !== "object") return null;

    const rawCommand = cleanStr(m._raw_command || m.command || m._cmd || m.payload);
    const cmd = rawCommand.toUpperCase();

    if (!cmd) return null;

    const origin = cleanStr(m._origin);
    const explicitPriority = m._priority === true;

    const isPriority =
        explicitPriority ||
        origin === "ha_set" ||
        origin === "learn_retry" ||
        origin === "poll_fast_fault" ||
        origin === "poll_fault_trigger";

    return {
        inverterNum: m.inverterNum ?? inv,
        command: cmd,
        _cmd: cmd,
        _raw_command: rawCommand || cmd,
        payload: cmd,

        _origin: origin,
        _burst: m._burst === true,
        _learn: m._learn || null,
        _qpigs2_probe: m._qpigs2_probe === true,
        _raw_manual: m._raw_manual === true,
        _priority: explicitPriority,

        enqueued_ts: now,
        priority: isPriority
    };
}

function getDedupeKey(item) {
    return String(item.command || "").trim().toUpperCase();
}

function isCriticalOrigin(origin) {
    return (
        origin === "ha_set" ||
        origin === "learn_retry" ||
        origin === "poll_fast_fault" ||
        origin === "poll_fault_trigger"
    );
}

function isPollingOrigin(origin) {
    return origin.startsWith("poll");
}

// -------------------------------------------------
// Prépare la liste à ajouter
// -------------------------------------------------
const incoming = asArray(msg);
const toPush = [];

for (const m of incoming) {
    const item = normalizeCmd(m);
    if (!item) continue;
    toPush.push(item);
}

if (toPush.length === 0) return null;

// -------------------------------------------------
// Pause polling si commande HA / manuelle
// -------------------------------------------------
let pauseUntil = Number(flow.get(pausePollingUntilKey) || 0);

// si une vraie commande utilisateur arrive → pause courte
const hasHaSet = toPush.some(x => x._origin === "ha_set");
if (hasHaSet) {
    pauseUntil = now + 2500; // 2.5 s de fenêtre prioritaire
    flow.set(pausePollingUntilKey, pauseUntil);
}

// -------------------------------------------------
// Si pause active : on ignore les commandes de polling
// non critiques qui arrivent pendant cette fenêtre
// -------------------------------------------------
const pauseActive = pauseUntil > now;
const filteredToPush = [];

for (const item of toPush) {
    const origin = cleanStr(item._origin);

    if (
        pauseActive &&
        isPollingOrigin(origin) &&
        !isCriticalOrigin(origin)
    ) {
        continue;
    }

    filteredToPush.push(item);
}

if (filteredToPush.length === 0) {
    return {
        inverterNum: inv,
        topic: "pump"
    };
}

// -------------------------------------------------
// Dédoublonnage intelligent
// - on évite d’empiler 50 fois les mêmes polls
// - on garde toujours les ha_set
// -------------------------------------------------
const inFlightCmd = inFlight?.cmd ? String(inFlight.cmd).toUpperCase() : "";
const existingKeys = new Set(
    q.map(x => getDedupeKey(x)).filter(Boolean)
);

let added = 0;
let dropped = 0;

for (const item of filteredToPush) {
    const key = getDedupeKey(item);
    const origin = cleanStr(item._origin);

    // Toujours garder les commandes user / fault
    const mustKeep = isCriticalOrigin(origin);

    // Si même commande déjà inflight ou déjà en queue
    if (!mustKeep) {
        if ((inFlightCmd && inFlightCmd === key) || existingKeys.has(key)) {
            dropped++;
            continue;
        }
    }

    // si QPIGS2 désactivé, ne pas l’empiler
    if (key === "QPIGS2") {
        const st = getQpigs2State();
        if (st && st.disabled === true) {
            dropped++;
            continue;
        }
    }

    if (item.priority) {
        q.unshift(item);
    } else {
        q.push(item);
    }

    existingKeys.add(key);
    added++;
}

// -------------------------------------------------
// Pendant pause active : on nettoie la queue des polls
// non critiques déjà présents, pour laisser passer le ha_set
// -------------------------------------------------
pauseUntil = Number(flow.get(pausePollingUntilKey) || 0);
if (pauseUntil > now) {
    q = q.filter(item => {
        const origin = cleanStr(item?._origin);
        if (!isPollingOrigin(origin)) return true;
        return isCriticalOrigin(origin);
    });
}

// limite sécurité
if (q.length > 200) {
    q = q.slice(0, 200);
}

flow.set(qKey, q);

const head = q[0];
const headTxt = head
    ? `${head.command}${head.priority ? " !" : ""}`
    : "empty";

const pauseLeftMs = Math.max(0, Number(flow.get(pausePollingUntilKey) || 0) - now);
const pauseTxt = pauseLeftMs > 0 ? ` pause:${Math.ceil(pauseLeftMs / 1000)}s` : "";

node.status({
    fill: "blue",
    shape: "dot",
    text: `q:${q.length} +${added}${dropped ? ` -${dropped}` : ""} [${headTxt}]${pauseTxt}`
});

// déclenche le pump
return {
    inverterNum: inv,
    topic: "pump"
};

// HA SET -> Voltronic CMD
// 2 sorties:
//   1) paramètres gérés par apprentissage
//   2) commandes directes vers Queue Enqueue
//
// topic: voltronic/<inv>/set/<param>
// payload: valeur

const m = String(msg.topic || "").match(/^voltronic\/(\d+)\/set\/(.+)$/);
if (!m) return null;

const inverterNum = Number(m[1]);
const param = String(m[2] || "").trim();

if (!Number.isFinite(inverterNum) || !param) return null;

// -------------------------------------------------
// Normalisation payload
// -------------------------------------------------
function cleanString(v) {
  let s = String(v ?? "").trim();
  if (!s) return "";

  s = s.replace(/^"+|"+$/g, "");

  try {
    if (
      s.startsWith('\\"') ||
      (s.startsWith('"') && s.endsWith('"'))
    ) {
      const parsed = JSON.parse(s);
      if (typeof parsed === "string") s = parsed;
    }
  } catch (e) {
    // ignore
  }

  return String(s ?? "").trim().replace(/^"+|"+$/g, "");
}

let v = msg.payload;
if (typeof v === "string") {
  v = cleanString(v);
}

// -------------------------------------------------
// Helpers
// -------------------------------------------------
const toNum = (x) => {
  if (x == null) return null;

  if (typeof x === "string") {
    const s = cleanString(x);
    const m = s.match(/-?\d+(\.\d+)?/);
    if (!m) return null;
    x = m[0];
  }

  const n = Number(x);
  return Number.isFinite(n) ? n : null;
};

const clamp = (x, a, b) => Math.min(b, Math.max(a, Number(x)));
const pad3 = (x) => String(Math.trunc(Number(x))).padStart(3, "0");

const mk = (c, extra = {}) => ({
  inverterNum,
  command: c,
  _cmd: c,
  payload: c,
  _burst: true,
  _origin: extra._origin || "ha_set",
  ...extra
});

function getParallelId(inv) {
  let machine = flow.get(`inv${inv}_parallel_id`);
  if (machine === undefined || machine === null || machine === "") machine = 0;
  machine = Number(machine);
  if (!Number.isFinite(machine) || machine < 0 || machine > 9) machine = 0;
  return machine;
}

function normKey(v) {
  return cleanString(v)
    .toLowerCase()
    .replace(/\s+/g, "")
    .replace(/\+/g, "plus");
}

function isTwoChoiceOutputPriorityEnabled(inv) {
  return global.get(`inverter_${inv}.output_priority_2choices`) === true;
}

function parseBoolLike(v) {
  if (typeof v === "boolean") return v;
  if (typeof v === "number") return v !== 0;

  const s = normKey(v);

  if (["1", "on", "true", "enable", "enabled"].includes(s)) return true;
  if (["0", "off", "false", "disable", "disabled"].includes(s)) return false;

  return null;
}

// -------------------------------------------------
// Plages tensions selon système batterie
// -------------------------------------------------
function getBatterySystemVoltage() {
  const sysV = Number(
    global.get("config.batterySystemVoltage") ||
    global.get("battery_system_voltage") ||
    48
  );
  return sysV === 24 ? 24 : 48;
}

function getVoltageRanges() {
  const sysV = getBatterySystemVoltage();

  if (sysV === 24) {
    return {
      battery_bulk_voltage: { min: 24, max: 30, decimals: 1 },
      battery_float_voltage: { min: 24, max: 30, decimals: 1 },
      battery_recharge_voltage: { min: 22, max: 25.5, decimals: 1 },
      battery_re_discharge_voltage: { min: 24, max: 29, decimals: 1 },
      battery_under_voltage: { min: 20, max: 27, decimals: 1 }
    };
  }

  return {
    battery_bulk_voltage: { min: 40, max: 65, decimals: 1 },
    battery_float_voltage: { min: 40, max: 65, decimals: 1 },
    battery_recharge_voltage: { min: 40, max: 65, decimals: 1 },
    battery_re_discharge_voltage: { min: 40, max: 65, decimals: 1 },
    battery_under_voltage: { min: 40, max: 65, decimals: 1 }
  };
}

function validateVoltageParam(paramName, rawValue) {
  const ranges = getVoltageRanges();
  const rule = ranges[paramName];
  if (!rule) {
    return { ok: false, value: null, reason: "unknown_param" };
  }

  const n = toNum(rawValue);
  if (n == null) {
    return { ok: false, value: null, reason: "not_a_number", rule };
  }

  if (n < rule.min || n > rule.max) {
    return { ok: false, value: n, reason: "out_of_range", rule };
  }

  const factor = 10 ** (rule.decimals || 1);
  const rounded = Math.round(n * factor) / factor;

  return { ok: true, value: rounded, rule };
}

function rejectInvalidVoltage(paramName, rawValue) {
  const res = validateVoltageParam(paramName, rawValue);
  if (res.ok) return res;

  const txt = res.rule
    ? `${paramName} out of range (${res.rule.min}-${res.rule.max}V)`
    : `${paramName} invalid`;

  node.status({
    fill: "red",
    shape: "ring",
    text: txt
  });

  return null;
}

// -------------------------------------------------
// Paramètres apprenables
// -------------------------------------------------
function canonLearnParam(p) {
  const s = cleanString(p);

  const map = {
    battery_bulk_voltage: "battery_bulk_voltage",
    battery_float_voltage: "battery_float_voltage",

    battery_cutoff_voltage: "battery_under_voltage",
    battery_under_voltage: "battery_under_voltage",

    back_to_grid_voltage: "battery_recharge_voltage",
    battery_recharge_voltage: "battery_recharge_voltage",

    back_to_battery_voltage: "battery_re_discharge_voltage",
    battery_re_discharge_voltage: "battery_re_discharge_voltage",

    max_charging_current: "max_charging_current",

    grid_charging_current: "max_ac_charging_current",
    max_ac_charging_current: "max_ac_charging_current",

    charger_source_priority: "charger_source_priority",
    output_source_priority: "output_source_priority"
  };

  return map[s] || s;
}

function isLearnableParam(p) {
  const lp = canonLearnParam(p);
  return [
    "battery_bulk_voltage",
    "battery_float_voltage",
    "battery_under_voltage",
    "battery_recharge_voltage",
    "battery_re_discharge_voltage",
    "max_charging_current",
    "max_ac_charging_current",
    "charger_source_priority",
    "output_source_priority"
  ].includes(lp);
}

// -------------------------------------------------
// OUTPUT SOURCE PRIORITY
// -------------------------------------------------
function getForcedTwoChoiceOutputCommand(v) {
  const raw = cleanString(v);
  const key = normKey(v);

  if (raw === "0" || key === "0") return "POP00";
  if (raw === "1" || key === "1") return "POP01";

  const map = {
    sub: "POP00",
    solarutilitybat: "POP00",

    sbu: "POP01",
    solarbatutility: "POP01",

    usb: null,
    utilitysolarbat: null
  };

  return Object.prototype.hasOwnProperty.call(map, key) ? map[key] : null;
}

function getOutputPrioritySlotNormal(v) {
  const raw = cleanString(v);
  const key = normKey(v);

  if (raw === "0" || key === "0") return 0;
  if (raw === "1" || key === "1") return 1;
  if (raw === "2" || key === "2") return 2;

  const map = {
    utilitysolarbat: 0,
    usb: 0,

    solarutilitybat: 1,
    sub: 1,

    solarbatutility: 2,
    sbu: 2
  };

  return Number.isInteger(map[key]) ? map[key] : null;
}

// -------------------------------------------------
// CHARGER SOURCE PRIORITY
// -------------------------------------------------
function getChargerPrioritySlot(v) {
  const raw = cleanString(v);
  const key = normKey(v);

  if (raw === "0" || key === "0") return 0;
  if (raw === "1" || key === "1") return 1;
  if (raw === "2" || key === "2") return 2;

  const map = {
    solarfirst: 0,
    cso: 0,

    solarplusutility: 1,
    solarutility: 1,
    snu: 1,

    onlysolar: 2,
    oso: 2
  };

  return Number.isInteger(map[key]) ? map[key] : null;
}

// -------------------------------------------------
// RAW COMMAND MANUELLE
// -------------------------------------------------
if (param === "raw_command") {
  const cmd = cleanString(v);
  if (!cmd) return null;

  flow.set(`inv${inverterNum}_raw_pending`, {
    active: true,
    command: cmd,
    ts: Date.now()
  });

  const rawMsg = mk(cmd, {
    _burst: false,
    _origin: "ha_set",
    _raw_manual: true,
    _raw_command: cmd,
    _ha_param: "raw_command",
    _ha_value: v
  });

  node.status({
    fill: "yellow",
    shape: "dot",
    text: `RAW ${cmd}`
  });

  return [null, [rawMsg]];
}

// -------------------------------------------------
// OUTPUT SOURCE PRIORITY EN MODE 2 CHOIX FORCE
// -------------------------------------------------
if (param === "output_source_priority" && isTwoChoiceOutputPriorityEnabled(inverterNum)) {
  const cmd = getForcedTwoChoiceOutputCommand(v);

  if (!cmd) {
    node.status({
      fill: "red",
      shape: "ring",
      text: "output priority unsupported"
    });
    return null;
  }

  const setMsg = mk(cmd, {
    _burst: false,
    _origin: "ha_set",
    _ha_param: param,
    _ha_value: v
  });

  const refreshMsgs = ["QPIRI", "QMOD", "QPIGS"].map(c => mk(c, {
    _origin: "ha_refresh",
    _from_param: param
  }));

  const out = [setMsg, ...refreshMsgs];

  node.status({
    fill: "green",
    shape: "dot",
    text: `SET ${param} (${cmd}) forced 2-choice`
  });

  return [null, out];
}

// -------------------------------------------------
// PARAMÈTRES APPRENABLES
// -------------------------------------------------
if (isLearnableParam(param)) {
  const learnParam = canonLearnParam(param);

  let learnValue = v;
  let learnMode = "number";

  // validation tensions avant apprentissage
  if ([
    "battery_bulk_voltage",
    "battery_float_voltage",
    "battery_under_voltage",
    "battery_recharge_voltage",
    "battery_re_discharge_voltage"
  ].includes(learnParam)) {
    const valid = rejectInvalidVoltage(learnParam, v);
    if (!valid) return null;
    learnValue = valid.value;
    learnMode = "number";
  }

  if (learnParam === "output_source_priority") {
    const slot = getOutputPrioritySlotNormal(v);

    if (slot == null) {
      node.status({
        fill: "red",
        shape: "ring",
        text: "output priority unsupported"
      });
      return null;
    }

    learnValue = slot;
    learnMode = "enum_profile";
  }

  if (learnParam === "charger_source_priority") {
    const slot = getChargerPrioritySlot(v);

    if (slot == null) {
      node.status({
        fill: "red",
        shape: "ring",
        text: "charger priority unsupported"
      });
      return null;
    }

    learnValue = slot;
    learnMode = "enum_profile";
  }

  const learnMsg = {
    inverterNum,
    topic: msg.topic,
    payload: learnValue,
    _origin: "ha_set",
    _ha_param: learnParam,
    _ha_param_raw: param,
    _ha_value: learnValue,
    _ha_value_raw: v,
    _learn_mode: learnMode
  };

  node.status({
    fill: "blue",
    shape: "dot",
    text: `LEARN ${learnParam}`
  });

  return [learnMsg, null];
}

// -------------------------------------------------
// Tables de mapping direct (hors apprentissage)
// -------------------------------------------------
const batteryTypeMap = {
  AGM: "PBT00",
  Flooded: "PBT01",
  User: "PBT02",
  Pylon: "PBT03",
  Weco: "PBT05",
  Soltaro: "PBT06",
  Lib: "PBT08",
  Lic: "PBT09"
};

// -------------------------------------------------
// Résolution commande directe
// -------------------------------------------------
const machine = getParallelId(inverterNum);

let cmd = null;
let refresh = ["QMOD", "QPIGS"];

// ----- switchs flags QFLAG -----
if (param === "overload_bypass") {
  const b = parseBoolLike(v);
  if (b == null) return null;

  cmd = b ? "PEb" : "PDb";
  refresh = ["QFLAG", "QMOD", "QPIGS"];

} else if (param === "fault_auto_restart") {
  const b = parseBoolLike(v);
  if (b == null) return null;

  cmd = b ? "PEu" : "PDu";
  refresh = ["QFLAG", "QMOD", "QPIGS"];

} else if (param === "over_temperature_restart") {
  const b = parseBoolLike(v);
  if (b == null) return null;

  cmd = b ? "PEv" : "PDv";
  refresh = ["QFLAG", "QMOD", "QPIGS"];

} else if (param === "battery_type") {
  const sv = cleanString(v);
  cmd = batteryTypeMap[sv] || null;
  refresh = ["QPIRI", "QMOD", "QPIGS"];

} else if (param === "max_discharging_current") {
  const sv = cleanString(v);
  if (sv === "0") return null;

  const nv = toNum(sv);
  if (nv == null) return null;

  cmd = `PBATMAXDISC${pad3(clamp(nv, 1, 200))}`;
  refresh = ["QPIRI", "QPIGS"];

} else if (param === "battery_recharge_capacity_pct") {
  const nv = toNum(v);
  if (nv == null) return null;
  cmd = `PBCC${pad3(clamp(nv, 5, 95))}`;
  refresh = ["QDOP", "QPIGS"];

} else if (param === "battery_redischarge_capacity_pct") {
  const nv = toNum(v);
  if (nv == null) return null;
  cmd = `PBDC${pad3(clamp(nv, 10, 100))}`;
  refresh = ["QDOP", "QPIGS"];

} else if (param === "battery_under_capacity_pct") {
  const nv = toNum(v);
  if (nv == null) return null;
  cmd = `PSDC${pad3(clamp(nv, 0, 90))}`;
  refresh = ["QDOP", "QPIGS"];
}

if (!cmd) return null;

// -------------------------------------------------
// Construction sortie directe
// -------------------------------------------------
const setMsg = mk(cmd, {
  _burst: false,
  _origin: "ha_set",
  _ha_param: param,
  _ha_value: v
});

const refreshMsgs = refresh.map(c => mk(c, {
  _origin: "ha_refresh",
  _from_param: param
}));

const out = [setMsg, ...refreshMsgs];

node.status({
  fill: "green",
  shape: "dot",
  text: `SET ${param} (${cmd}) + refresh x${refreshMsgs.length}`
});

return [null, out];

// Transport Select (2 outputs): [SERIAL, TCP]
const inv = Number(msg.inverterNum || 1);

let t =
    (msg.transport || "").toString().toLowerCase().trim() ||
    (flow.get(`inv${inv}_transport`) || "").toString().toLowerCase().trim() ||
    (env.get(`INV${inv}_TRANSPORT`) || "").toString().toLowerCase().trim() ||
    "serial";

if (t !== "tcp" && t !== "serial") t = "serial";
msg.transport = t;

msg.tcpHost =
    msg.tcpHost ||
    flow.get(`inv${inv}_tcp_host`) ||
    env.get(`INV${inv}_TCP_HOST`) ||
    "192.168.1.40";

msg.tcpPort =
    Number(
        msg.tcpPort ||
        flow.get(`inv${inv}_tcp_port`) ||
        env.get(`INV${inv}_TCP_PORT`) ||
        8899
    ) || 8899;

if (t === "tcp") return [null, msg];
return [msg, null];

msg.inverterNum = 2;
if (!Buffer.isBuffer(msg.payload)) return null;
return msg;

// TCP TX gate: ne laisse passer que si Transport Select a choisi TCP
if ((msg.transport || "").toString().toLowerCase() !== "tcp") return null;

// sécurité: on envoie uniquement un Buffer (commande construite)
if (!Buffer.isBuffer(msg.payload)) return null;

return msg;

// Transport Select (2 outputs): [SERIAL, TCP]
const inv = Number(msg.inverterNum || 1);

let t =
    (msg.transport || "").toString().toLowerCase().trim() ||
    (flow.get(`inv${inv}_transport`) || "").toString().toLowerCase().trim() ||
    (env.get(`INV${inv}_TRANSPORT`) || "").toString().toLowerCase().trim() ||
    "serial";

if (t !== "tcp" && t !== "serial") t = "serial";
msg.transport = t;

msg.tcpHost =
    msg.tcpHost ||
    flow.get(`inv${inv}_tcp_host`) ||
    env.get(`INV${inv}_TCP_HOST`) ||
    "192.168.1.40";

msg.tcpPort =
    Number(
        msg.tcpPort ||
        flow.get(`inv${inv}_tcp_port`) ||
        env.get(`INV${inv}_TCP_PORT`) ||
        8899
    ) || 8899;

if (t === "tcp") return [null, msg];
return [msg, null];

// TCP TX gate: ne laisse passer que si Transport Select a choisi TCP
if ((msg.transport || "").toString().toLowerCase() !== "tcp") return null;

// sécurité: on envoie uniquement un Buffer (commande construite)
if (!Buffer.isBuffer(msg.payload)) return null;

return msg;

msg.inverterNum = 1;
if (!Buffer.isBuffer(msg.payload)) return null;
return msg;

const inv = msg.inverterNum ?? 1;

const qKey = `inv${inv}_queue`;
const inFlightKey = `inv${inv}_inflight`;
const pendingLearnKey = `learn_pending_inv${inv}`;

// -------------------------------------------------
// Helpers QPIGS2
// -------------------------------------------------
function getQpigs2State() {
    const key = `inv${inv}_qpigs2_state`;
    let st = flow.get(key);

    if (!st || typeof st !== "object") {
        st = {
            score: 0,
            fail_count: 0,
            mode: "normal",
            disabled: false,
            last_try: 0,
            last_ok: 0,
            last_fail: 0,
            last_nak: 0,
            last_timeout: 0,
            last_invalid: 0,
            retry_after: 0,
            reason: ""
        };
        flow.set(key, st);
    }

    if (!st.mode) {
        st.mode = st.disabled ? "disabled" : "normal";
    }

    return st;
}

function setQpigs2State(st) {
    st.disabled = (st.mode === "disabled");
    st.fail_count = Number(st.score || st.fail_count || 0);
    flow.set(`inv${inv}_qpigs2_state`, st);
}

function markQpigs2Fail(reason) {
    const st = getQpigs2State();
    st.score = Number(st.score || 0) + 1;
    st.last_fail = Date.now();
    st.last_timeout = Date.now();
    st.reason = reason || "timeout";

    if (st.score >= 7) {
        st.mode = "disabled";
        st.retry_after = Date.now() + (2 * 60 * 1000);
    } else if (st.score >= 3) {
        st.mode = "degraded";
        st.retry_after = 0;
    } else {
        st.mode = "normal";
        st.retry_after = 0;
    }

    setQpigs2State(st);
    return st;
}

// -------------------------------------------------
// Helpers généraux
// -------------------------------------------------
function cleanStr(v) {
    return String(v ?? "").trim();
}

function getTimeoutMs(cmd, origin) {
    if (origin === "ha_set" || origin === "learn_retry") return 4000;
    if (cmd === "QPIRI" || cmd === "QDOP") return 4000;
    return 3000;
}

function normalizeOut(item) {
    const rawCommand = cleanStr(item?._raw_command || item?.command || item?._cmd || item?.payload);
    const cmd = rawCommand.toUpperCase();

    if (!cmd) return null;

    return {
        ...item,
        inverterNum: item?.inverterNum ?? inv,
        command: cmd,
        _cmd: cmd,
        _raw_command: rawCommand || cmd,
        payload: cmd
    };
}

// -------------------------------------------------
// 0) Gère l'inflight courant
// -------------------------------------------------
let inFlight = flow.get(inFlightKey);
let timeoutEvent = null;

if (inFlight) {
    const now = Date.now();
    const age = now - Number(inFlight.ts || 0);
    const timeoutMs = Number(inFlight.timeoutMs || 3000);

    if (age < timeoutMs) {
        return [null, null];
    }

    const timedOutCmd = cleanStr(inFlight.cmd).toUpperCase();
    const timedOutRaw = cleanStr(inFlight.raw || timedOutCmd);
    const timedOutOrigin = cleanStr(inFlight.origin);

    if (timedOutCmd === "QPIGS2") {
        const st = markQpigs2Fail("timeout");

        node.status({
            fill: st.mode === "disabled" ? "red" : "yellow",
            shape: st.mode === "disabled" ? "ring" : "dot",
            text: st.mode === "disabled"
                ? `QPIGS2 timeout disable (${st.fail_count})`
                : (st.mode === "degraded"
                    ? `QPIGS2 timeout degraded (${st.fail_count})`
                    : `QPIGS2 timeout (${st.fail_count})`)
        });
    }

    const pendingLearn = flow.get(pendingLearnKey);

    if (
        pendingLearn &&
        String(pendingLearn.cmd || "").trim().toUpperCase() === timedOutCmd
    ) {
        timeoutEvent = {
            inverterNum: inv,
            topic: "learn_timeout",
            payload: {
                inverter: inv,
                command: timedOutCmd,
                raw_command: timedOutRaw,
                raw_response: null,
                timeout: true,
                nak: false,
                raw: null,
                fields: [],
                nums: [],
                value: null
            },
            _cmd: timedOutCmd,
            command: timedOutCmd,
            _raw_command: timedOutRaw,
            _learn_timeout: true,
            _origin: timedOutOrigin || "timeout"
        };

        flow.set(pendingLearnKey, null);

        node.status({
            fill: "red",
            shape: "ring",
            text: `LEARN TIMEOUT ${pendingLearn.param || timedOutCmd}`
        });
    }

    flow.set(inFlightKey, null);
    inFlight = null;
}

// -------------------------------------------------
// 1) Lit la queue
// -------------------------------------------------
let q = flow.get(qKey);
if (!Array.isArray(q) || q.length === 0) {
    return [null, timeoutEvent];
}

q = q.filter(x => x && (x.command || x._cmd || x.payload));
if (q.length === 0) {
    flow.set(qKey, []);
    return [null, timeoutEvent];
}

// -------------------------------------------------
// 2) Dépile la prochaine commande
// -------------------------------------------------
const next = q.shift();
flow.set(qKey, q);

const out = normalizeOut(next);
if (!out) {
    return [{
        inverterNum: inv,
        topic: "pump"
    }, timeoutEvent];
}

const cmd = out.command;
const origin = cleanStr(out._origin);
const timeoutMs = getTimeoutMs(cmd, origin);
const isPriority = out.priority === true || out._priority === true;

// -------------------------------------------------
// 3) Marque inflight
// -------------------------------------------------
flow.set(inFlightKey, {
    cmd,
    raw: out._raw_command || cmd,
    ts: Date.now(),
    timeoutMs,

    inverterNum: inv,
    origin: origin,
    learn: out._learn || null,
    raw_manual: out._raw_manual === true,
    enqueued_ts: out.enqueued_ts || null,
    priority: isPriority
});

// -------------------------------------------------
// 4) Statut visuel
// -------------------------------------------------
let fill = "green";
if (origin === "ha_set" || origin === "learn_retry") fill = "yellow";
if (origin === "poll_fast_fault" || origin === "poll_fault_trigger" || isPriority) fill = "red";

const shortOrigin = origin || "poll";
const prioTxt = isPriority ? " !" : "";

node.status({
    fill,
    shape: "dot",
    text: `${cmd}${prioTxt} [${shortOrigin}] (${q.length} left)`
});

// -------------------------------------------------
// 5) Envoi au node "construire commande"
// -------------------------------------------------
return [out, timeoutEvent];

// Transport Select (2 outputs): [SERIAL, TCP]
const inv = Number(msg.inverterNum || 1);

let t =
    (msg.transport || "").toString().toLowerCase().trim() ||
    (flow.get(`inv${inv}_transport`) || "").toString().toLowerCase().trim() ||
    (env.get(`INV${inv}_TRANSPORT`) || "").toString().toLowerCase().trim() ||
    "serial";

if (t !== "tcp" && t !== "serial") t = "serial";
msg.transport = t;

msg.tcpHost =
    msg.tcpHost ||
    flow.get(`inv${inv}_tcp_host`) ||
    env.get(`INV${inv}_TCP_HOST`) ||
    "192.168.1.40";

msg.tcpPort =
    Number(
        msg.tcpPort ||
        flow.get(`inv${inv}_tcp_port`) ||
        env.get(`INV${inv}_TCP_PORT`) ||
        8899
    ) || 8899;

if (t === "tcp") return [null, msg];
return [msg, null];

// TCP TX gate: ne laisse passer que si Transport Select a choisi TCP
if ((msg.transport || "").toString().toLowerCase() !== "tcp") return null;

// sécurité: on envoie uniquement un Buffer (commande construite)
if (!Buffer.isBuffer(msg.payload)) return null;

return msg;

msg.inverterNum = 3;
if (!Buffer.isBuffer(msg.payload)) return null;
return msg;

// ====== LEARNING - PREPROCESS ======
// Sortie 1 = apprentissage
// Sortie 2 = bypass direct

const inv = msg.inverterNum ?? 1;

function cleanString(v) {
    return String(v ?? "").trim();
}

function toNum(x) {
    if (x == null) return null;
    if (typeof x === "string") {
        const s = cleanString(x);
        const m = s.match(/-?\d+(\.\d+)?/);
        if (!m) return null;
        x = m[0];
    }
    const n = Number(x);
    return Number.isFinite(n) ? n : null;
}

function clone(obj) {
    return JSON.parse(JSON.stringify(obj || {}));
}

function getByPath(obj, path) {
    if (!obj || !path) return undefined;
    return path.split(".").reduce((acc, k) => acc && acc[k], obj);
}

function getFingerprint(state) {
    const model = cleanString(state?.diag?.model);
    const serial = cleanString(state?.diag?.serial);
    const fw = cleanString(state?.diag?.fw_main);

    if (serial) return `SERIAL:${serial}`;
    if (model && fw) return `MODELFW:${model}|${fw}`;
    if (model) return `MODEL:${model}`;
    if (fw) return `FW:${fw}`;

    return "";
}

function canonParam(p) {
    const map = {
        battery_bulk_voltage: "battery_bulk_voltage",
        battery_float_voltage: "battery_float_voltage",

        battery_cutoff_voltage: "battery_under_voltage",
        battery_under_voltage: "battery_under_voltage",

        back_to_grid_voltage: "battery_recharge_voltage",
        battery_recharge_voltage: "battery_recharge_voltage",

        back_to_battery_voltage: "battery_re_discharge_voltage",
        battery_re_discharge_voltage: "battery_re_discharge_voltage",

        max_charging_current: "max_charging_current",

        grid_charging_current: "max_ac_charging_current",
        max_ac_charging_current: "max_ac_charging_current",

        charger_source_priority: "charger_source_priority",
        output_source_priority: "output_source_priority"
    };

    return map[cleanString(p)] || cleanString(p);
}

function getRegistry() {
    return {
        battery_bulk_voltage: {
            kind: "number",
            statePath: "params.qpiri.battery_bulk_voltage",
            tolerance: 0.05
        },
        battery_float_voltage: {
            kind: "number",
            statePath: "params.qpiri.battery_float_voltage",
            tolerance: 0.05
        },
        battery_under_voltage: {
            kind: "number",
            statePath: "params.qpiri.battery_under_voltage",
            tolerance: 0.05
        },
        battery_recharge_voltage: {
            kind: "number",
            statePath: "params.qpiri.battery_recharge_voltage",
            tolerance: 0.05
        },
        battery_re_discharge_voltage: {
            kind: "number",
            statePath: "params.qpiri.battery_re_discharge_voltage",
            tolerance: 0.05
        },
        max_charging_current: {
            kind: "number",
            statePath: "params.qpiri.max_charging_current",
            tolerance: 0.5
        },
        max_ac_charging_current: {
            kind: "number",
            statePath: "params.qpiri.max_ac_charging_current",
            tolerance: 0.5
        },
        charger_source_priority: {
            kind: "enum_profile",
            statePath: "params.qpiri.charger_source_priority_code"
        },
        output_source_priority: {
            kind: "enum_profile",
            statePath: "params.qpiri.output_source_priority_code"
        }
    };
}

function isEqual(a, b, tol) {
    const na = Number(a);
    const nb = Number(b);
    if (!Number.isFinite(na) || !Number.isFinite(nb)) return false;
    return Math.abs(na - nb) <= tol;
}

function isTwoChoiceOutputPriorityEnabled(inv) {
    return global.get(`inverter_${inv}.output_priority_2choices`) === true;
}

function getLearnedAll() {
    let all = clone(global.get("learned_commands") || {});
    if (!all || typeof all !== "object" || Array.isArray(all)) all = {};

    const persistentAll = clone(global.get("learned_commands", "persistent") || {});
    if (persistentAll && typeof persistentAll === "object" && !Array.isArray(persistentAll)) {
        for (const fp of Object.keys(persistentAll)) {
            if (!all[fp] || typeof all[fp] !== "object") {
                all[fp] = clone(persistentAll[fp]);
            }
        }
    }

    const backupAll = clone(global.get("learned_commands_backup", "persistent") || {});
    if (backupAll && typeof backupAll === "object" && !Array.isArray(backupAll)) {
        for (const fp of Object.keys(backupAll)) {
            if (!all[fp] || typeof all[fp] !== "object") {
                all[fp] = clone(backupAll[fp]);
            }
        }
    }

    return all;
}

const paramRaw = cleanString(msg._ha_param || msg.topic || "");
const valueRaw = msg._ha_value ?? msg.payload;
const param = canonParam(paramRaw);

const registry = getRegistry();
const cfg = registry[param];

// param non géré par apprentissage => bypass
if (!cfg) {
    return [null, msg];
}

// output_source_priority en mode 2 choix forcé => bypass
if (param === "output_source_priority" && isTwoChoiceOutputPriorityEnabled(inv)) {
    node.status({
        fill: "blue",
        shape: "dot",
        text: "bypass forced 2-choice"
    });
    return [null, msg];
}

const sessionKey = `learn_session_inv${inv}`;
const pendingLearnKey = `learn_pending_inv${inv}`;
const retryGuardKey = `learn_retry_guard_inv${inv}`;

let existing = flow.get(sessionKey);

// purge session morte
if (existing && existing.active === true) {
    const lastTs = Number(existing.updatedAt || existing.createdAt || 0);
    const age = lastTs > 0 ? (Date.now() - lastTs) : 999999;

    if (age > 60000) {
        flow.set(sessionKey, null);
        flow.set(pendingLearnKey, null);
        existing = null;

        node.status({
            fill: "grey",
            shape: "dot",
            text: "learn stale cleared"
        });
    }
}

if (existing && existing.active === true) {
    node.status({
        fill: "yellow",
        shape: "ring",
        text: `learn busy ${existing.param}`
    });
    return [null, null];
}

// état normalisé : RAM puis secours persistent
const state =
    flow.get(`inv${inv}_normalized_state`) ||
    flow.get(`inv${inv}_normalized_state`, "persistent") ||
    global.get(`inv${inv}_normalized_state`) ||
    global.get(`inv${inv}_normalized_state`, "persistent") ||
    {};

const fingerprint = getFingerprint(state);

// si fingerprint absent, bypass
if (!fingerprint) {
    node.status({
        fill: "yellow",
        shape: "dot",
        text: "learn bypass no fingerprint"
    });
    return [null, msg];
}

const currentValue = getByPath(state, cfg.statePath);

// -------------------------------------------------
// Anti-réarmement après échec
// -------------------------------------------------
let retryGuard = flow.get(retryGuardKey);
if (!retryGuard || typeof retryGuard !== "object") retryGuard = {};

const guardId = `${fingerprint}|${param}|${JSON.stringify(valueRaw)}`;
const guard = retryGuard[guardId] || null;

if (guard && guard.blockUntil && Date.now() < Number(guard.blockUntil)) {
    node.status({
        fill: "red",
        shape: "ring",
        text: `learn blocked ${param}`
    });
    return [null, null];
}

// -------------------------------------------------
// MODE NUMERIQUE
// -------------------------------------------------
if (cfg.kind === "number") {
    const requestedValue = toNum(valueRaw);
    if (requestedValue == null) {
        node.status({ fill: "red", shape: "ring", text: `learn invalid ${param}` });
        return [null, null];
    }

    if (isEqual(currentValue, requestedValue, cfg.tolerance)) {
        node.status({
            fill: "green",
            shape: "dot",
            text: `already ${param}=${requestedValue}`
        });
        return [null, null];
    }

    msg._learn = {
        active: true,
        sessionId: `inv${inv}_${param}_${Date.now()}`,
        inverterNum: inv,
        param,
        paramRaw: cleanString(msg._ha_param_raw || msg._ha_param || param),
        requestedValue,
        requestedRaw: msg._ha_value_raw ?? valueRaw,
        baselineValue: currentValue,
        fingerprint,
        statePath: cfg.statePath,
        tolerance: cfg.tolerance,
        kind: "number",
        createdAt: Date.now(),
        updatedAt: Date.now()
    };

    node.status({
        fill: "blue",
        shape: "dot",
        text: `learn ${param} -> ${requestedValue}`
    });

    return [msg, null];
}

// -------------------------------------------------
// MODE ENUM PROFILE
// -------------------------------------------------
if (cfg.kind === "enum_profile") {
    const requestedSlot = Number(valueRaw);
    if (!Number.isInteger(requestedSlot) || requestedSlot < 0 || requestedSlot > 2) {
        node.status({ fill: "red", shape: "ring", text: `learn invalid slot ${param}` });
        return [null, null];
    }

    const currentNum = Number(currentValue);
    if (Number.isInteger(currentNum)) {
        const learnedAll = getLearnedAll();
        const learned = learnedAll[fingerprint]?.[param] || null;
        const profileKey = learned?.profileKey || null;

        if (param === "output_source_priority") {
            if (profileKey === "pop_00_02" && currentNum === requestedSlot) {
                node.status({ fill: "green", shape: "dot", text: `already ${param} slot ${requestedSlot}` });
                return [null, null];
            }
            if (profileKey === "pop_01_03" && currentNum === (requestedSlot + 1)) {
                node.status({ fill: "green", shape: "dot", text: `already ${param} slot ${requestedSlot}` });
                return [null, null];
            }
        }

        if (param === "charger_source_priority") {
            if (profileKey === "pcp_00_02" && currentNum === requestedSlot) {
                node.status({ fill: "green", shape: "dot", text: `already ${param} slot ${requestedSlot}` });
                return [null, null];
            }
            if (profileKey === "pcp_01_03" && currentNum === (requestedSlot + 1)) {
                node.status({ fill: "green", shape: "dot", text: `already ${param} slot ${requestedSlot}` });
                return [null, null];
            }
        }
    }

    msg._learn = {
        active: true,
        sessionId: `inv${inv}_${param}_${Date.now()}`,
        inverterNum: inv,
        param,
        paramRaw: cleanString(msg._ha_param_raw || msg._ha_param || param),
        requestedSlot,
        requestedRaw: msg._ha_value_raw ?? valueRaw,
        baselineValue: currentValue,
        fingerprint,
        statePath: cfg.statePath,
        kind: "enum_profile",
        createdAt: Date.now(),
        updatedAt: Date.now()
    };

    node.status({
        fill: "blue",
        shape: "dot",
        text: `learn ${param} slot ${requestedSlot}`
    });

    return [msg, null];
}

return [null, msg];

// ====== LEARNING - DECISION ======

const inv = msg.inverterNum ?? 1;
if (!msg._learn || typeof msg._learn !== "object") return null;

const sessionKey = `learn_session_inv${inv}`;

function cleanString(v) {
    return String(v ?? "").trim();
}

function normalizeFingerprint(fp) {
    return cleanString(fp);
}

function getParallelId(inv) {
    let machine = flow.get(`inv${inv}_parallel_id`);
    if (machine === undefined || machine === null || machine === "") machine = 0;
    machine = Number(machine);
    if (!Number.isFinite(machine) || machine < 0 || machine > 9) machine = 0;
    return machine;
}

function pad3(x) {
    return String(Math.trunc(Number(x))).padStart(3, "0");
}

function fixed1(x) {
    return Number(x).toFixed(1);
}

function getRegistry(inv) {
    const machine = getParallelId(inv);

    return {
        battery_bulk_voltage: {
            kind: "number",
            candidates: [
                { key: "BULK_PCVV", build: (v) => `PCVV${fixed1(v)}` }
            ]
        },

        battery_float_voltage: {
            kind: "number",
            candidates: [
                { key: "FLOAT_PBFT", build: (v) => `PBFT${fixed1(v)}` }
            ]
        },

        battery_under_voltage: {
            kind: "number",
            candidates: [
                { key: "UNDER_PSDV", build: (v) => `PSDV${fixed1(v)}` }
            ]
        },

        battery_recharge_voltage: {
            kind: "number",
            candidates: [
                { key: "BACK_GRID_PBCV", build: (v) => `PBCV${fixed1(v)}` }
            ]
        },

        battery_re_discharge_voltage: {
            kind: "number",
            candidates: [
                { key: "BACK_BATT_PBDV", build: (v) => `PBDV${fixed1(v)}` }
            ]
        },

        max_charging_current: {
            kind: "number",
            candidates: [
                { key: "MNCHGC_3", build: (v) => `MNCHGC${pad3(v)}` },
                { key: "MNCHGC_MACHINE", build: (v) => `MNCHGC${machine}${pad3(v)}` },
                { key: "MNCHGC_RAW", build: (v) => `MNCHGC${Math.trunc(Number(v))}` },
                { key: "PBDCHGC", build: (v) => `PBDCHGC${pad3(v)}` }
            ]
        },

        max_ac_charging_current: {
            kind: "number",
            candidates: [
                // Ne pas casser les autres onduleurs :
                // on garde plusieurs formats, l'apprentissage choisira le bon
                { key: "MUCHGC_4", build: (v) => `MUCHGC${String(Math.trunc(Number(v))).padStart(4, "0")}` },
                { key: "MUCHGC_3", build: (v) => `MUCHGC${String(Math.trunc(Number(v))).padStart(3, "0")}` },
                { key: "MUCHGC_2", build: (v) => `MUCHGC${String(Math.trunc(Number(v))).padStart(2, "0")}` },
                { key: "MUCHGC_RAW", build: (v) => `MUCHGC${Math.trunc(Number(v))}` },
                { key: "PBCCHGC", build: (v) => `PBCCHGC${pad3(v)}` }
            ]
        },

        output_source_priority: {
            kind: "enum_profile_detect",
            statePath: "params.qpiri.output_source_priority_code",
            family: "POP",
            defaultProfile: "pop_01_03",
            applyByProfile: {
                pop_00_02: {
                    0: { command: "POP00", expectedCode: 0 },
                    1: { command: "POP01", expectedCode: 1 },
                    2: { command: "POP02", expectedCode: 2 }
                },
                pop_01_03: {
                    0: { command: "POP01", expectedCode: 1 },
                    1: { command: "POP02", expectedCode: 2 },
                    2: { command: "POP03", expectedCode: 3 }
                }
            },
            detect: {
                low: { command: "POP00", expectedCode: 0, profileKey: "pop_00_02" },
                high: { command: "POP03", expectedCode: 3, profileKey: "pop_01_03" }
            }
        },

        charger_source_priority: {
            kind: "enum_profile_detect",
            statePath: "params.qpiri.charger_source_priority_code",
            family: "PCP",
            defaultProfile: "pcp_01_03",
            applyByProfile: {
                pcp_00_02: {
                    0: { command: "PCP00", expectedCode: 0 },
                    1: { command: "PCP01", expectedCode: 1 },
                    2: { command: "PCP02", expectedCode: 2 }
                },
                pcp_01_03: {
                    0: { command: "PCP01", expectedCode: 1 },
                    1: { command: "PCP02", expectedCode: 2 },
                    2: { command: "PCP03", expectedCode: 3 }
                }
            },
            detect: {
                low: { command: "PCP00", expectedCode: 0, profileKey: "pcp_00_02" },
                high: { command: "PCP03", expectedCode: 3, profileKey: "pcp_01_03" }
            }
        }
    };
}

const registry = getRegistry(inv);
const param = cleanString(msg._learn.param);
const cfg = registry[param];
if (!cfg) return null;

// garde anti-reset de session
let existing = flow.get(sessionKey);
if (
    msg._learn_action === "next_candidate" &&
    existing &&
    existing.active === true &&
    existing.sessionId === msg._learn.sessionId
) {
    return msg;
}

const learnedAll = global.get("learned_commands") || {};
const fp = normalizeFingerprint(msg._learn.fingerprint);
const learnedForFp = (fp && learnedAll[fp]) ? learnedAll[fp] : {};
const learnedEntry = learnedForFp[param] || null;

const session = {
    active: true,
    sessionId: msg._learn.sessionId,
    inverterNum: inv,
    param,
    paramRaw: cleanString(msg._learn.paramRaw),
    requestedRaw: msg._learn.requestedRaw,
    baselineValue: msg._learn.baselineValue,
    fingerprint: fp,
    statePath: msg._learn.statePath,
    kind: msg._learn.kind,
    createdAt: msg._learn.createdAt || Date.now(),
    updatedAt: Date.now(),
    index: -1,
    currentCandidate: null,
    phase: "build",
    lastAck: null,
    verifySentAt: 0,

    bannedCommands: Array.isArray(learnedEntry?.bannedCommands) ? [...learnedEntry.bannedCommands] : [],
    supportedCodes: Array.isArray(learnedEntry?.supportedCodes) ? [...learnedEntry.supportedCodes] : [],
    rangeStart: Number.isFinite(Number(learnedEntry?.rangeStart)) ? Number(learnedEntry.rangeStart) : null,
    rangeEnd: Number.isFinite(Number(learnedEntry?.rangeEnd)) ? Number(learnedEntry.rangeEnd) : null
};

// -------------------------------------------------
// MODE NUMERIQUE
// -------------------------------------------------
if (msg._learn.kind === "number") {
    session.requestedValue = msg._learn.requestedValue;
    session.tolerance = msg._learn.tolerance;

    let ordered = [];

    // si une commande a déjà été apprise pour ce fingerprint, on la tente d'abord
    if (learnedEntry && learnedEntry.key) {
        ordered.push({
            kind: "number_candidate",
            key: learnedEntry.key,
            source: "learned"
        });
    }

    // puis le registre complet
    for (const c of cfg.candidates) {
        if (!ordered.some(x => x.key === c.key)) {
            ordered.push({
                kind: "number_candidate",
                key: c.key,
                source: "registry"
            });
        }
    }

    session.candidateKeys = ordered;
}

// -------------------------------------------------
// MODE ENUM PROFILE
// -------------------------------------------------
if (msg._learn.kind === "enum_profile") {
    session.kind = "enum_profile_detect";
    session.requestedSlot = msg._learn.requestedSlot;

    let preferred = null;

    if (
        learnedEntry &&
        learnedEntry.mode === "profile" &&
        typeof learnedEntry.profileKey === "string" &&
        cleanString(learnedEntry.profileKey)
    ) {
        preferred = cleanString(learnedEntry.profileKey);
    }

    if (!preferred && typeof cfg.defaultProfile === "string" && cleanString(cfg.defaultProfile)) {
        preferred = cleanString(cfg.defaultProfile);
    }

    session.detectState = {
        phase: "normal",
        preferredProfile: preferred,
        resolvedProfile: null,
        lastVerifiedCode: null,
        probeHighAck: false,
        probeHighNak: false,
        probeLowAck: false,
        probeLowNak: false
    };
}

flow.set(sessionKey, session);

node.status({
    fill: "blue",
    shape: "dot",
    text: session.kind === "enum_profile_detect"
        ? `learn decision ${param} (${session.detectState?.preferredProfile || "auto"})`
        : `learn decision ${param}`
});

msg._learn_action = "next_candidate";
return msg;

// ====== LEARNING - BUILD CANDIDATE ======
// Sortie 1 = queue enqueue
// Sortie 2 = complete fail

const inv = msg.inverterNum ?? 1;

// -------------------------------------------------
// Helpers
// -------------------------------------------------
function getParallelId(inv) {
    let machine = flow.get(`inv${inv}_parallel_id`);
    if (machine === undefined || machine === null || machine === "") machine = 0;
    machine = Number(machine);
    if (!Number.isFinite(machine) || machine < 0 || machine > 9) machine = 0;
    return machine;
}

function pad3(x) {
    return String(Math.trunc(Number(x))).padStart(3, "0");
}

function fixed1(x) {
    return Number(x).toFixed(1);
}

function isBanned(session, cmd) {
    const banned = Array.isArray(session?.bannedCommands) ? session.bannedCommands : [];
    return banned.includes(String(cmd || "").trim().toUpperCase());
}

function getRegistry(inv) {
    const machine = getParallelId(inv);

    return {
        battery_bulk_voltage: {
            kind: "number",
            candidates: [
                { key: "BULK_PCVV", build: (v) => `PCVV${fixed1(v)}` }
            ]
        },

        battery_float_voltage: {
            kind: "number",
            candidates: [
                { key: "FLOAT_PBFT", build: (v) => `PBFT${fixed1(v)}` }
            ]
        },

        battery_under_voltage: {
            kind: "number",
            candidates: [
                { key: "UNDER_PSDV", build: (v) => `PSDV${fixed1(v)}` }
            ]
        },

        battery_recharge_voltage: {
            kind: "number",
            candidates: [
                { key: "BACK_GRID_PBCV", build: (v) => `PBCV${fixed1(v)}` }
            ]
        },

        battery_re_discharge_voltage: {
            kind: "number",
            candidates: [
                { key: "BACK_BATT_PBDV", build: (v) => `PBDV${fixed1(v)}` }
            ]
        },

        max_charging_current: {
            kind: "number",
            candidates: [
                { key: "MNCHGC_3", build: (v) => `MNCHGC${pad3(v)}` },
                { key: "MNCHGC_MACHINE", build: (v) => `MNCHGC${machine}${pad3(v)}` },
                { key: "MNCHGC_RAW", build: (v) => `MNCHGC${Math.trunc(Number(v))}` },
                { key: "PBDCHGC", build: (v) => `PBDCHGC${pad3(v)}` }
            ]
        },

        max_ac_charging_current: {
            kind: "number",
            candidates: [
                // priorité voulue : tester d'abord MUCHGC0002 / format 4 digits
                { key: "MUCHGC_4", build: (v) => `MUCHGC${String(Math.trunc(Number(v))).padStart(4, "0")}` },

                // puis fallback formats alternatifs
                { key: "MUCHGC_3", build: (v) => `MUCHGC${String(Math.trunc(Number(v))).padStart(3, "0")}` },
                { key: "MUCHGC_2", build: (v) => `MUCHGC${String(Math.trunc(Number(v))).padStart(2, "0")}` },
                { key: "MUCHGC_RAW", build: (v) => `MUCHGC${Math.trunc(Number(v))}` },
                { key: "PBCCHGC", build: (v) => `PBCCHGC${pad3(v)}` }
            ]
        },

        output_source_priority: {
            kind: "enum_profile_detect",
            statePath: "params.qpiri.output_source_priority_code",
            family: "POP",
            defaultProfile: "pop_01_03",
            applyByProfile: {
                pop_00_02: {
                    0: { command: "POP00", expectedCode: 0 },
                    1: { command: "POP01", expectedCode: 1 },
                    2: { command: "POP02", expectedCode: 2 }
                },
                pop_01_03: {
                    0: { command: "POP01", expectedCode: 1 },
                    1: { command: "POP02", expectedCode: 2 },
                    2: { command: "POP03", expectedCode: 3 }
                }
            },
            detect: {
                low: { command: "POP00", expectedCode: 0, profileKey: "pop_00_02" },
                high: { command: "POP03", expectedCode: 3, profileKey: "pop_01_03" }
            }
        },

        charger_source_priority: {
            kind: "enum_profile_detect",
            statePath: "params.qpiri.charger_source_priority_code",
            family: "PCP",
            defaultProfile: "pcp_01_03",
            applyByProfile: {
                pcp_00_02: {
                    0: { command: "PCP00", expectedCode: 0 },
                    1: { command: "PCP01", expectedCode: 1 },
                    2: { command: "PCP02", expectedCode: 2 }
                },
                pcp_01_03: {
                    0: { command: "PCP01", expectedCode: 1 },
                    1: { command: "PCP02", expectedCode: 2 },
                    2: { command: "PCP03", expectedCode: 3 }
                }
            },
            detect: {
                low: { command: "PCP00", expectedCode: 0, profileKey: "pcp_00_02" },
                high: { command: "PCP03", expectedCode: 3, profileKey: "pcp_01_03" }
            }
        }
    };
}

// -------------------------------------------------
// Session
// -------------------------------------------------
const sessionKey = `learn_session_inv${inv}`;
const pendingLearnKey = `learn_pending_inv${inv}`;

let session = flow.get(sessionKey);
if (!session || session.active !== true) return null;

const registry = getRegistry(inv);
const cfg = registry[session.param];
if (!cfg) return null;

// -------------------------------------------------
// Helpers fail msg
// -------------------------------------------------
function buildFailMsg(reason) {
    return {
        inverterNum: inv,
        topic: `voltronic/${inv}/learning/status`,
        payload: {
            active: false,
            success: false,
            reason,
            param: session.param,
            requested_value: session.requestedValue ?? null,
            requested_slot: session.requestedSlot ?? null,
            fingerprint: session.fingerprint,
            finished_at: new Date().toISOString()
        },
        _learn_complete: true,
        _learn_success: false
    };
}

// -------------------------------------------------
// Anti boucle dure
// -------------------------------------------------
function antiLoopCheck(cmd, label) {
    const now = Date.now();
    const prev = session._loopGuard || {
        lastCommand: null,
        count: 0,
        firstTs: 0
    };

    if (prev.lastCommand === cmd && (now - Number(prev.firstTs || 0)) < 8000) {
        prev.count = Number(prev.count || 0) + 1;
    } else {
        prev.lastCommand = cmd;
        prev.count = 1;
        prev.firstTs = now;
    }

    session._loopGuard = prev;

    if (prev.count > 3) {
        session.phase = "failed";
        flow.set(sessionKey, session);
        flow.set(pendingLearnKey, null);

        node.status({
            fill: "red",
            shape: "ring",
            text: `loop stop ${label || session.param}`
        });

        return buildFailMsg(`same_command_loop_${cmd}`);
    }

    return null;
}

// -------------------------------------------------
// MODE NUMERIQUE
// -------------------------------------------------
if (session.kind === "number") {
    const currentIndex = Number(session.index);
    session.index = (Number.isFinite(currentIndex) ? currentIndex : -1) + 1;
    session.updatedAt = Date.now();

    if (!Array.isArray(session.candidateKeys)) {
        return [null, buildFailMsg("invalid_candidate_list")];
    }

    if (session.index >= session.candidateKeys.length) {
        node.status({
            fill: "red",
            shape: "ring",
            text: `learn fail ${session.param}`
        });
        return [null, buildFailMsg("no_candidate_left")];
    }

    const wanted = session.candidateKeys[session.index];
    const candidate = Array.isArray(cfg.candidates)
        ? cfg.candidates.find(c => c.key === wanted.key)
        : null;

    if (!candidate || typeof candidate.build !== "function") {
        flow.set(sessionKey, session);
        return [{
            inverterNum: inv,
            _learn_action: "next_candidate",
            _learn: { sessionId: session.sessionId }
        }, null];
    }

    const cmd = candidate.build(session.requestedValue);

    const loopFail = antiLoopCheck(cmd, candidate.key);
    if (loopFail) return [null, loopFail];

    session.currentCandidate = {
        mode: "number",
        key: candidate.key,
        source: wanted.source,
        command: cmd,
        sentAt: Date.now()
    };

    session.phase = "wait_ack";
    session.lastAck = null;

    flow.set(sessionKey, session);
    flow.set(pendingLearnKey, {
        sessionId: session.sessionId,
        param: session.param,
        cmd: cmd,
        phase: "wait_ack",
        ts: Date.now()
    });

    flow.set(`inv${inv}_poll_pause_until`, Date.now() + 2500);

    const out = {
        inverterNum: inv,
        command: cmd,
        _cmd: cmd,
        _raw_command: cmd,
        payload: cmd,
        _burst: false,
        _origin: "learn_retry",
        _ha_param: session.paramRaw || session.param,
        _ha_value: session.requestedRaw,
        _learn: {
            sessionId: session.sessionId,
            param: session.param,
            requestedValue: session.requestedValue,
            candidateKey: candidate.key,
            source: wanted.source,
            phase: "candidate"
        }
    };

    node.status({
        fill: "yellow",
        shape: "dot",
        text: `learn try ${candidate.key}`
    });

    return [out, null];
}

// -------------------------------------------------
// MODE DETECTION / REAPPLY PROFIL ENUM
// -------------------------------------------------
if (session.kind === "enum_profile_detect") {
    const detectState = session.detectState || {
        phase: "normal",
        preferredProfile: cfg.defaultProfile || null,
        resolvedProfile: null,
        lastVerifiedCode: null,
        probeHighAck: false,
        probeHighNak: false,
        probeLowAck: false,
        probeLowNak: false
    };

    let cmd = null;
    let expectedCode = null;
    let profileKey = null;
    let candidateLabel = null;

    if (detectState.phase === "normal") {
        const requestedSlot = Number(session.requestedSlot);
        const preferred =
            detectState.resolvedProfile ||
            detectState.preferredProfile ||
            cfg.defaultProfile ||
            null;

        if (
            preferred &&
            cfg.applyByProfile?.[preferred] &&
            cfg.applyByProfile[preferred][requestedSlot]
        ) {
            const slotCfg = cfg.applyByProfile[preferred][requestedSlot];
            cmd = slotCfg.command;
            expectedCode = Number(slotCfg.expectedCode);
            profileKey = preferred;
            candidateLabel = `normal_${preferred}`;
        } else {
            return [null, buildFailMsg("invalid_requested_slot")];
        }

        session.currentCandidate = {
            mode: "profile_detect",
            phase: "normal",
            command: cmd,
            expectedCode,
            profileKey,
            requestedSlot,
            sentAt: Date.now()
        };
    }

    else if (detectState.phase === "probe_low") {
        cmd = cfg.detect.low.command;
        expectedCode = cfg.detect.low.expectedCode;
        profileKey = cfg.detect.low.profileKey;
        candidateLabel = "probe_low_00";

        session.currentCandidate = {
            mode: "profile_detect",
            phase: "probe_low",
            command: cmd,
            expectedCode,
            profileKey,
            requestedSlot: session.requestedSlot,
            sentAt: Date.now()
        };
    }

    else if (detectState.phase === "probe_high") {
        if (isBanned(session, cfg.detect.high.command)) {
            return [null, buildFailMsg("high_probe_banned")];
        }

        cmd = cfg.detect.high.command;
        expectedCode = cfg.detect.high.expectedCode;
        profileKey = cfg.detect.high.profileKey;
        candidateLabel = "probe_high_03";

        session.currentCandidate = {
            mode: "profile_detect",
            phase: "probe_high",
            command: cmd,
            expectedCode,
            profileKey,
            requestedSlot: session.requestedSlot,
            sentAt: Date.now()
        };
    }

    else if (detectState.phase === "reapply_final") {
        const resolved = detectState.resolvedProfile;
        const requestedSlot = Number(session.requestedSlot);
        const slotCfg = cfg.applyByProfile?.[resolved]?.[requestedSlot];

        if (!resolved || !slotCfg) {
            return [null, buildFailMsg("invalid_reapply_profile")];
        }

        cmd = slotCfg.command;
        expectedCode = Number(slotCfg.expectedCode);
        profileKey = resolved;
        candidateLabel = "reapply_final_value";

        session.currentCandidate = {
            mode: "profile_detect",
            phase: "reapply_final",
            command: cmd,
            expectedCode,
            profileKey,
            requestedSlot,
            sentAt: Date.now()
        };
    }

    else {
        return [null, buildFailMsg("invalid_detect_phase")];
    }

    const loopFail = antiLoopCheck(cmd, candidateLabel);
    if (loopFail) return [null, loopFail];

    session.phase = "wait_ack";
    session.lastAck = null;
    session.updatedAt = Date.now();

    flow.set(sessionKey, session);
    flow.set(pendingLearnKey, {
        sessionId: session.sessionId,
        param: session.param,
        cmd: cmd,
        phase: "wait_ack",
        ts: Date.now()
    });

    flow.set(`inv${inv}_poll_pause_until`, Date.now() + 2500);

    const out = {
        inverterNum: inv,
        command: cmd,
        _cmd: cmd,
        _raw_command: cmd,
        payload: cmd,
        _burst: false,
        _origin: "learn_retry",
        _ha_param: session.paramRaw || session.param,
        _ha_value: session.requestedRaw,
        _learn: {
            sessionId: session.sessionId,
            param: session.param,
            requestedSlot: session.requestedSlot,
            detectPhase: detectState.phase,
            expectedCode,
            profileKey,
            candidateLabel,
            phase: "candidate"
        }
    };

    node.status({
        fill: "yellow",
        shape: "dot",
        text: `learn try ${candidateLabel}`
    });

    return [out, null];
}

return null;

// ====== LEARNING - RX FEEDBACK ======
// Entrées possibles:
// - Parser sortie 2
// - Queue Pump timeout sortie 2
//
// Sortie 1 = enqueue QPIRI verify
// Sortie 2 = next candidate / fail

const inv = msg.inverterNum ?? 1;
const sessionKey = `learn_session_inv${inv}`;
const pendingLearnKey = `learn_pending_inv${inv}`;

function cleanUpper(v) {
    return String(v ?? "").trim().toUpperCase();
}

function cleanResp(v) {
    return String(v ?? "")
        .trim()
        .replace(/^\(/, "")
        .trim()
        .toUpperCase();
}

function ensureArray(arr) {
    return Array.isArray(arr) ? arr : [];
}

function addUnique(arr, value) {
    const v = cleanUpper(value);
    const out = ensureArray(arr).map(x => cleanUpper(x));
    if (v && !out.includes(v)) out.push(v);
    return out;
}

function buildFailMsg(session, reason) {
    return {
        inverterNum: inv,
        topic: `voltronic/${inv}/learning/status`,
        payload: {
            active: false,
            success: false,
            reason,
            param: session.param,
            requested_slot: session.requestedSlot ?? null,
            requested_value: session.requestedValue ?? null,
            fingerprint: session.fingerprint,
            finished_at: new Date().toISOString()
        },
        _learn_complete: true,
        _learn_success: false
    };
}

let session = flow.get(sessionKey);
if (!session || session.active !== true) return null;

const pending = flow.get(pendingLearnKey) || null;

const currentCmd = cleanUpper(session.currentCandidate?.command || "");
const msgCmd = cleanUpper(
    msg._raw_command ||
    msg.command ||
    msg._cmd ||
    msg.payload?.raw_command ||
    msg.payload?.command
);

const pendingCmd = cleanUpper(pending?.cmd || "");

const rawResp = cleanResp(
    msg._raw_response ??
    msg.raw_response ??
    msg.payload?.raw_response ??
    msg.payload?.raw ??
    ""
);

const isTimeout = (msg._learn_timeout === true || msg.payload?.timeout === true);

const isNak =
    msg.payload?.nak === true ||
    rawResp.startsWith("NAK");

const isAck =
    !isTimeout &&
    !isNak &&
    (
        rawResp.startsWith("ACK") ||
        msg.payload?.nak === false
    );

function markResolvedProfile(session, profileKey) {
    const ds = session.detectState || {};
    ds.resolvedProfile = profileKey;

    if (profileKey === "pop_00_02" || profileKey === "pcp_00_02") {
        session.rangeStart = 0;
        session.rangeEnd = 2;
    } else if (profileKey === "pop_01_03" || profileKey === "pcp_01_03") {
        session.rangeStart = 1;
        session.rangeEnd = 3;
    }

    session.detectState = ds;
}

function advanceDetectPhaseOnFailure(session, reasonType = "") {
    if (session.kind !== "enum_profile_detect") {
        session.phase = "build";
        return { type: "next" };
    }

    const detectState = session.detectState || {
        phase: "normal",
        preferredProfile: null,
        resolvedProfile: null,
        lastVerifiedCode: null,
        probeHighAck: false,
        probeHighNak: false,
        probeLowAck: false,
        probeLowNak: false
    };

    const currentCommand = cleanUpper(session.currentCandidate?.command || "");
    const phase = cleanUpper(session.currentCandidate?.phase || detectState.phase || "");

    // -------------------------------------------------
    // Si le 03 échoue => plage basse
    // -------------------------------------------------
    if ((isNak || isTimeout) && (currentCommand === "POP03" || currentCommand === "PCP03")) {
        session.bannedCommands = addUnique(session.bannedCommands, currentCommand);
        detectState.probeHighNak = true;

        if (currentCommand === "POP03") {
            markResolvedProfile(session, "pop_00_02");
        } else if (currentCommand === "PCP03") {
            markResolvedProfile(session, "pcp_00_02");
        }

        detectState.phase = "reapply_final";
        session.detectState = detectState;
        session.phase = "build";
        return { type: "next" };
    }

    // -------------------------------------------------
    // Si le 00 échoue => plage haute
    // -------------------------------------------------
    if ((isNak || isTimeout) && (currentCommand === "POP00" || currentCommand === "PCP00")) {
        detectState.probeLowNak = true;

        if (currentCommand === "POP00") {
            markResolvedProfile(session, "pop_01_03");
        } else if (currentCommand === "PCP00") {
            markResolvedProfile(session, "pcp_01_03");
        }

        detectState.phase = "reapply_final";
        session.detectState = detectState;
        session.phase = "build";
        return { type: "next" };
    }

    // -------------------------------------------------
    // Si la tentative normale échoue, on force une vraie détection :
    // 1) probe_low (00)
    // 2) probe_high (03)
    // -------------------------------------------------
    if (phase === "NORMAL" || detectState.phase === "normal") {
        detectState.phase = "probe_low";
        session.detectState = detectState;
        session.phase = "build";
        return { type: "next" };
    }

    if (phase === "PROBE_LOW" || detectState.phase === "probe_low") {
        detectState.phase = "probe_high";
        session.detectState = detectState;
        session.phase = "build";
        return { type: "next" };
    }

    if (phase === "PROBE_HIGH" || detectState.phase === "probe_high") {
        session.detectState = detectState;
        session.phase = "failed";
        return { type: "fail", reason: reasonType || "probe_high_failed" };
    }

    if (phase === "REAPPLY_FINAL" || detectState.phase === "reapply_final") {
        session.detectState = detectState;
        session.phase = "failed";
        return { type: "fail", reason: reasonType || "reapply_failed" };
    }

    session.phase = "failed";
    return { type: "fail", reason: reasonType || "invalid_detect_phase" };
}

// -------------------------
// PHASE 1 : wait_ack
// -------------------------
if (session.phase === "wait_ack") {
    let cmdMatches = false;

    if (pendingCmd && msgCmd && pendingCmd === msgCmd) {
        cmdMatches = true;
    } else if (currentCmd && msgCmd && currentCmd === msgCmd) {
        cmdMatches = true;
    }

    if (isTimeout) {
        if (pendingCmd && currentCmd && pendingCmd === currentCmd) {
            cmdMatches = true;
        } else if (!pendingCmd && currentCmd) {
            cmdMatches = true;
        }
    }

    if (!cmdMatches) return null;

    if (isTimeout) {
        session.lastAck = "TIMEOUT";
        session.updatedAt = Date.now();

        const step = advanceDetectPhaseOnFailure(session, "candidate_timeout");

        flow.set(sessionKey, session);
        flow.set(pendingLearnKey, null);

        if (step.type === "fail") {
            node.status({ fill: "red", shape: "ring", text: `learn fail ${session.param}` });
            return [null, buildFailMsg(session, step.reason || "candidate_timeout")];
        }

        node.status({ fill: "red", shape: "ring", text: `learn timeout ${session.param}` });

        return [null, {
            inverterNum: inv,
            _learn_action: "next_candidate",
            _learn: { sessionId: session.sessionId }
        }];
    }

    if (isNak) {
        session.lastAck = "NAK";
        session.updatedAt = Date.now();

        const currentCommand = cleanUpper(session.currentCandidate?.command || "");
        if (currentCommand === "POP03" || currentCommand === "PCP03") {
            session.bannedCommands = addUnique(session.bannedCommands, currentCommand);
        }

        const step = advanceDetectPhaseOnFailure(session, "candidate_nak");

        flow.set(sessionKey, session);
        flow.set(pendingLearnKey, null);

        if (step.type === "fail") {
            node.status({ fill: "red", shape: "ring", text: `learn fail ${session.param}` });
            return [null, buildFailMsg(session, step.reason || "candidate_nak")];
        }

        node.status({
            fill: "yellow",
            shape: "ring",
            text: `learn NAK ${session.currentCandidate?.command || session.param}`
        });

        return [null, {
            inverterNum: inv,
            _learn_action: "next_candidate",
            _learn: { sessionId: session.sessionId }
        }];
    }

    if (isAck) {
        session.lastAck = "ACK";
        session.phase = "wait_state";
        session.verifySentAt = Date.now();
        session.updatedAt = Date.now();

        const currentCommand = cleanUpper(session.currentCandidate?.command || "");
        const currentPhase = cleanUpper(session.currentCandidate?.phase || "");

        const ds = session.detectState || {};
        if (currentCommand === "POP03" || currentCommand === "PCP03") ds.probeHighAck = true;
        if (currentCommand === "POP00" || currentCommand === "PCP00") ds.probeLowAck = true;
        session.detectState = ds;

        flow.set(sessionKey, session);
        flow.set(pendingLearnKey, {
            sessionId: session.sessionId,
            param: session.param,
            cmd: "QPIRI",
            phase: "wait_state",
            ts: Date.now()
        });

        const verifyMsg = {
            inverterNum: inv,
            command: "QPIRI",
            _cmd: "QPIRI",
            _raw_command: "QPIRI",
            payload: "QPIRI",
            _burst: false,
            _origin: "learn_retry",
            _learn: {
                sessionId: session.sessionId,
                param: session.param,
                requestedValue: session.requestedValue ?? null,
                requestedSlot: session.requestedSlot ?? null,
                candidateKey: session.currentCandidate?.key || null,
                profileKey: session.currentCandidate?.profileKey || null,
                detectPhase: currentPhase || session.detectState?.phase || null,
                phase: "verify"
            }
        };

        node.status({
            fill: "blue",
            shape: "dot",
            text: `learn verify ${session.param}`
        });

        return [verifyMsg, null];
    }

    return null;
}

// -------------------------
// PHASE 2 : wait_state
// -------------------------
if (session.phase === "wait_state") {
    const waitingForQpiri = (pendingCmd === "QPIRI");
    if (!waitingForQpiri) return null;

    if (isTimeout) {
        session.lastAck = "QPIRI_TIMEOUT";
        session.updatedAt = Date.now();

        const step = advanceDetectPhaseOnFailure(session, "verify_timeout");

        flow.set(sessionKey, session);
        flow.set(pendingLearnKey, null);

        if (step.type === "fail") {
            node.status({ fill: "red", shape: "ring", text: `learn fail ${session.param}` });
            return [null, buildFailMsg(session, step.reason || "verify_timeout")];
        }

        node.status({
            fill: "red",
            shape: "ring",
            text: `verify timeout ${session.param}`
        });

        return [null, {
            inverterNum: inv,
            _learn_action: "next_candidate",
            _learn: { sessionId: session.sessionId }
        }];
    }

    return null;
}

return null;

// ====== LEARNING - STATE FEEDBACK ======
// Sortie 1 = complete success
// Sortie 2 = next candidate / next detect phase

const inv = msg.inverterNum ?? 1;
const sessionKey = `learn_session_inv${inv}`;
const pendingLearnKey = `learn_pending_inv${inv}`;

function getByPath(obj, path) {
    if (!obj || !path) return undefined;
    return path.split(".").reduce((acc, k) => acc && acc[k], obj);
}

function toNum(v) {
    const n = Number(v);
    return Number.isFinite(n) ? n : null;
}

function isEqual(a, b, tol) {
    const na = toNum(a);
    const nb = toNum(b);
    if (na == null || nb == null) return false;
    return Math.abs(na - nb) <= tol;
}

function addNumUnique(arr, value) {
    const out = Array.isArray(arr) ? [...arr] : [];
    const n = Number(value);
    if (Number.isFinite(n) && !out.includes(n)) out.push(n);
    return out.sort((a, b) => a - b);
}

function markResolvedProfile(session, profileKey) {
    const ds = session.detectState || {};
    ds.resolvedProfile = profileKey;

    if (profileKey === "pop_00_02" || profileKey === "pcp_00_02") {
        session.rangeStart = 0;
        session.rangeEnd = 2;
    } else if (profileKey === "pop_01_03" || profileKey === "pcp_01_03") {
        session.rangeStart = 1;
        session.rangeEnd = 3;
    }

    session.detectState = ds;
}

const session = flow.get(sessionKey);
if (!session || session.active !== true) return null;

if (session.phase !== "wait_state") return null;

const pending = flow.get(pendingLearnKey) || null;
const pendingCmd = String(pending?.cmd || "").trim().toUpperCase();
if (pendingCmd !== "QPIRI") return null;

const state = msg.payload;
if (!state || typeof state !== "object") return null;

const ageSinceVerify = Date.now() - Number(session.verifySentAt || 0);
if (ageSinceVerify < 1200) {
    return null;
}

// -------------------------
// MODE NUMERIQUE
// -------------------------
if (session.kind === "number") {
    const actualValue = getByPath(state, session.statePath);

    if (isEqual(actualValue, session.requestedValue, session.tolerance)) {
        flow.set(pendingLearnKey, null);

        const okMsg = {
            inverterNum: inv,
            topic: `voltronic/${inv}/learning/status`,
            payload: {
                active: false,
                success: true,
                param: session.param,
                candidate_key: session.currentCandidate?.key || null,
                command: session.currentCandidate?.command || null,
                requested_value: session.requestedValue,
                verified_value: actualValue,
                fingerprint: session.fingerprint,
                finished_at: new Date().toISOString()
            },
            _learn_complete: true,
            _learn_success: true
        };

        node.status({ fill: "green", shape: "dot", text: `learn OK ${session.param}` });
        return [okMsg, null];
    }

    flow.set(pendingLearnKey, null);

    node.status({ fill: "yellow", shape: "ring", text: `learn next ${session.param}` });
    return [null, {
        inverterNum: inv,
        _learn_action: "next_candidate",
        _learn: { sessionId: session.sessionId }
    }];
}

// -------------------------
// MODE DETECTION PROFIL ENUM + REAPPLY
// -------------------------
if (session.kind === "enum_profile_detect") {
    const actualCode = toNum(getByPath(state, session.statePath));
    const detectState = session.detectState || {
        phase: "normal",
        preferredProfile: null,
        resolvedProfile: null,
        lastVerifiedCode: null,
        probeHighAck: false,
        probeHighNak: false,
        probeLowAck: false,
        probeLowNak: false
    };

    detectState.lastVerifiedCode = actualCode;
    session.detectState = detectState;
    session.supportedCodes = addNumUnique(session.supportedCodes, actualCode);

    const currentPhase = String(session.currentCandidate?.phase || detectState.phase || "").trim().toLowerCase();
    const expectedCode = toNum(session.currentCandidate?.expectedCode);

    // -------------------------------------------------
    // normal:
    // si le code correspond, succès direct
    // sinon on lance une vraie détection par 00
    // -------------------------------------------------
    if (currentPhase === "normal") {
        if (actualCode != null && expectedCode != null && actualCode === expectedCode) {
            markResolvedProfile(
                session,
                session.currentCandidate?.profileKey ||
                detectState.resolvedProfile ||
                detectState.preferredProfile ||
                null
            );

            flow.set(sessionKey, session);
            flow.set(pendingLearnKey, null);

            const okMsg = {
                inverterNum: inv,
                topic: `voltronic/${inv}/learning/status`,
                payload: {
                    active: false,
                    success: true,
                    param: session.param,
                    profile_key: session.detectState?.resolvedProfile || null,
                    command: session.currentCandidate?.command || null,
                    requested_slot: session.requestedSlot,
                    verified_code: actualCode,
                    expected_code: expectedCode,
                    fingerprint: session.fingerprint,
                    finished_at: new Date().toISOString()
                },
                _learn_complete: true,
                _learn_success: true
            };

            node.status({ fill: "green", shape: "dot", text: `learn OK ${session.param}` });
            return [okMsg, null];
        }

        detectState.phase = "probe_low";
        session.detectState = detectState;
        session.updatedAt = Date.now();

        flow.set(sessionKey, session);
        flow.set(pendingLearnKey, null);

        node.status({ fill: "yellow", shape: "ring", text: `probe low ${session.param}` });
        return [null, {
            inverterNum: inv,
            _learn_action: "next_candidate",
            _learn: { sessionId: session.sessionId }
        }];
    }

    // -------------------------------------------------
    // probe_low:
    // si QPIRI lit 0 => plage basse confirmée
    // sinon on tente probe_high
    // -------------------------------------------------
    if (currentPhase === "probe_low") {
        if (actualCode === 0) {
            markResolvedProfile(
                session,
                session.currentCandidate?.profileKey || detectState.resolvedProfile || "pop_00_02"
            );
            detectState.phase = "reapply_final";

            session.detectState = detectState;
            session.updatedAt = Date.now();

            flow.set(sessionKey, session);
            flow.set(pendingLearnKey, null);

            node.status({ fill: "blue", shape: "dot", text: `reapply ${session.param}` });
            return [null, {
                inverterNum: inv,
                _learn_action: "next_candidate",
                _learn: { sessionId: session.sessionId }
            }];
        }

        detectState.phase = "probe_high";
        session.detectState = detectState;
        session.updatedAt = Date.now();

        flow.set(sessionKey, session);
        flow.set(pendingLearnKey, null);

        node.status({ fill: "yellow", shape: "ring", text: `probe high ${session.param}` });
        return [null, {
            inverterNum: inv,
            _learn_action: "next_candidate",
            _learn: { sessionId: session.sessionId }
        }];
    }

    // -------------------------------------------------
    // probe_high:
    // si QPIRI lit 3 => plage haute confirmée
    // sinon échec
    // -------------------------------------------------
    if (currentPhase === "probe_high") {
        if (actualCode === 3) {
            markResolvedProfile(
                session,
                session.currentCandidate?.profileKey || detectState.resolvedProfile || "pop_01_03"
            );
            detectState.phase = "reapply_final";

            session.detectState = detectState;
            session.updatedAt = Date.now();

            flow.set(sessionKey, session);
            flow.set(pendingLearnKey, null);

            node.status({ fill: "blue", shape: "dot", text: `reapply ${session.param}` });
            return [null, {
                inverterNum: inv,
                _learn_action: "next_candidate",
                _learn: { sessionId: session.sessionId }
            }];
        }

        flow.set(pendingLearnKey, null);

        node.status({ fill: "red", shape: "ring", text: `learn fail ${session.param}` });
        return [null, {
            inverterNum: inv,
            topic: `voltronic/${inv}/learning/status`,
            payload: {
                active: false,
                success: false,
                reason: "profile_not_resolved",
                param: session.param,
                requested_slot: session.requestedSlot,
                fingerprint: session.fingerprint,
                finished_at: new Date().toISOString()
            },
            _learn_complete: true,
            _learn_success: false
        }];
    }

    // -------------------------------------------------
    // reapply_final:
    // on valide que la vraie commande du slot demandé
    // donne bien le code attendu
    // -------------------------------------------------
    if (currentPhase === "reapply_final") {
        if (actualCode != null && expectedCode != null && actualCode === expectedCode) {
            flow.set(pendingLearnKey, null);

            const okMsg = {
                inverterNum: inv,
                topic: `voltronic/${inv}/learning/status`,
                payload: {
                    active: false,
                    success: true,
                    param: session.param,
                    profile_key: detectState.resolvedProfile,
                    command: session.currentCandidate?.command || null,
                    requested_slot: session.requestedSlot,
                    verified_code: actualCode,
                    expected_code: expectedCode,
                    fingerprint: session.fingerprint,
                    finished_at: new Date().toISOString()
                },
                _learn_complete: true,
                _learn_success: true
            };

            node.status({ fill: "green", shape: "dot", text: `learn OK ${session.param}` });
            return [okMsg, null];
        }

        flow.set(pendingLearnKey, null);

        node.status({ fill: "red", shape: "ring", text: `reapply fail ${session.param}` });
        return [null, {
            inverterNum: inv,
            topic: `voltronic/${inv}/learning/status`,
            payload: {
                active: false,
                success: false,
                reason: "reapply_failed",
                param: session.param,
                requested_slot: session.requestedSlot,
                fingerprint: session.fingerprint,
                finished_at: new Date().toISOString()
            },
            _learn_complete: true,
            _learn_success: false
        }];
    }
}

return null;

// ====== LEARNING - COMPLETE ======

const inv = msg.inverterNum ?? 1;
const sessionKey = `learn_session_inv${inv}`;
const pendingLearnKey = `learn_pending_inv${inv}`;

let session =
    flow.get(sessionKey) ||
    flow.get(sessionKey, "persistent") ||
    null;

if (!msg._learn_complete) {
    return null;
}

const success = (msg._learn_success === true);

function clone(obj) {
    return JSON.parse(JSON.stringify(obj || {}));
}

function uniqNums(arr) {
    const out = [];
    for (const v of (Array.isArray(arr) ? arr : [])) {
        const n = Number(v);
        if (Number.isFinite(n) && !out.includes(n)) out.push(n);
    }
    return out.sort((a, b) => a - b);
}

function uniqUpper(arr) {
    const out = [];
    for (const v of (Array.isArray(arr) ? arr : [])) {
        const s = String(v ?? "").trim().toUpperCase();
        if (s && !out.includes(s)) out.push(s);
    }
    return out.sort();
}

function cleanString(v) {
    return String(v ?? "").trim();
}

function normalizeFingerprint(fp) {
    const s = cleanString(fp);
    return s || "";
}

function getLearnedAll() {
    let all = clone(global.get("learned_commands") || {});
    if (!all || typeof all !== "object" || Array.isArray(all)) all = {};

    const persistentAll = clone(global.get("learned_commands", "persistent") || {});
    if (persistentAll && typeof persistentAll === "object" && !Array.isArray(persistentAll)) {
        for (const fp of Object.keys(persistentAll)) {
            if (!all[fp] || typeof all[fp] !== "object") {
                all[fp] = clone(persistentAll[fp]);
            }
        }
    }

    const backupAll = clone(global.get("learned_commands_backup", "persistent") || {});
    if (backupAll && typeof backupAll === "object" && !Array.isArray(backupAll)) {
        for (const fp of Object.keys(backupAll)) {
            if (!all[fp] || typeof all[fp] !== "object") {
                all[fp] = clone(backupAll[fp]);
            }
        }
    }

    return all;
}

function saveLearnedAll(all) {
    global.set("learned_commands", all);
    global.set("learned_commands", all, "persistent");
    global.set("learned_commands_backup", all, "persistent");
}

try {
    const fp = normalizeFingerprint(
        session?.fingerprint ||
        msg.payload?.fingerprint ||
        ""
    );

    const param = cleanString(
        session?.param ||
        msg.payload?.param ||
        ""
    );

    if (success && session && session.active === true && fp && param) {
        const all = getLearnedAll();
        if (!all[fp]) all[fp] = {};

        const prev = all[fp][param] || {};

        if (session.kind === "number" && session.currentCandidate?.key) {
            all[fp][param] = {
                key: session.currentCandidate.key,
                learnedAt: Date.now(),
                successCount: Number(prev.successCount || 0) + 1,
                failCount: 0,
                lastValue: session.requestedValue,
                lastCommandExample: session.currentCandidate.command
            };
        }

        if (session.kind === "enum_profile_detect") {
            const resolvedProfile =
                session.detectState?.resolvedProfile ||
                msg.payload?.profile_key ||
                null;

            const verifiedCode = Number(
                msg.payload?.verified_code ??
                session.detectState?.lastVerifiedCode
            );

            const prevCodes = uniqNums(prev.provenCodes || []);
            const newCodes = uniqNums([...prevCodes, verifiedCode]);

            const confidence =
                (newCodes.includes(0) || newCodes.includes(3))
                    ? "confirmed"
                    : "tentative";

            if (resolvedProfile) {
                all[fp][param] = {
                    mode: "profile",
                    profileKey: resolvedProfile,
                    confidence,
                    provenCodes: newCodes,
                    bannedCommands: uniqUpper(session.bannedCommands || prev.bannedCommands || []),
                    supportedCodes: uniqNums(session.supportedCodes || prev.supportedCodes || []),
                    rangeStart: Number.isFinite(Number(session.rangeStart)) ? Number(session.rangeStart) : null,
                    rangeEnd: Number.isFinite(Number(session.rangeEnd)) ? Number(session.rangeEnd) : null,
                    learnedAt: Date.now(),
                    successCount: Number(prev.successCount || 0) + 1,
                    failCount: 0,
                    lastSlot: session.requestedSlot,
                    lastExpectedCode: verifiedCode,
                    lastCommandExample: session.currentCandidate?.command || null
                };
            }
        }

        saveLearnedAll(all);
    }

    if (!success && fp && param) {
        const all = getLearnedAll();
        if (!all[fp]) all[fp] = {};

        const prev = all[fp][param] || {};

        all[fp][param] = {
            ...prev,
            bannedCommands: uniqUpper(session?.bannedCommands || prev.bannedCommands || []),
            supportedCodes: uniqNums(session?.supportedCodes || prev.supportedCodes || []),
            rangeStart: Number.isFinite(Number(session?.rangeStart)) ? Number(session?.rangeStart) : prev.rangeStart ?? null,
            rangeEnd: Number.isFinite(Number(session?.rangeEnd)) ? Number(session?.rangeEnd) : prev.rangeEnd ?? null,
            failCount: Number(prev.failCount || 0) + 1,
            lastFailAt: Date.now()
        };

        if (
            all[fp][param].failCount >= 3 &&
            !all[fp][param].profileKey &&
            !all[fp][param].key
        ) {
            delete all[fp][param];
        }

        saveLearnedAll(all);
    }
} finally {
    flow.set(pendingLearnKey, null);
    flow.set(sessionKey, null);
}

const historyKey = `learn_history_inv${inv}`;
let hist =
    flow.get(historyKey, "persistent") ||
    flow.get(historyKey) ||
    [];

if (!Array.isArray(hist)) hist = [];

hist.unshift({
    ts: Date.now(),
    success,
    kind: session?.kind || null,
    param: session?.param || msg.payload?.param || null,
    candidate_key: session?.currentCandidate?.key || msg.payload?.candidate_key || null,
    profile_key:
        session?.detectState?.resolvedProfile ||
        session?.currentCandidate?.profileKey ||
        msg.payload?.profile_key ||
        null,
    command: session?.currentCandidate?.command || msg.payload?.command || null,
    requested_value: session?.requestedValue ?? msg.payload?.requested_value ?? null,
    requested_slot: session?.requestedSlot ?? msg.payload?.requested_slot ?? null,
    expected_code:
        session?.currentCandidate?.expectedCode ??
        msg.payload?.expected_code ??
        null,
    verified_code:
        msg.payload?.verified_code ??
        session?.detectState?.lastVerifiedCode ??
        null,
    range_start: session?.rangeStart ?? null,
    range_end: session?.rangeEnd ?? null,
    banned_commands: uniqUpper(session?.bannedCommands || []),
    supported_codes: uniqNums(session?.supportedCodes || []),
    fingerprint: session?.fingerprint || msg.payload?.fingerprint || null
});

if (hist.length > 50) hist = hist.slice(0, 50);

flow.set(historyKey, hist, "persistent");
flow.set(historyKey, hist);

node.status({
    fill: success ? "green" : "red",
    shape: success ? "dot" : "ring",
    text: success ? "learn saved" : "learn failed"
});

const retryGuardKey = `learn_retry_guard_inv${inv}`;
let retryGuard = flow.get(retryGuardKey);
if (!retryGuard || typeof retryGuard !== "object") retryGuard = {};

const guardValue =
    session?.requestedRaw ??
    session?.requestedValue ??
    session?.requestedSlot ??
    msg.payload?.requested_value ??
    msg.payload?.requested_slot ??
    null;

const guardFingerprint = cleanString(
    session?.fingerprint ||
    msg.payload?.fingerprint ||
    ""
);

const guardParam = cleanString(
    session?.param ||
    msg.payload?.param ||
    ""
);

const guardId = `${guardFingerprint}|${guardParam}|${JSON.stringify(guardValue)}`;

if (!success) {
    retryGuard[guardId] = {
        failedAt: Date.now(),
        blockUntil: Date.now() + 15000
    };
} else {
    delete retryGuard[guardId];
}

flow.set(retryGuardKey, retryGuard);

return msg;

// ====== LEARNING - PREPROCESS ======
// Sortie 1 = apprentissage
// Sortie 2 = bypass direct

const inv = msg.inverterNum ?? 1;

function cleanString(v) {
    return String(v ?? "").trim();
}

function toNum(x) {
    if (x == null) return null;
    if (typeof x === "string") {
        const s = cleanString(x);
        const m = s.match(/-?\d+(\.\d+)?/);
        if (!m) return null;
        x = m[0];
    }
    const n = Number(x);
    return Number.isFinite(n) ? n : null;
}

function clone(obj) {
    return JSON.parse(JSON.stringify(obj || {}));
}

function getByPath(obj, path) {
    if (!obj || !path) return undefined;
    return path.split(".").reduce((acc, k) => acc && acc[k], obj);
}

function getFingerprint(state) {
    const model = cleanString(state?.diag?.model);
    const serial = cleanString(state?.diag?.serial);
    const fw = cleanString(state?.diag?.fw_main);

    if (serial) return `SERIAL:${serial}`;
    if (model && fw) return `MODELFW:${model}|${fw}`;
    if (model) return `MODEL:${model}`;
    if (fw) return `FW:${fw}`;

    return "";
}

function canonParam(p) {
    const map = {
        battery_bulk_voltage: "battery_bulk_voltage",
        battery_float_voltage: "battery_float_voltage",

        battery_cutoff_voltage: "battery_under_voltage",
        battery_under_voltage: "battery_under_voltage",

        back_to_grid_voltage: "battery_recharge_voltage",
        battery_recharge_voltage: "battery_recharge_voltage",

        back_to_battery_voltage: "battery_re_discharge_voltage",
        battery_re_discharge_voltage: "battery_re_discharge_voltage",

        max_charging_current: "max_charging_current",

        grid_charging_current: "max_ac_charging_current",
        max_ac_charging_current: "max_ac_charging_current",

        charger_source_priority: "charger_source_priority",
        output_source_priority: "output_source_priority"
    };

    return map[cleanString(p)] || cleanString(p);
}

function getRegistry() {
    return {
        battery_bulk_voltage: {
            kind: "number",
            statePath: "params.qpiri.battery_bulk_voltage",
            tolerance: 0.05
        },
        battery_float_voltage: {
            kind: "number",
            statePath: "params.qpiri.battery_float_voltage",
            tolerance: 0.05
        },
        battery_under_voltage: {
            kind: "number",
            statePath: "params.qpiri.battery_under_voltage",
            tolerance: 0.05
        },
        battery_recharge_voltage: {
            kind: "number",
            statePath: "params.qpiri.battery_recharge_voltage",
            tolerance: 0.05
        },
        battery_re_discharge_voltage: {
            kind: "number",
            statePath: "params.qpiri.battery_re_discharge_voltage",
            tolerance: 0.05
        },
        max_charging_current: {
            kind: "number",
            statePath: "params.qpiri.max_charging_current",
            tolerance: 0.5
        },
        max_ac_charging_current: {
            kind: "number",
            statePath: "params.qpiri.max_ac_charging_current",
            tolerance: 0.5
        },
        charger_source_priority: {
            kind: "enum_profile",
            statePath: "params.qpiri.charger_source_priority_code"
        },
        output_source_priority: {
            kind: "enum_profile",
            statePath: "params.qpiri.output_source_priority_code"
        }
    };
}

function isEqual(a, b, tol) {
    const na = Number(a);
    const nb = Number(b);
    if (!Number.isFinite(na) || !Number.isFinite(nb)) return false;
    return Math.abs(na - nb) <= tol;
}

function isTwoChoiceOutputPriorityEnabled(inv) {
    return global.get(`inverter_${inv}.output_priority_2choices`) === true;
}

function getLearnedAll() {
    let all = clone(global.get("learned_commands") || {});
    if (!all || typeof all !== "object" || Array.isArray(all)) all = {};

    const persistentAll = clone(global.get("learned_commands", "persistent") || {});
    if (persistentAll && typeof persistentAll === "object" && !Array.isArray(persistentAll)) {
        for (const fp of Object.keys(persistentAll)) {
            if (!all[fp] || typeof all[fp] !== "object") {
                all[fp] = clone(persistentAll[fp]);
            }
        }
    }

    const backupAll = clone(global.get("learned_commands_backup", "persistent") || {});
    if (backupAll && typeof backupAll === "object" && !Array.isArray(backupAll)) {
        for (const fp of Object.keys(backupAll)) {
            if (!all[fp] || typeof all[fp] !== "object") {
                all[fp] = clone(backupAll[fp]);
            }
        }
    }

    return all;
}

const paramRaw = cleanString(msg._ha_param || msg.topic || "");
const valueRaw = msg._ha_value ?? msg.payload;
const param = canonParam(paramRaw);

const registry = getRegistry();
const cfg = registry[param];

// param non géré par apprentissage => bypass
if (!cfg) {
    return [null, msg];
}

// output_source_priority en mode 2 choix forcé => bypass
if (param === "output_source_priority" && isTwoChoiceOutputPriorityEnabled(inv)) {
    node.status({
        fill: "blue",
        shape: "dot",
        text: "bypass forced 2-choice"
    });
    return [null, msg];
}

const sessionKey = `learn_session_inv${inv}`;
const pendingLearnKey = `learn_pending_inv${inv}`;
const retryGuardKey = `learn_retry_guard_inv${inv}`;

let existing = flow.get(sessionKey);

// purge session morte
if (existing && existing.active === true) {
    const lastTs = Number(existing.updatedAt || existing.createdAt || 0);
    const age = lastTs > 0 ? (Date.now() - lastTs) : 999999;

    if (age > 60000) {
        flow.set(sessionKey, null);
        flow.set(pendingLearnKey, null);
        existing = null;

        node.status({
            fill: "grey",
            shape: "dot",
            text: "learn stale cleared"
        });
    }
}

if (existing && existing.active === true) {
    node.status({
        fill: "yellow",
        shape: "ring",
        text: `learn busy ${existing.param}`
    });
    return [null, null];
}

// état normalisé : RAM puis secours persistent
const state =
    flow.get(`inv${inv}_normalized_state`) ||
    flow.get(`inv${inv}_normalized_state`, "persistent") ||
    global.get(`inv${inv}_normalized_state`) ||
    global.get(`inv${inv}_normalized_state`, "persistent") ||
    {};

const fingerprint = getFingerprint(state);

// si fingerprint absent, bypass
if (!fingerprint) {
    node.status({
        fill: "yellow",
        shape: "dot",
        text: "learn bypass no fingerprint"
    });
    return [null, msg];
}

const currentValue = getByPath(state, cfg.statePath);

// -------------------------------------------------
// Anti-réarmement après échec
// -------------------------------------------------
let retryGuard = flow.get(retryGuardKey);
if (!retryGuard || typeof retryGuard !== "object") retryGuard = {};

const guardId = `${fingerprint}|${param}|${JSON.stringify(valueRaw)}`;
const guard = retryGuard[guardId] || null;

if (guard && guard.blockUntil && Date.now() < Number(guard.blockUntil)) {
    node.status({
        fill: "red",
        shape: "ring",
        text: `learn blocked ${param}`
    });
    return [null, null];
}

// -------------------------------------------------
// MODE NUMERIQUE
// -------------------------------------------------
if (cfg.kind === "number") {
    const requestedValue = toNum(valueRaw);
    if (requestedValue == null) {
        node.status({ fill: "red", shape: "ring", text: `learn invalid ${param}` });
        return [null, null];
    }

    if (isEqual(currentValue, requestedValue, cfg.tolerance)) {
        node.status({
            fill: "green",
            shape: "dot",
            text: `already ${param}=${requestedValue}`
        });
        return [null, null];
    }

    msg._learn = {
        active: true,
        sessionId: `inv${inv}_${param}_${Date.now()}`,
        inverterNum: inv,
        param,
        paramRaw: cleanString(msg._ha_param_raw || msg._ha_param || param),
        requestedValue,
        requestedRaw: msg._ha_value_raw ?? valueRaw,
        baselineValue: currentValue,
        fingerprint,
        statePath: cfg.statePath,
        tolerance: cfg.tolerance,
        kind: "number",
        createdAt: Date.now(),
        updatedAt: Date.now()
    };

    node.status({
        fill: "blue",
        shape: "dot",
        text: `learn ${param} -> ${requestedValue}`
    });

    return [msg, null];
}

// -------------------------------------------------
// MODE ENUM PROFILE
// -------------------------------------------------
if (cfg.kind === "enum_profile") {
    const requestedSlot = Number(valueRaw);
    if (!Number.isInteger(requestedSlot) || requestedSlot < 0 || requestedSlot > 2) {
        node.status({ fill: "red", shape: "ring", text: `learn invalid slot ${param}` });
        return [null, null];
    }

    const currentNum = Number(currentValue);
    if (Number.isInteger(currentNum)) {
        const learnedAll = getLearnedAll();
        const learned = learnedAll[fingerprint]?.[param] || null;
        const profileKey = learned?.profileKey || null;

        if (param === "output_source_priority") {
            if (profileKey === "pop_00_02" && currentNum === requestedSlot) {
                node.status({ fill: "green", shape: "dot", text: `already ${param} slot ${requestedSlot}` });
                return [null, null];
            }
            if (profileKey === "pop_01_03" && currentNum === (requestedSlot + 1)) {
                node.status({ fill: "green", shape: "dot", text: `already ${param} slot ${requestedSlot}` });
                return [null, null];
            }
        }

        if (param === "charger_source_priority") {
            if (profileKey === "pcp_00_02" && currentNum === requestedSlot) {
                node.status({ fill: "green", shape: "dot", text: `already ${param} slot ${requestedSlot}` });
                return [null, null];
            }
            if (profileKey === "pcp_01_03" && currentNum === (requestedSlot + 1)) {
                node.status({ fill: "green", shape: "dot", text: `already ${param} slot ${requestedSlot}` });
                return [null, null];
            }
        }
    }

    msg._learn = {
        active: true,
        sessionId: `inv${inv}_${param}_${Date.now()}`,
        inverterNum: inv,
        param,
        paramRaw: cleanString(msg._ha_param_raw || msg._ha_param || param),
        requestedSlot,
        requestedRaw: msg._ha_value_raw ?? valueRaw,
        baselineValue: currentValue,
        fingerprint,
        statePath: cfg.statePath,
        kind: "enum_profile",
        createdAt: Date.now(),
        updatedAt: Date.now()
    };

    node.status({
        fill: "blue",
        shape: "dot",
        text: `learn ${param} slot ${requestedSlot}`
    });

    return [msg, null];
}

return [null, msg];

// ====== LEARNING - DECISION ======

const inv = msg.inverterNum ?? 1;
if (!msg._learn || typeof msg._learn !== "object") return null;

const sessionKey = `learn_session_inv${inv}`;

function cleanString(v) {
    return String(v ?? "").trim();
}

function normalizeFingerprint(fp) {
    return cleanString(fp);
}

function getParallelId(inv) {
    let machine = flow.get(`inv${inv}_parallel_id`);
    if (machine === undefined || machine === null || machine === "") machine = 0;
    machine = Number(machine);
    if (!Number.isFinite(machine) || machine < 0 || machine > 9) machine = 0;
    return machine;
}

function pad3(x) {
    return String(Math.trunc(Number(x))).padStart(3, "0");
}

function fixed1(x) {
    return Number(x).toFixed(1);
}

function getRegistry(inv) {
    const machine = getParallelId(inv);

    return {
        battery_bulk_voltage: {
            kind: "number",
            candidates: [
                { key: "BULK_PCVV", build: (v) => `PCVV${fixed1(v)}` }
            ]
        },

        battery_float_voltage: {
            kind: "number",
            candidates: [
                { key: "FLOAT_PBFT", build: (v) => `PBFT${fixed1(v)}` }
            ]
        },

        battery_under_voltage: {
            kind: "number",
            candidates: [
                { key: "UNDER_PSDV", build: (v) => `PSDV${fixed1(v)}` }
            ]
        },

        battery_recharge_voltage: {
            kind: "number",
            candidates: [
                { key: "BACK_GRID_PBCV", build: (v) => `PBCV${fixed1(v)}` }
            ]
        },

        battery_re_discharge_voltage: {
            kind: "number",
            candidates: [
                { key: "BACK_BATT_PBDV", build: (v) => `PBDV${fixed1(v)}` }
            ]
        },

        max_charging_current: {
            kind: "number",
            candidates: [
                { key: "MNCHGC_3", build: (v) => `MNCHGC${pad3(v)}` },
                { key: "MNCHGC_MACHINE", build: (v) => `MNCHGC${machine}${pad3(v)}` },
                { key: "MNCHGC_RAW", build: (v) => `MNCHGC${Math.trunc(Number(v))}` },
                { key: "PBDCHGC", build: (v) => `PBDCHGC${pad3(v)}` }
            ]
        },

        max_ac_charging_current: {
            kind: "number",
            candidates: [
                // Ne pas casser les autres onduleurs :
                // on garde plusieurs formats, l'apprentissage choisira le bon
                { key: "MUCHGC_4", build: (v) => `MUCHGC${String(Math.trunc(Number(v))).padStart(4, "0")}` },
                { key: "MUCHGC_3", build: (v) => `MUCHGC${String(Math.trunc(Number(v))).padStart(3, "0")}` },
                { key: "MUCHGC_2", build: (v) => `MUCHGC${String(Math.trunc(Number(v))).padStart(2, "0")}` },
                { key: "MUCHGC_RAW", build: (v) => `MUCHGC${Math.trunc(Number(v))}` },
                { key: "PBCCHGC", build: (v) => `PBCCHGC${pad3(v)}` }
            ]
        },

        output_source_priority: {
            kind: "enum_profile_detect",
            statePath: "params.qpiri.output_source_priority_code",
            family: "POP",
            defaultProfile: "pop_01_03",
            applyByProfile: {
                pop_00_02: {
                    0: { command: "POP00", expectedCode: 0 },
                    1: { command: "POP01", expectedCode: 1 },
                    2: { command: "POP02", expectedCode: 2 }
                },
                pop_01_03: {
                    0: { command: "POP01", expectedCode: 1 },
                    1: { command: "POP02", expectedCode: 2 },
                    2: { command: "POP03", expectedCode: 3 }
                }
            },
            detect: {
                low: { command: "POP00", expectedCode: 0, profileKey: "pop_00_02" },
                high: { command: "POP03", expectedCode: 3, profileKey: "pop_01_03" }
            }
        },

        charger_source_priority: {
            kind: "enum_profile_detect",
            statePath: "params.qpiri.charger_source_priority_code",
            family: "PCP",
            defaultProfile: "pcp_01_03",
            applyByProfile: {
                pcp_00_02: {
                    0: { command: "PCP00", expectedCode: 0 },
                    1: { command: "PCP01", expectedCode: 1 },
                    2: { command: "PCP02", expectedCode: 2 }
                },
                pcp_01_03: {
                    0: { command: "PCP01", expectedCode: 1 },
                    1: { command: "PCP02", expectedCode: 2 },
                    2: { command: "PCP03", expectedCode: 3 }
                }
            },
            detect: {
                low: { command: "PCP00", expectedCode: 0, profileKey: "pcp_00_02" },
                high: { command: "PCP03", expectedCode: 3, profileKey: "pcp_01_03" }
            }
        }
    };
}

const registry = getRegistry(inv);
const param = cleanString(msg._learn.param);
const cfg = registry[param];
if (!cfg) return null;

// garde anti-reset de session
let existing = flow.get(sessionKey);
if (
    msg._learn_action === "next_candidate" &&
    existing &&
    existing.active === true &&
    existing.sessionId === msg._learn.sessionId
) {
    return msg;
}

const learnedAll = global.get("learned_commands") || {};
const fp = normalizeFingerprint(msg._learn.fingerprint);
const learnedForFp = (fp && learnedAll[fp]) ? learnedAll[fp] : {};
const learnedEntry = learnedForFp[param] || null;

const session = {
    active: true,
    sessionId: msg._learn.sessionId,
    inverterNum: inv,
    param,
    paramRaw: cleanString(msg._learn.paramRaw),
    requestedRaw: msg._learn.requestedRaw,
    baselineValue: msg._learn.baselineValue,
    fingerprint: fp,
    statePath: msg._learn.statePath,
    kind: msg._learn.kind,
    createdAt: msg._learn.createdAt || Date.now(),
    updatedAt: Date.now(),
    index: -1,
    currentCandidate: null,
    phase: "build",
    lastAck: null,
    verifySentAt: 0,

    bannedCommands: Array.isArray(learnedEntry?.bannedCommands) ? [...learnedEntry.bannedCommands] : [],
    supportedCodes: Array.isArray(learnedEntry?.supportedCodes) ? [...learnedEntry.supportedCodes] : [],
    rangeStart: Number.isFinite(Number(learnedEntry?.rangeStart)) ? Number(learnedEntry.rangeStart) : null,
    rangeEnd: Number.isFinite(Number(learnedEntry?.rangeEnd)) ? Number(learnedEntry.rangeEnd) : null
};

// -------------------------------------------------
// MODE NUMERIQUE
// -------------------------------------------------
if (msg._learn.kind === "number") {
    session.requestedValue = msg._learn.requestedValue;
    session.tolerance = msg._learn.tolerance;

    let ordered = [];

    // si une commande a déjà été apprise pour ce fingerprint, on la tente d'abord
    if (learnedEntry && learnedEntry.key) {
        ordered.push({
            kind: "number_candidate",
            key: learnedEntry.key,
            source: "learned"
        });
    }

    // puis le registre complet
    for (const c of cfg.candidates) {
        if (!ordered.some(x => x.key === c.key)) {
            ordered.push({
                kind: "number_candidate",
                key: c.key,
                source: "registry"
            });
        }
    }

    session.candidateKeys = ordered;
}

// -------------------------------------------------
// MODE ENUM PROFILE
// -------------------------------------------------
if (msg._learn.kind === "enum_profile") {
    session.kind = "enum_profile_detect";
    session.requestedSlot = msg._learn.requestedSlot;

    let preferred = null;

    if (
        learnedEntry &&
        learnedEntry.mode === "profile" &&
        typeof learnedEntry.profileKey === "string" &&
        cleanString(learnedEntry.profileKey)
    ) {
        preferred = cleanString(learnedEntry.profileKey);
    }

    if (!preferred && typeof cfg.defaultProfile === "string" && cleanString(cfg.defaultProfile)) {
        preferred = cleanString(cfg.defaultProfile);
    }

    session.detectState = {
        phase: "normal",
        preferredProfile: preferred,
        resolvedProfile: null,
        lastVerifiedCode: null,
        probeHighAck: false,
        probeHighNak: false,
        probeLowAck: false,
        probeLowNak: false
    };
}

flow.set(sessionKey, session);

node.status({
    fill: "blue",
    shape: "dot",
    text: session.kind === "enum_profile_detect"
        ? `learn decision ${param} (${session.detectState?.preferredProfile || "auto"})`
        : `learn decision ${param}`
});

msg._learn_action = "next_candidate";
return msg;

// ====== LEARNING - RX FEEDBACK ======
// Entrées possibles:
// - Parser sortie 2
// - Queue Pump timeout sortie 2
//
// Sortie 1 = enqueue QPIRI verify
// Sortie 2 = next candidate / fail

const inv = msg.inverterNum ?? 1;
const sessionKey = `learn_session_inv${inv}`;
const pendingLearnKey = `learn_pending_inv${inv}`;

function cleanUpper(v) {
    return String(v ?? "").trim().toUpperCase();
}

function cleanResp(v) {
    return String(v ?? "")
        .trim()
        .replace(/^\(/, "")
        .trim()
        .toUpperCase();
}

function ensureArray(arr) {
    return Array.isArray(arr) ? arr : [];
}

function addUnique(arr, value) {
    const v = cleanUpper(value);
    const out = ensureArray(arr).map(x => cleanUpper(x));
    if (v && !out.includes(v)) out.push(v);
    return out;
}

function buildFailMsg(session, reason) {
    return {
        inverterNum: inv,
        topic: `voltronic/${inv}/learning/status`,
        payload: {
            active: false,
            success: false,
            reason,
            param: session.param,
            requested_slot: session.requestedSlot ?? null,
            requested_value: session.requestedValue ?? null,
            fingerprint: session.fingerprint,
            finished_at: new Date().toISOString()
        },
        _learn_complete: true,
        _learn_success: false
    };
}

let session = flow.get(sessionKey);
if (!session || session.active !== true) return null;

const pending = flow.get(pendingLearnKey) || null;

const currentCmd = cleanUpper(session.currentCandidate?.command || "");
const msgCmd = cleanUpper(
    msg._raw_command ||
    msg.command ||
    msg._cmd ||
    msg.payload?.raw_command ||
    msg.payload?.command
);

const pendingCmd = cleanUpper(pending?.cmd || "");

const rawResp = cleanResp(
    msg._raw_response ??
    msg.raw_response ??
    msg.payload?.raw_response ??
    msg.payload?.raw ??
    ""
);

const isTimeout = (msg._learn_timeout === true || msg.payload?.timeout === true);

const isNak =
    msg.payload?.nak === true ||
    rawResp.startsWith("NAK");

const isAck =
    !isTimeout &&
    !isNak &&
    (
        rawResp.startsWith("ACK") ||
        msg.payload?.nak === false
    );

function markResolvedProfile(session, profileKey) {
    const ds = session.detectState || {};
    ds.resolvedProfile = profileKey;

    if (profileKey === "pop_00_02" || profileKey === "pcp_00_02") {
        session.rangeStart = 0;
        session.rangeEnd = 2;
    } else if (profileKey === "pop_01_03" || profileKey === "pcp_01_03") {
        session.rangeStart = 1;
        session.rangeEnd = 3;
    }

    session.detectState = ds;
}

function advanceDetectPhaseOnFailure(session, reasonType = "") {
    if (session.kind !== "enum_profile_detect") {
        session.phase = "build";
        return { type: "next" };
    }

    const detectState = session.detectState || {
        phase: "normal",
        preferredProfile: null,
        resolvedProfile: null,
        lastVerifiedCode: null,
        probeHighAck: false,
        probeHighNak: false,
        probeLowAck: false,
        probeLowNak: false
    };

    const currentCommand = cleanUpper(session.currentCandidate?.command || "");
    const phase = cleanUpper(session.currentCandidate?.phase || detectState.phase || "");

    // -------------------------------------------------
    // Si le 03 échoue => plage basse
    // -------------------------------------------------
    if ((isNak || isTimeout) && (currentCommand === "POP03" || currentCommand === "PCP03")) {
        session.bannedCommands = addUnique(session.bannedCommands, currentCommand);
        detectState.probeHighNak = true;

        if (currentCommand === "POP03") {
            markResolvedProfile(session, "pop_00_02");
        } else if (currentCommand === "PCP03") {
            markResolvedProfile(session, "pcp_00_02");
        }

        detectState.phase = "reapply_final";
        session.detectState = detectState;
        session.phase = "build";
        return { type: "next" };
    }

    // -------------------------------------------------
    // Si le 00 échoue => plage haute
    // -------------------------------------------------
    if ((isNak || isTimeout) && (currentCommand === "POP00" || currentCommand === "PCP00")) {
        detectState.probeLowNak = true;

        if (currentCommand === "POP00") {
            markResolvedProfile(session, "pop_01_03");
        } else if (currentCommand === "PCP00") {
            markResolvedProfile(session, "pcp_01_03");
        }

        detectState.phase = "reapply_final";
        session.detectState = detectState;
        session.phase = "build";
        return { type: "next" };
    }

    // -------------------------------------------------
    // Si la tentative normale échoue, on force une vraie détection :
    // 1) probe_low (00)
    // 2) probe_high (03)
    // -------------------------------------------------
    if (phase === "NORMAL" || detectState.phase === "normal") {
        detectState.phase = "probe_low";
        session.detectState = detectState;
        session.phase = "build";
        return { type: "next" };
    }

    if (phase === "PROBE_LOW" || detectState.phase === "probe_low") {
        detectState.phase = "probe_high";
        session.detectState = detectState;
        session.phase = "build";
        return { type: "next" };
    }

    if (phase === "PROBE_HIGH" || detectState.phase === "probe_high") {
        session.detectState = detectState;
        session.phase = "failed";
        return { type: "fail", reason: reasonType || "probe_high_failed" };
    }

    if (phase === "REAPPLY_FINAL" || detectState.phase === "reapply_final") {
        session.detectState = detectState;
        session.phase = "failed";
        return { type: "fail", reason: reasonType || "reapply_failed" };
    }

    session.phase = "failed";
    return { type: "fail", reason: reasonType || "invalid_detect_phase" };
}

// -------------------------
// PHASE 1 : wait_ack
// -------------------------
if (session.phase === "wait_ack") {
    let cmdMatches = false;

    if (pendingCmd && msgCmd && pendingCmd === msgCmd) {
        cmdMatches = true;
    } else if (currentCmd && msgCmd && currentCmd === msgCmd) {
        cmdMatches = true;
    }

    if (isTimeout) {
        if (pendingCmd && currentCmd && pendingCmd === currentCmd) {
            cmdMatches = true;
        } else if (!pendingCmd && currentCmd) {
            cmdMatches = true;
        }
    }

    if (!cmdMatches) return null;

    if (isTimeout) {
        session.lastAck = "TIMEOUT";
        session.updatedAt = Date.now();

        const step = advanceDetectPhaseOnFailure(session, "candidate_timeout");

        flow.set(sessionKey, session);
        flow.set(pendingLearnKey, null);

        if (step.type === "fail") {
            node.status({ fill: "red", shape: "ring", text: `learn fail ${session.param}` });
            return [null, buildFailMsg(session, step.reason || "candidate_timeout")];
        }

        node.status({ fill: "red", shape: "ring", text: `learn timeout ${session.param}` });

        return [null, {
            inverterNum: inv,
            _learn_action: "next_candidate",
            _learn: { sessionId: session.sessionId }
        }];
    }

    if (isNak) {
        session.lastAck = "NAK";
        session.updatedAt = Date.now();

        const currentCommand = cleanUpper(session.currentCandidate?.command || "");
        if (currentCommand === "POP03" || currentCommand === "PCP03") {
            session.bannedCommands = addUnique(session.bannedCommands, currentCommand);
        }

        const step = advanceDetectPhaseOnFailure(session, "candidate_nak");

        flow.set(sessionKey, session);
        flow.set(pendingLearnKey, null);

        if (step.type === "fail") {
            node.status({ fill: "red", shape: "ring", text: `learn fail ${session.param}` });
            return [null, buildFailMsg(session, step.reason || "candidate_nak")];
        }

        node.status({
            fill: "yellow",
            shape: "ring",
            text: `learn NAK ${session.currentCandidate?.command || session.param}`
        });

        return [null, {
            inverterNum: inv,
            _learn_action: "next_candidate",
            _learn: { sessionId: session.sessionId }
        }];
    }

    if (isAck) {
        session.lastAck = "ACK";
        session.phase = "wait_state";
        session.verifySentAt = Date.now();
        session.updatedAt = Date.now();

        const currentCommand = cleanUpper(session.currentCandidate?.command || "");
        const currentPhase = cleanUpper(session.currentCandidate?.phase || "");

        const ds = session.detectState || {};
        if (currentCommand === "POP03" || currentCommand === "PCP03") ds.probeHighAck = true;
        if (currentCommand === "POP00" || currentCommand === "PCP00") ds.probeLowAck = true;
        session.detectState = ds;

        flow.set(sessionKey, session);
        flow.set(pendingLearnKey, {
            sessionId: session.sessionId,
            param: session.param,
            cmd: "QPIRI",
            phase: "wait_state",
            ts: Date.now()
        });

        const verifyMsg = {
            inverterNum: inv,
            command: "QPIRI",
            _cmd: "QPIRI",
            _raw_command: "QPIRI",
            payload: "QPIRI",
            _burst: false,
            _origin: "learn_retry",
            _learn: {
                sessionId: session.sessionId,
                param: session.param,
                requestedValue: session.requestedValue ?? null,
                requestedSlot: session.requestedSlot ?? null,
                candidateKey: session.currentCandidate?.key || null,
                profileKey: session.currentCandidate?.profileKey || null,
                detectPhase: currentPhase || session.detectState?.phase || null,
                phase: "verify"
            }
        };

        node.status({
            fill: "blue",
            shape: "dot",
            text: `learn verify ${session.param}`
        });

        return [verifyMsg, null];
    }

    return null;
}

// -------------------------
// PHASE 2 : wait_state
// -------------------------
if (session.phase === "wait_state") {
    const waitingForQpiri = (pendingCmd === "QPIRI");
    if (!waitingForQpiri) return null;

    if (isTimeout) {
        session.lastAck = "QPIRI_TIMEOUT";
        session.updatedAt = Date.now();

        const step = advanceDetectPhaseOnFailure(session, "verify_timeout");

        flow.set(sessionKey, session);
        flow.set(pendingLearnKey, null);

        if (step.type === "fail") {
            node.status({ fill: "red", shape: "ring", text: `learn fail ${session.param}` });
            return [null, buildFailMsg(session, step.reason || "verify_timeout")];
        }

        node.status({
            fill: "red",
            shape: "ring",
            text: `verify timeout ${session.param}`
        });

        return [null, {
            inverterNum: inv,
            _learn_action: "next_candidate",
            _learn: { sessionId: session.sessionId }
        }];
    }

    return null;
}

return null;

// ====== LEARNING - BUILD CANDIDATE ======
// Sortie 1 = queue enqueue
// Sortie 2 = complete fail

const inv = msg.inverterNum ?? 1;

// -------------------------------------------------
// Helpers
// -------------------------------------------------
function getParallelId(inv) {
    let machine = flow.get(`inv${inv}_parallel_id`);
    if (machine === undefined || machine === null || machine === "") machine = 0;
    machine = Number(machine);
    if (!Number.isFinite(machine) || machine < 0 || machine > 9) machine = 0;
    return machine;
}

function pad3(x) {
    return String(Math.trunc(Number(x))).padStart(3, "0");
}

function fixed1(x) {
    return Number(x).toFixed(1);
}

function isBanned(session, cmd) {
    const banned = Array.isArray(session?.bannedCommands) ? session.bannedCommands : [];
    return banned.includes(String(cmd || "").trim().toUpperCase());
}

function getRegistry(inv) {
