        text: `restore wait identity inv${inv}`
    });
    return msg;
}

const currentVariants = buildIdentityVariants(identity);

// lecture marqueurs
const lastAppliedKey = cleanString(
    flow.get(`inv${inv}_profile_identity_key`, "persistent") ||
    flow.get(`inv${inv}_profile_identity_key`) ||
    ""
);

const lastMatchedSavedKey = cleanString(
    flow.get(`inv${inv}_profile_saved_identity_key`, "persistent") ||
    flow.get(`inv${inv}_profile_saved_identity_key`) ||
    ""
);

// profils persistants
let profiles = clone(global.get("inverter_profiles", "persistent") || {});
if (!profiles || typeof profiles !== "object") profiles = {};

// learned_commands RAM
let learnedAll = clone(global.get("learned_commands") || {});
if (!learnedAll || typeof learnedAll !== "object") learnedAll = {};

// learned_commands persistent
let learnedPersistent = clone(global.get("learned_commands", "persistent") || {});
if (!learnedPersistent || typeof learnedPersistent !== "object") learnedPersistent = {};

// backup persistant
let learnedBackup = clone(global.get("learned_commands_backup", "persistent") || {});
if (!learnedBackup || typeof learnedBackup !== "object") learnedBackup = {};

const profile = profiles[`inv${inv}`] || null;

// aucun profil sauvegardé
if (!profile || !profile.identity) {
    flow.set(`inv${inv}_profile_identity_key`, identity.key, "persistent");
    flow.set(`inv${inv}_profile_identity_key`, identity.key);
    flow.set(`inv${inv}_profile_saved_identity_key`, "", "persistent");
    flow.set(`inv${inv}_profile_saved_identity_key`, "");

    node.status({
        fill: "yellow",
        shape: "dot",
        text: `no saved profile inv${inv}`
    });
    return msg;
}

const savedIdentity = {
    model: cleanString(profile.identity.model),
    serial: cleanString(profile.identity.serial),
    fw_main: cleanString(profile.identity.fw_main),
    fingerprint: cleanString(profile.identity.fingerprint),
    key: cleanString(profile.identity.key)
};

const compare = compareIdentity(savedIdentity, identity);
const savedVariants = buildIdentityVariants(savedIdentity);

// Vérifie si déjà réellement restauré
const currentFp = cleanString(identity.fingerprint);
const alreadyLoaded =
    lastAppliedKey === identity.key &&
    lastMatchedSavedKey === savedIdentity.key &&
    learnedAll &&
    typeof learnedAll === "object" &&
    learnedAll[currentFp] &&
    typeof learnedAll[currentFp] === "object" &&
    Object.keys(learnedAll[currentFp]).length > 0;

// -------------------------------------------------
// CAS 1 : au moins 1 élément match => restauration
// -------------------------------------------------
if (compare.match) {
    if (!alreadyLoaded) {
        const sourceLearned = getProfileLearnedMap(profile, learnedPersistent, learnedBackup);
        const savedFp = cleanString(savedIdentity.fingerprint);

        // injecte la config apprise sous le fingerprint courant
        learnedAll[currentFp] = clone(sourceLearned || {});
        global.set("learned_commands", learnedAll);
        global.set("learned_commands", learnedAll, "persistent");

        // garde aussi la version sous le fingerprint sauvegardé si différent
        if (savedFp && savedFp !== currentFp) {
            learnedAll[savedFp] = clone(sourceLearned || {});
            global.set("learned_commands", learnedAll);
            global.set("learned_commands", learnedAll, "persistent");
        }

        learnedBackup[currentFp] = clone(sourceLearned || {});
        global.set("learned_commands_backup", learnedBackup, "persistent");

        if (savedFp && savedFp !== currentFp) {
            learnedBackup[savedFp] = clone(sourceLearned || {});
            global.set("learned_commands_backup", learnedBackup, "persistent");
        }
    }

    flow.set(`inv${inv}_profile_identity_key`, identity.key, "persistent");
    flow.set(`inv${inv}_profile_identity_key`, identity.key);

    flow.set(`inv${inv}_profile_saved_identity_key`, savedIdentity.key, "persistent");
    flow.set(`inv${inv}_profile_saved_identity_key`, savedIdentity.key);

    node.status({
        fill: "green",
        shape: "dot",
        text: alreadyLoaded ? `profile already ok inv${inv}` : `profile restored inv${inv}`
    });

    return msg;
}

// -------------------------------------------------
// CAS 2 : pas de match mais pas assez d'éléments pour conclure => attendre
// -------------------------------------------------
if (!compare.contradiction) {
    node.status({
        fill: "yellow",
        shape: "ring",
        text: `restore wait more id inv${inv}`
    });
    return msg;
}

// -------------------------------------------------
// CAS 3 : contradiction claire => purge
// -------------------------------------------------
delete profiles[`inv${inv}`];
global.set("inverter_profiles", profiles, "persistent");

const oldFingerprint = cleanString(savedIdentity.fingerprint || "");

if (oldFingerprint && learnedAll[oldFingerprint]) {
    delete learnedAll[oldFingerprint];
    global.set("learned_commands", learnedAll);
    global.set("learned_commands", learnedAll, "persistent");
}

if (oldFingerprint && learnedPersistent[oldFingerprint]) {
    delete learnedPersistent[oldFingerprint];
    global.set("learned_commands", learnedPersistent, "persistent");
}

if (oldFingerprint && learnedBackup[oldFingerprint]) {
    delete learnedBackup[oldFingerprint];
    global.set("learned_commands_backup", learnedBackup, "persistent");
}

flow.set(`learn_session_inv${inv}`, null);
flow.set(`learn_pending_inv${inv}`, null);
flow.set(`learn_session_inv${inv}`, null, "persistent");
flow.set(`learn_pending_inv${inv}`, null, "persistent");

flow.set(`inv${inv}_profile_identity_key`, identity.key, "persistent");
flow.set(`inv${inv}_profile_identity_key`, identity.key);

flow.set(`inv${inv}_profile_saved_identity_key`, "", "persistent");
flow.set(`inv${inv}_profile_saved_identity_key`, "");

node.status({
    fill: "red",
    shape: "ring",
    text: `profile cleared inv${inv} changed`
});

return msg;

// =====================================
// DAILY ENERGY CALC / FALLBACK
// VERSION ROBUSTE PERSISTENCE + FILE STORE + ANTI RESET POST UPDATE
// =====================================

if (!msg || !msg.payload || typeof msg.payload !== "object") return msg;

const inv = Number(msg.inverterNum ?? msg.payload.inverter ?? 1) || 1;
const state = { ...msg.payload };

const premiumActive = global.get("premium.active") === true;
const fs = global.get("fs");
const path = global.get("path");

const ENERGY_STORE_FILE = "/config/smart_voltronic_energy_store.json";
const FILE_STORE_VERSION = 1;
const fileInvKey = `inverter_${inv}`;

function toNum(v) {
  const n = Number(v);
  return Number.isFinite(n) ? n : null;
}

function round2(v) {
  const n = Number(v);
  return Number.isFinite(n) ? Math.round((n + Number.EPSILON) * 100) / 100 : 0;
}

function clampNonNegative(v, fb = 0) {
  const n = Number(v);
  if (!Number.isFinite(n)) return fb;
  return Math.max(0, round2(n));
}

function ensureObj(v, fb = {}) {
  return v && typeof v === "object" && !Array.isArray(v) ? v : fb;
}

function pickFirstNumber(...vals) {
  for (const v of vals) {
    const n = Number(v);
    if (Number.isFinite(n)) return n;
  }
  return null;
}

function getSafeTimezone() {
  let tz = (global.get("addon_timezone") || "UTC").toString().trim();
  if (!tz) tz = "UTC";

  try {
    new Intl.DateTimeFormat("en-CA", { timeZone: tz }).format(new Date());
  } catch (e) {
    tz = "UTC";
  }

  return tz;
}

function localDateParts(d = new Date()) {
  const tz = getSafeTimezone();

  const parts = new Intl.DateTimeFormat("en-CA", {
    timeZone: tz,
    year: "numeric",
    month: "2-digit",
    day: "2-digit",
    hour: "2-digit",
    minute: "2-digit",
    second: "2-digit",
    hour12: false
  }).formatToParts(d);

  const get = (t) => parts.find(p => p.type === t)?.value;

  const year = get("year");
  const month = get("month");
  const day = get("day");
  const hour = Number(get("hour") || 0);
  const minute = Number(get("minute") || 0);

  return {
    year,
    month,
    day,
    hour,
    minute,
    minutesSinceMidnight: hour * 60 + minute,
    dayKey: `${year}${month}${day}`,
    monthKey: `${year}${month}`,
    yearKey: `${year}`
  };
}

function safeGet(key, storeName) {
  try {
    return flow.get(key, storeName);
  } catch (e) {
    return undefined;
  }
}

function safeSet(key, value, storeName) {
  try {
    flow.set(key, value, storeName);
    return true;
  } catch (e) {
    return false;
  }
}

function getRobust(key, fallback = null) {
  const fromPersistent = safeGet(key, "persistent");
  if (fromPersistent !== undefined && fromPersistent !== null) return fromPersistent;

  const fromDefault = safeGet(key);
  if (fromDefault !== undefined && fromDefault !== null) return fromDefault;

  return fallback;
}

function setRobust(key, value) {
  try {
    flow.set(key, value);
  } catch (e) { }

  safeSet(key, value, "persistent");
}

function readEnergyFileStore() {
  if (!fs) return null;

  try {
    if (!fs.existsSync(ENERGY_STORE_FILE)) return null;

    const raw = fs.readFileSync(ENERGY_STORE_FILE, "utf8");
    const data = JSON.parse(raw);

    if (!data || typeof data !== "object") return null;
    if (!data.inverters || typeof data.inverters !== "object") return null;

    return data;
  } catch (e) {
    node.warn("Energy file store read error: " + e.message);
    return null;
  }
}

function restoreStatsFromFile(invKey) {
  const data = readEnergyFileStore();
  const invData = data?.inverters?.[invKey];

  if (!invData || typeof invData !== "object") return null;
  if (!invData.stats || typeof invData.stats !== "object") return null;

  return invData.stats;
}

function restoreLastValuesFromFile(invKey) {
  const data = readEnergyFileStore();
  const invData = data?.inverters?.[invKey];

  if (!invData || typeof invData !== "object") return null;
  if (!invData.last_values || typeof invData.last_values !== "object") return null;

  return invData.last_values;
}

function writeEnergyFileStoreForInv(invKey, patch) {
  if (!fs) return false;

  try {
    let data = readEnergyFileStore();

    if (!data || typeof data !== "object") {
      data = {
        version: FILE_STORE_VERSION,
        updated_at: null,
        inverters: {}
      };
    }

    if (!data.inverters || typeof data.inverters !== "object") {
      data.inverters = {};
    }

    const previous = ensureObj(data.inverters[invKey], {});

    data.version = FILE_STORE_VERSION;
    data.updated_at = new Date().toISOString();

    data.inverters[invKey] = {
      ...previous,
      ...patch,
      updated_at: new Date().toISOString()
    };

    if (path && typeof path.dirname === "function") {
      fs.mkdirSync(path.dirname(ENERGY_STORE_FILE), { recursive: true });
    } else {
      fs.mkdirSync("/config", { recursive: true });
    }

    fs.writeFileSync(ENERGY_STORE_FILE, JSON.stringify(data, null, 2), "utf8");
    return true;
  } catch (e) {
    node.warn("Energy file store write error: " + e.message);
    return false;
  }
}

function setDiagSource(diag, key, source, reason = "") {
  diag[key] = source;
  if (reason) diag[`${key}_reason`] = reason;
}

const nowKeys = localDateParts(new Date());
const dayKey = nowKeys.dayKey;
const monthKey = nowKeys.monthKey;
const yearKey = nowKeys.yearKey;
const tsNow = Date.now();

state.diag = ensureObj(state.diag, {});
state.diag.energy_logic_version = "source_lock_v8_pv_sum_native_zero_spike_guard";
state.diag.energy_timezone = getSafeTimezone();
state.diag.energy_file_store = ENERGY_STORE_FILE;

const statsKey = `inv${inv}_energy_stats`;

let statsRestoreSource = "new";

let stats = restoreStatsFromFile(fileInvKey);
if (stats) {
  statsRestoreSource = "file_config";
} else {
  stats = getRobust(statsKey, null);
  if (stats) statsRestoreSource = "node_red_context";
}

if (!stats || typeof stats !== "object") {
  stats = {
    lastTs: tsNow,
    lastDayKey: dayKey,
    lastMonthKey: monthKey,
    lastYearKey: yearKey,
    lastDayResetTs: tsNow,
    day: { pv: 0, load: 0, grid: 0, battCharge: 0, battDischarge: 0 },
    month: { pv: 0, load: 0, grid: 0, battCharge: 0, battDischarge: 0 },
    year: { pv: 0, load: 0, grid: 0, battCharge: 0, battDischarge: 0 },
    total: { pv: 0, load: 0, grid: 0, battCharge: 0, battDischarge: 0 }
  };
}

stats.day = ensureObj(stats.day, { pv: 0, load: 0, grid: 0, battCharge: 0, battDischarge: 0 });
stats.month = ensureObj(stats.month, { pv: 0, load: 0, grid: 0, battCharge: 0, battDischarge: 0 });
stats.year = ensureObj(stats.year, { pv: 0, load: 0, grid: 0, battCharge: 0, battDischarge: 0 });
stats.total = ensureObj(stats.total, { pv: 0, load: 0, grid: 0, battCharge: 0, battDischarge: 0 });

for (const bucket of ["day", "month", "year", "total"]) {
  stats[bucket].pv = Number(stats[bucket].pv) || 0;
  stats[bucket].load = Number(stats[bucket].load) || 0;
  stats[bucket].grid = Number(stats[bucket].grid) || 0;
  stats[bucket].battCharge = Number(stats[bucket].battCharge) || 0;
  stats[bucket].battDischarge = Number(stats[bucket].battDischarge) || 0;
}

if (!Number.isFinite(Number(stats.lastTs))) stats.lastTs = tsNow;
if (!stats.lastDayKey) stats.lastDayKey = dayKey;
if (!stats.lastMonthKey) stats.lastMonthKey = monthKey;
if (!stats.lastYearKey) stats.lastYearKey = yearKey;
if (!Number.isFinite(Number(stats.lastDayResetTs))) stats.lastDayResetTs = tsNow;

let dtHours = (tsNow - Number(stats.lastTs || tsNow)) / 3600000;
if (!Number.isFinite(dtHours) || dtHours < 0) dtHours = 0;
if (dtHours > 1) dtHours = 0;

const dayChanged = stats.lastDayKey !== dayKey;
const monthChanged = stats.lastMonthKey !== monthKey;
const yearChanged = stats.lastYearKey !== yearKey;

if (dayChanged) {
  stats.day = { pv: 0, load: 0, grid: 0, battCharge: 0, battDischarge: 0 };
  stats.lastDayResetTs = tsNow;
}

if (monthChanged) {
  stats.month = { pv: 0, load: 0, grid: 0, battCharge: 0, battDischarge: 0 };
}

if (yearChanged) {
  stats.year = { pv: 0, load: 0, grid: 0, battCharge: 0, battDischarge: 0 };
}

// PV power robuste : certains onduleurs renvoient pv_total_power = 0
// alors que pv1_power / pv2_power sont bien présents.
// Dans ce cas on force le total calculé pour que les compteurs PV avancent.
const pv1Power = Number(state.pv1_power);
const pv2Power = Number(state.pv2_power);
const pvInputsTotalPower =
  (Number.isFinite(pv1Power) ? Math.max(0, pv1Power) : 0) +
  (Number.isFinite(pv2Power) ? Math.max(0, pv2Power) : 0);

let pvPower = pickFirstNumber(
  state.pv_total_power,
  state.pv_power,
  state.solar_power
);

if (!Number.isFinite(pvPower) || pvPower <= 0) {
  pvPower = pvInputsTotalPower > 0 ? pvInputsTotalPower : 0;
}

// On republie aussi pv_total_power corrigé pour le dashboard.
if (pvInputsTotalPower > 0 && (!Number.isFinite(Number(state.pv_total_power)) || Number(state.pv_total_power) <= 0)) {
  state.pv_total_power = round2(pvInputsTotalPower);
}

const loadPower =
  pickFirstNumber(
    state.ac_output_active_power,
    state.load_power,
    state.output_load_power,
    state.ac_output_power
  ) || 0;

const batteryPower =
  pickFirstNumber(
    state.battery_power,
    state.global_battery_power
  ) || 0;

let gridPower =
  pickFirstNumber(
    state.grid_power,
    state.utility_power
  );

if (!Number.isFinite(gridPower)) {
  const battContributionToLoad = batteryPower < 0 ? Math.abs(batteryPower) : 0;
  const battChargeFromSystem = batteryPower > 0 ? batteryPower : 0;
  gridPower = Math.max(0, loadPower - pvPower - battContributionToLoad + battChargeFromSystem);
}

gridPower = Math.max(0, gridPower);

const MIDNIGHT_GUARD_MS = 5 * 60 * 1000;
const BATTERY_IDLE_W = 25;
const BATTERY_STRONG_ACTIVITY_W = 150;

const msSinceDayReset = tsNow - Number(stats.lastDayResetTs || tsNow);
const withinMidnightGuard = msSinceDayReset >= 0 && msSinceDayReset < MIDNIGHT_GUARD_MS;

let batteryChargeGuarded = false;
let batteryDischargeGuarded = false;

const pvInc = Math.max(0, pvPower) * dtHours / 1000;
const loadInc = Math.max(0, loadPower) * dtHours / 1000;
const gridInc = Math.max(0, gridPower) * dtHours / 1000;

const battChargePower = batteryPower > 0 ? batteryPower : 0;
const battDischargePower = batteryPower < 0 ? Math.abs(batteryPower) : 0;

let battChargeInc = Math.max(0, battChargePower) * dtHours / 1000;
let battDischargeInc = Math.max(0, battDischargePower) * dtHours / 1000;

if (withinMidnightGuard) {
  if (battChargePower > 0 && battChargePower < BATTERY_STRONG_ACTIVITY_W) {
    battChargeInc = 0;
    batteryChargeGuarded = true;
  }

  if (battDischargePower > 0 && battDischargePower < BATTERY_STRONG_ACTIVITY_W) {
    battDischargeInc = 0;
    batteryDischargeGuarded = true;
  }

  if (Math.abs(batteryPower) <= BATTERY_IDLE_W) {
    battChargeInc = 0;
    battDischargeInc = 0;
    batteryChargeGuarded = true;
    batteryDischargeGuarded = true;
  }
}

if (dtHours > 0) {
  stats.day.pv += pvInc;
  stats.day.load += loadInc;
  stats.day.grid += gridInc;
  stats.day.battCharge += battChargeInc;
  stats.day.battDischarge += battDischargeInc;

  stats.month.pv += pvInc;
  stats.month.load += loadInc;
  stats.month.grid += gridInc;
  stats.month.battCharge += battChargeInc;
  stats.month.battDischarge += battDischargeInc;

  stats.year.pv += pvInc;
  stats.year.load += loadInc;
  stats.year.grid += gridInc;
  stats.year.battCharge += battChargeInc;
  stats.year.battDischarge += battDischargeInc;

  stats.total.pv += pvInc;
  stats.total.load += loadInc;
  stats.total.grid += gridInc;
  stats.total.battCharge += battChargeInc;
  stats.total.battDischarge += battDischargeInc;
}

let calcPvDay = clampNonNegative(stats.day.pv);
let calcPvMonth = clampNonNegative(stats.month.pv);
let calcPvYear = clampNonNegative(stats.year.pv);
let calcPvTotal = clampNonNegative(stats.total.pv);

let calcLoadDay = clampNonNegative(stats.day.load);
let calcLoadMonth = clampNonNegative(stats.month.load);
let calcLoadYear = clampNonNegative(stats.year.load);
let calcLoadTotal = clampNonNegative(stats.total.load);

let calcGridDay = clampNonNegative(stats.day.grid);
let calcGridMonth = clampNonNegative(stats.month.grid);
let calcGridYear = clampNonNegative(stats.year.grid);
let calcGridTotal = clampNonNegative(stats.total.grid);

let calcBattChargeDay = clampNonNegative(stats.day.battCharge);
let calcBattChargeMonth = clampNonNegative(stats.month.battCharge);
let calcBattChargeYear = clampNonNegative(stats.year.battCharge);
let calcBattChargeTotal = clampNonNegative(stats.total.battCharge);

let calcBattDischargeDay = clampNonNegative(stats.day.battDischarge);
let calcBattDischargeMonth = clampNonNegative(stats.month.battDischarge);
let calcBattDischargeYear = clampNonNegative(stats.year.battDischarge);
let calcBattDischargeTotal = clampNonNegative(stats.total.battDischarge);

const lastValues = restoreLastValuesFromFile(fileInvKey) || {};

const justRestored =
  statsRestoreSource === "file_config" ||
  statsRestoreSource === "node_red_context";

const noNewEnergyIntegration = dtHours === 0;

function protectRestoredValue(currentValue, statsValue, lastFileValue) {
  const current = Number(currentValue) || 0;
  const fromStats = Number(statsValue) || 0;
  const fromFile = Number(lastFileValue) || 0;

  if (current > 0) return round2(current);
  if (fromStats > 0) return round2(fromStats);
  if (fromFile > 0) return round2(fromFile);

  return 0;
}

if (justRestored && noNewEnergyIntegration && !dayChanged) {
  calcPvDay = protectRestoredValue(calcPvDay, stats.day.pv, lastValues.pv_energy_day_kwh);
  calcLoadDay = protectRestoredValue(calcLoadDay, stats.day.load, lastValues.load_energy_day_kwh);
  calcGridDay = protectRestoredValue(calcGridDay, stats.day.grid, lastValues.grid_energy_day_kwh);
  calcBattChargeDay = protectRestoredValue(calcBattChargeDay, stats.day.battCharge, lastValues.battery_charge_day_kwh);
  calcBattDischargeDay = protectRestoredValue(calcBattDischargeDay, stats.day.battDischarge, lastValues.battery_discharge_day_kwh);
}

const inverterPvDayRaw = toNum(state.pv_energy_day_kwh);
const inverterPvMonthRaw = toNum(state.pv_energy_month_kwh);
const inverterPvYearRaw = toNum(state.pv_energy_year_kwh);
const inverterPvTotalRaw = toNum(state.pv_energy_total_kwh);

const inverterLoadDayRaw = toNum(state.load_energy_day_kwh);
const inverterLoadMonthRaw = toNum(state.load_energy_month_kwh);
const inverterLoadYearRaw = toNum(state.load_energy_year_kwh);
const inverterLoadTotalRaw = toNum(state.load_energy_total_kwh);

function nativeOk(v) {
  const n = Number(v);
  return Number.isFinite(n) && n >= 0;
}

function energyCommandForMetric(metric) {
  const m = String(metric || "").toLowerCase();

  if (m === "pv_day") return "QED";
  if (m === "pv_month") return "QEM";
  if (m === "pv_year") return "QEY";
  if (m === "pv_total") return "QET";

  if (m === "load_day") return "QLD";
  if (m === "load_month") return "QLM";
  if (m === "load_year") return "QLY";
  if (m === "load_total") return "QLT";

  return "";
}

function isNativeEnergyCommandUsable(metric) {
  const cmd = energyCommandForMetric(metric);
  if (!cmd) return true;

  const st = flow.get(`inv${inv}_cmd_state_${cmd}`);
  if (!st || typeof st !== "object") return true;

  // Si la commande a été apprise comme non supportée, on n'utilise plus
  // l'ancienne valeur native qui reste dans le state.
  if (st.disabled === true) return false;

  return true;
}

function lastPublishedValueForMetric(metric) {
  const map = {
    pv_day: "pv_energy_day_kwh",
    pv_month: "pv_energy_month_kwh",
    pv_year: "pv_energy_year_kwh",
    pv_total: "pv_energy_total_kwh",

    load_day: "load_energy_day_kwh",
    load_month: "load_energy_month_kwh",
    load_year: "load_energy_year_kwh",
    load_total: "load_energy_total_kwh"
  };

  const key = map[String(metric || "").toLowerCase()];
  if (!key) return 0;

  return Number(lastValues?.[key]) || 0;
}

function resolveNativeOrCalc(nativeVal, calcVal, metric, currentPower = 0) {
  const n = Number(nativeVal);
  const c = Number(calcVal) || 0;
  const m = String(metric || "").toLowerCase();
  const last = lastPublishedValueForMetric(m);

  const nativeUsable = isNativeEnergyCommandUsable(m);

  // Ne jamais laisser une valeur native à 0 écraser un compteur calculé
  // déjà positif : c'était la cause des remises à zéro month/total.
  if (nativeOk(n) && n === 0 && c > 0) {
    return {
      value: clampNonNegative(c),
      source: "calculated",
      reason: "native_zero_protected"
    };
  }

  // Si l'onduleur ne supporte pas la commande énergie, on reste sur le calcul.
  if (!nativeUsable) {
    return {
      value: clampNonNegative(Math.max(c, last)),
      source: "calculated",
      reason: "native_command_disabled"
    };
  }

  // Protection HA Energie : sur les compteurs total_increasing, un gros saut
  // natif d'un onduleur non fiable crée des pics énormes. On accepte le natif
  // seulement s'il est cohérent avec la dernière valeur publiée.
  if ((m.endsWith("_total") || m.endsWith("_month") || m.endsWith("_year")) && nativeOk(n)) {
    const maxStepKwh = m.endsWith("_total") ? 50 : 30;

    if (last > 0 && n > last + maxStepKwh) {
      return {
        value: clampNonNegative(Math.max(c, last)),
        source: "calculated",
        reason: "native_spike_protected"
      };
    }

    if (last === 0 && c > 0 && n > c + maxStepKwh) {
      return {
        value: clampNonNegative(c),
        source: "calculated",
        reason: "native_initial_spike_protected"
      };
    }
  }

  if (nativeOk(n)) {
    return {
      value: clampNonNegative(n),
      source: "inverter",
      reason: "native_valid"
    };
  }

  return {
    value: clampNonNegative(Math.max(c, last)),
    source: "calculated",
    reason: "native_missing_or_invalid"
  };
}

const pvDayResolved = resolveNativeOrCalc(inverterPvDayRaw, calcPvDay, "pv_day", pvPower);
const pvMonthResolved = resolveNativeOrCalc(inverterPvMonthRaw, calcPvMonth, "pv_month", pvPower);
