    battery_charge_month_kwh: state.battery_charge_month_kwh,
    battery_charge_year_kwh: state.battery_charge_year_kwh,
    battery_charge_total_kwh: state.battery_charge_total_kwh,

    battery_discharge_day_kwh: state.battery_discharge_day_kwh,
    battery_discharge_month_kwh: state.battery_discharge_month_kwh,
    battery_discharge_year_kwh: state.battery_discharge_year_kwh,
    battery_discharge_total_kwh: state.battery_discharge_total_kwh
  }
});

setDiagSource(state.diag, "pv_energy_day_source", pvDayResolved.source, pvDayResolved.reason);
setDiagSource(state.diag, "pv_energy_month_source", pvMonthResolved.source, pvMonthResolved.reason);
setDiagSource(state.diag, "pv_energy_year_source", pvYearResolved.source, pvYearResolved.reason);
setDiagSource(state.diag, "pv_energy_total_source", pvTotalResolved.source, pvTotalResolved.reason);

setDiagSource(state.diag, "load_energy_day_source", loadDayResolved.source, loadDayResolved.reason);
setDiagSource(state.diag, "load_energy_month_source", loadMonthResolved.source, loadMonthResolved.reason);
setDiagSource(state.diag, "load_energy_year_source", loadYearResolved.source, loadYearResolved.reason);
setDiagSource(state.diag, "load_energy_total_source", loadTotalResolved.source, loadTotalResolved.reason);

setDiagSource(state.diag, "grid_energy_day_source", "calculated", "policy_always_calculated");
setDiagSource(state.diag, "grid_energy_month_source", "calculated", "policy_always_calculated");
setDiagSource(state.diag, "grid_energy_year_source", "calculated", "policy_always_calculated");
setDiagSource(state.diag, "grid_energy_total_source", "calculated", "policy_always_calculated");

setDiagSource(state.diag, "battery_charge_day_source", "calculated", withinMidnightGuard && batteryChargeGuarded ? "midnight_guard" : "policy_always_calculated");
setDiagSource(state.diag, "battery_charge_month_source", "calculated", "policy_always_calculated");
setDiagSource(state.diag, "battery_charge_year_source", "calculated", "policy_always_calculated");
setDiagSource(state.diag, "battery_charge_total_source", "calculated", "policy_always_calculated");

setDiagSource(state.diag, "battery_discharge_day_source", "calculated", withinMidnightGuard && batteryDischargeGuarded ? "midnight_guard" : "policy_always_calculated");
setDiagSource(state.diag, "battery_discharge_month_source", "calculated", "policy_always_calculated");
setDiagSource(state.diag, "battery_discharge_year_source", "calculated", "policy_always_calculated");
setDiagSource(state.diag, "battery_discharge_total_source", "calculated", "policy_always_calculated");

state.diag.energy_dt_hours = round2(dtHours);
state.diag.energy_store_restore_stats = statsRestoreSource;
state.diag.energy_store_write_mode = "default_plus_persistent_plus_config_file";
state.diag.energy_file_store_write_ok = fileWriteOk;
state.diag.energy_file_store_key = fileInvKey;
state.diag.energy_anti_reset_active = justRestored && noNewEnergyIntegration && !dayChanged;

state.diag.energy_midnight_guard_active = withinMidnightGuard;
state.diag.energy_battery_charge_guarded = batteryChargeGuarded;
state.diag.energy_battery_discharge_guarded = batteryDischargeGuarded;

state._day_key = dayKey;
state._month_key = monthKey;
state._year_key = yearKey;
state._premium_extended_energy = premiumActive;

msg.payload = state;
return msg;

// ===============================
// PREMIUM CALC
// A placer après "Daily Energy Calc / Fallback"
// et avant "MQTT state publisher"
// ===============================

if (!msg || !msg.payload || typeof msg.payload !== "object") return msg;

const premiumActive = global.get("premium.active") === true;
if (!premiumActive) return msg;

const state = msg.payload;
const inv = msg.inverterNum ?? state.inverter ?? 1;
const now = Date.now();

// --------------------------------------------------
// Helpers
// --------------------------------------------------
function n(v) {
    const x = Number(v);
    return Number.isFinite(x) ? x : null;
}
function nz(v, fb = 0) {
    const x = Number(v);
    return Number.isFinite(x) ? x : fb;
}
function clamp(v, min, max) {
    const x = Number(v);
    if (!Number.isFinite(x)) return min;
    return Math.max(min, Math.min(max, x));
}
function round(v, d = 1) {
    const x = Number(v);
    if (!Number.isFinite(x)) return null;
    const m = Math.pow(10, d);
    return Math.round(x * m) / m;
}
function avg(arr) {
    if (!Array.isArray(arr) || !arr.length) return null;
    const vals = arr.map(Number).filter(Number.isFinite);
    if (!vals.length) return null;
    return vals.reduce((a, b) => a + b, 0) / vals.length;
}
function safeText(v, fb = "unknown") {
    if (v === null || v === undefined || v === "") return fb;
    return String(v);
}
function setNum(obj, key, val, digits = null) {
    if (!Number.isFinite(Number(val))) return;
    obj[key] = digits == null ? Number(val) : round(val, digits);
}
function getPersistent(key, fb = null) {
    const v = flow.get(key, "persistent");
    return v === undefined ? fb : v;
}
function setPersistent(key, val) {
    flow.set(key, val, "persistent");
}

function getSafeTimezone() {
    let tz = (global.get("addon_timezone") || "UTC").toString().trim();
    if (!tz) tz = "UTC";
    try {
        new Intl.DateTimeFormat("en-CA", { timeZone: tz }).format(new Date());
    } catch (e) {
        tz = "UTC";
    }
    return tz;
}

function localDayKey(d = new Date()) {
    const tz = getSafeTimezone();
    const parts = new Intl.DateTimeFormat("en-CA", {
        timeZone: tz,
        year: "numeric",
        month: "2-digit",
        day: "2-digit"
    }).formatToParts(d);

    const get = (t) => parts.find(p => p.type === t)?.value;
    return `${get("year")}-${get("month")}-${get("day")}`;
}

function localMonthKey(d = new Date()) {
    const tz = getSafeTimezone();
    const parts = new Intl.DateTimeFormat("en-CA", {
        timeZone: tz,
        year: "numeric",
        month: "2-digit"
    }).formatToParts(d);

    const get = (t) => parts.find(p => p.type === t)?.value;
    return `${get("year")}-${get("month")}`;
}

function localYearKey(d = new Date()) {
    const tz = getSafeTimezone();
    const parts = new Intl.DateTimeFormat("en-CA", {
        timeZone: tz,
        year: "numeric"
    }).formatToParts(d);

    const get = (t) => parts.find(p => p.type === t)?.value;
    return `${get("year")}`;
}

function sanitizeEnergyGap(v, totalLoad, pctFloor = 0.01, absFloor = 0.05) {
    let x = Math.max(0, nz(v));
    const load = Math.max(0, nz(totalLoad));
    const dynamicFloor = Math.max(absFloor, load * pctFloor);
    if (x < dynamicFloor) x = 0;
    return x;
}

// --------------------------------------------------
// Battery user config (premium)
// --------------------------------------------------
const sysV = Number(
    global.get(`inverter_${inv}.battery_system_voltage`) ??
    global.get("config.batterySystemVoltage") ??
    global.get("battery_system_voltage") ??
    48
);

const batteryCapacityAh = n(
    global.get(`inverter_${inv}.battery_capacity_ah`) ??
    global.get("battery_capacity_ah")
);

const batteryTotalCapacityKwh = n(
    global.get(`inverter_${inv}.battery_total_capacity_kwh`) ??
    global.get("battery_total_capacity_kwh")
);

// --------------------------------------------------
// Stats premium persistantes
// --------------------------------------------------
const statsKey = `premium_stats_inv${inv}`;
let stats = context.get(statsKey) || flow.get(statsKey, "persistent");

if (!stats || typeof stats !== "object") {
    stats = {
        dayKey: "",
        monthKey: "",
        yearKey: "",
        lastTs: now,
        battery: {
            restSamples: [],
            loadSamples: [],
            lowVoltageEventsToday: 0,
            nearLowVoltageMinutesToday: 0,
            heavyDischargeMinutesToday: 0,
            lastLowVoltageFlag: false,
            highCrateMinutesToday: 0,
            veryHighCrateMinutesToday: 0,
            highRelativePowerMinutesToday: 0,
            veryHighRelativePowerMinutesToday: 0
        },
        inverter: {
            highTempMinutesToday: 0,
            severeTempMinutesToday: 0,
            bypassMinutesToday: 0,
            faultMinutesToday: 0,
            load70MinutesToday: 0,
            load85MinutesToday: 0,
            load95MinutesToday: 0
        },
        energy: {
            gridToLoadTodayCalc: 0,
            solarToLoadTodayCalc: 0,
            gridSeenToday: false,
            gridSeenMonth: false,
            gridSeenYear: false
        }
    };
}

stats.battery = stats.battery || {};
stats.inverter = stats.inverter || {};
stats.energy = stats.energy || {};

if (!Array.isArray(stats.battery.restSamples)) stats.battery.restSamples = [];
if (!Array.isArray(stats.battery.loadSamples)) stats.battery.loadSamples = [];

if (typeof stats.energy.gridSeenToday !== "boolean") stats.energy.gridSeenToday = false;
if (typeof stats.energy.gridSeenMonth !== "boolean") stats.energy.gridSeenMonth = false;
if (typeof stats.energy.gridSeenYear !== "boolean") stats.energy.gridSeenYear = false;
if (!Number.isFinite(Number(stats.energy.gridToLoadTodayCalc))) stats.energy.gridToLoadTodayCalc = 0;
if (!Number.isFinite(Number(stats.energy.solarToLoadTodayCalc))) stats.energy.solarToLoadTodayCalc = 0;

// --------------------------------------------------
// Reset journalier / mensuel / annuel
// --------------------------------------------------
const tz = getSafeTimezone();
const dayKey = localDayKey(new Date());
const monthKey = localMonthKey(new Date());
const yearKey = localYearKey(new Date());

if (stats.dayKey !== dayKey) {
    stats.dayKey = dayKey;
    stats.lastTs = now;

    stats.battery.restSamples = [];
    stats.battery.loadSamples = [];
    stats.battery.lowVoltageEventsToday = 0;
    stats.battery.nearLowVoltageMinutesToday = 0;
    stats.battery.heavyDischargeMinutesToday = 0;
    stats.battery.lastLowVoltageFlag = false;
    stats.battery.highCrateMinutesToday = 0;
