function isLegacyMode(mode) {
  return String(mode || "").startsWith("legacy");
}

function getOutputPriorityOptions(mode, twoChoices) {
  if (twoChoices) {
    if (isLegacyMode(mode)) return ["SUB", "SBU"];
    return ["SolarUtilityBat", "SolarBatUtility"];
  }
  if (isLegacyMode(mode)) return ["USB", "SUB", "SBU"];
  return ["UtilitySolarBat", "SolarUtilityBat", "SolarBatUtility"];
}

function getOutputPriorityValueTpl(mode, twoChoices) {
  if (twoChoices) {
    if (isLegacyMode(mode)) {
      return `{% set v = ${QPIRI}.get('output_source_priority') %}
{% if v in ['SUB','SBU'] %}{{ v }}
{% elif v in ['SolarUtilityBat'] %}SUB
{% elif v in ['SolarBatUtility'] %}SBU
{% else %}{{ {0:'SUB',1:'SBU',2:'SBU',3:'SBU'}.get((${QPIRI}.get('output_source_priority_code', 0) | int), 'SUB') }}{% endif %}`;
    }
    return `{% set v = ${QPIRI}.get('output_source_priority') %}
{% if v in ['SolarUtilityBat','SolarBatUtility'] %}{{ v }}
{% elif v in ['SUB'] %}SolarUtilityBat
{% elif v in ['SBU'] %}SolarBatUtility
{% else %}{{ {0:'SolarUtilityBat',1:'SolarBatUtility',2:'SolarBatUtility',3:'SolarBatUtility'}.get((${QPIRI}.get('output_source_priority_code', 0) | int), 'SolarUtilityBat') }}{% endif %}`;
  }

  if (isLegacyMode(mode)) {
    return `{% set v = ${QPIRI}.get('output_source_priority') %}
{% if v in ['USB','SUB','SBU'] %}{{ v }}
{% elif v == 'UtilitySolarBat' %}USB
{% elif v == 'SolarUtilityBat' %}SUB
{% elif v == 'SolarBatUtility' %}SBU
{% else %}{{ {0:'USB',1:'SUB',2:'SBU',3:'SBU'}.get((${QPIRI}.get('output_source_priority_code', 0) | int), 'SBU') }}{% endif %}`;
  }

  return `{% set v = ${QPIRI}.get('output_source_priority') %}
{% if v in ['UtilitySolarBat','SolarUtilityBat','SolarBatUtility'] %}{{ v }}
{% elif v == 'USB' %}UtilitySolarBat
{% elif v == 'SUB' %}SolarUtilityBat
{% elif v == 'SBU' %}SolarBatUtility
{% else %}{{ {0:'UtilitySolarBat',1:'SolarUtilityBat',2:'SolarBatUtility',3:'SolarBatUtility'}.get((${QPIRI}.get('output_source_priority_code', 0) | int), 'SolarBatUtility') }}{% endif %}`;
}

function getChargerPriorityOptions(mode) {
  if (isLegacyMode(mode)) return ["CSO", "SNU", "OSO"];
  return ["Solar first", "Solar + Utility", "Only solar"];
}

function getChargerPriorityValueTpl(mode) {
  if (isLegacyMode(mode)) {
    return `{% set v = ${QPIRI}.get('charger_source_priority') %}
{% if v in ['CSO','SNU','OSO'] %}{{ v }}
{% elif v == 'Solar first' %}CSO
{% elif v == 'Solar + Utility' %}SNU
{% elif v == 'Only solar' %}OSO
{% else %}{{ {0:'CSO',1:'SNU',2:'OSO',3:'OSO'}.get((${QPIRI}.get('charger_source_priority_code', 0) | int), 'CSO') }}{% endif %}`;
  }

  return `{% set v = ${QPIRI}.get('charger_source_priority') %}
{% if v in ['Solar first','Solar + Utility','Only solar'] %}{{ v }}
{% elif v == 'CSO' %}Solar first
{% elif v == 'SNU' %}Solar + Utility
{% elif v == 'OSO' %}Only solar
{% else %}{{ {0:'Solar first',1:'Solar + Utility',2:'Only solar',3:'Only solar'}.get((${QPIRI}.get('charger_source_priority_code', 0) | int), 'Solar first') }}{% endif %}`;
}

// -----------------------
