                    bottom: 0;
                    width: 5px;
                    background: ${accent};
                    opacity: 0.95;
                    z-index: 1;
                }

                ha-card h1,
                ha-card h2,
                ha-card h3,
                ha-card strong {
                    color: var(--primary-text-color) !important;
                }

                ha-card p,
                ha-card li {
                    color: var(--secondary-text-color) !important;
                    opacity: 1 !important;
                }

                a {
                    color: ${accent} !important;
                }
            `
        }
    };
}

// -------------------------
// Helpers cartes
// -------------------------
function stack(cards) {
    return { type: "vertical-stack", cards: cards.filter(Boolean) };
}

function grid(columns, cards) {
    return { type: "grid", columns, square: false, cards: cards.filter(Boolean) };
}

function titleCard(title, subtitle = "", kind = "neutral") {
    return {
        type: "markdown",
        content: subtitle ? `# ${title}\n${subtitle}` : `# ${title}`,
        ...sectionBandStyle(kind, `
            ha-card {
                padding-left: 18px;
                padding-right: 18px;
            }
            ha-markdown {
                padding: 8px 4px 4px 4px !important;
            }
        `)
    };
}

function sectionTitle(title, subtitle = "", kind = "neutral") {
    return {
        type: "markdown",
        content: subtitle ? `## ${title}\n${subtitle}` : `## ${title}`,
        ...sectionBandStyle(kind, `
            ha-card {
                padding-left: 16px;
                padding-right: 16px;
            }
            ha-markdown {
                padding: 6px 4px 2px 4px !important;
            }
        `)
    };
}

function tile(entity, name, icon, kind = "neutral") {
    return {
        type: "tile",
        entity,
        name,
        icon,
        vertical: true,
        hide_state: false,
        features_position: "bottom",
        ...cardStyle(kind)
    };
}

function entitiesCard(title, entities, kind = "neutral") {
    return {
        type: "entities",
        title,
        show_header_toggle: false,
        state_color: true,
        entities: entities.filter(Boolean),
        ...cardStyle(kind, `
            .card-header {
                font-weight: 700 !important;
                padding-top: 16px !important;
            }
        `)
    };
}

function glanceCard(title, entities, columns = 4, kind = "neutral") {
    return {
        type: "glance",
        title,
        columns,
        show_state: true,
        show_name: true,
        state_color: true,
        entities: entities.filter(Boolean),
        ...cardStyle(kind, `
            .card-header {
                font-weight: 700 !important;
                padding-top: 16px !important;
            }
        `)
    };
}

function gaugeCard(entity, name, kind = "green", severity = null) {
    const base = {
        type: "gauge",
        entity,
        name,
        min: 0,
        max: 100,
        needle: true,
        ...cardStyle(kind)
    };

    if (severity) {
        base.severity = severity;
    }

    return base;
}

// =========================================================
// MINI GRAPH
// =========================================================
function miniGraph(title, entities, hours = 24, height = 260, kind = "neutral") {
    if (HAS_MINI_GRAPH) {
        return {
            type: "custom:mini-graph-card",
            name: title,
            hours_to_show: hours,
            points_per_hour: 2,
            hour24: true,
            animate: true,
            line_width: 3,
            font_size: 95,
            height,
            decimals: 2,
            show: {
                icon: false,
                name: true,
                state: true,
                legend: true,
                fill: true,
                labels: true,
                average: false,
                extrema: false
            },
            entities,
            ...cardStyle(kind)
        };
    }

    return {
        type: "history-graph",
        title,
        hours_to_show: hours,
        entities: entities.map(e => ({
            entity: typeof e === "string" ? e : e.entity,
            name: typeof e === "string" ? undefined : e.name
        })),
        ...cardStyle(kind)
    };
}

function statStrip(items) {
    return grid(
        items.length,
        items.map(i => tile(i.entity, i.name, i.icon, i.kind || "neutral"))
    );
}

