  const frames={
    voltronic:document.getElementById('frame_voltronic'),
    jkbms:document.getElementById('frame_jkbms'),
    finance:document.getElementById('frame_finance')
  };
  async function exists(url){
    try{const r=await fetch(url+'?check='+Date.now(),{cache:'no-store'});return r.ok;}catch(e){return false;}
  }
  function activate(btn){
    const mod=btn.dataset.module;
    const view=btn.dataset.view||'';
    const url=btn.dataset.url;
    buttons.forEach(b=>b.classList.remove('active'));
    btn.classList.add('active');
    Object.values(frames).forEach(f=>f.classList.remove('active'));
    empty.style.display='none';
    title.textContent=btn.dataset.title||btn.textContent.trim();
    const f=frames[mod];
    if(!f)return;
    const src=url+'?embed=1&view='+encodeURIComponent(view)+'&v='+Date.now()+'#'+encodeURIComponent(view);
    f.classList.add('active');
    if(f.dataset.src!==src){f.dataset.src=src;f.src=src;}
    f.onload=function(){
      try{f.contentWindow.postMessage({type:'smart-energy-view',module:mod,view:view},'*');}catch(e){}
    };
  }
  async function init(){
    const moduleAvailable={};
    for(const mod of Object.keys(frames)){
      const btn=buttons.find(b=>b.dataset.module===mod);
      moduleAvailable[mod]=btn ? await exists(btn.dataset.url) : false;
    }
    const availableButtons=[];
    for(const b of buttons){
      if(moduleAvailable[b.dataset.module]){b.classList.add('available');availableButtons.push(b);}else{b.classList.add('missing');}
