/* ===== JK-BMS V2 VISUEL ===== */
.bms-wall{
  display:grid;
  grid-template-columns:repeat(2,minmax(420px,1fr));
  gap:14px;
}
.bms-pack{
  position:relative;
  overflow:hidden;
  background:
    radial-gradient(circle at 15% 0%,rgba(36,224,109,.18),transparent 32%),
    radial-gradient(circle at 90% 10%,rgba(46,199,255,.12),transparent 36%),
    linear-gradient(180deg,rgba(14,27,50,.98),rgba(5,12,25,.96));
  border:1px solid rgba(126,161,206,.22);
  border-radius:22px;
  padding:14px;
  box-shadow:0 20px 60px rgba(0,0,0,.34);
}
.bms-pack:before{
  content:"";
  position:absolute;
  inset:0;
  background-image:
    linear-gradient(rgba(126,161,206,.045) 1px,transparent 1px),
    linear-gradient(90deg,rgba(126,161,206,.045) 1px,transparent 1px);
  background-size:28px 28px;
  pointer-events:none;
}
.bms-head{
  position:relative;
  z-index:1;
  display:flex;
  align-items:center;
  justify-content:space-between;
  margin-bottom:14px;
}
.bms-title{
  display:flex;
  align-items:center;
  gap:10px;
  font-size:22px;
  font-weight:1000;
  letter-spacing:-.6px;
}
