  border:1px solid rgba(36,224,109,.35);
  box-shadow:0 0 24px rgba(36,224,109,.12);
}
.bms-pill{
  padding:7px 11px;
  border-radius:999px;
  background:rgba(36,224,109,.13);
  border:1px solid rgba(36,224,109,.38);
  color:#baffcf;
  font-size:12px;
  font-weight:900;
}
.bms-body{
  position:relative;
  z-index:1;
  display:grid;
  grid-template-columns:185px 1fr;
  gap:14px;
  align-items:center;
}
.soc-ring{
  width:170px;
  height:170px;
  border-radius:50%;
  display:flex;
  align-items:center;
  justify-content:center;
  background:conic-gradient(var(--bat) 0 75%,#182335 75% 100%);
  box-shadow:0 0 45px rgba(36,224,109,.16);
}
.soc-ring-inner{
  width:113px;
  height:113px;
  border-radius:50%;
  background:#0b1424;
