  align-items:center;
  justify-content:center;
  text-align:center;
  border:1px solid rgba(126,161,206,.16);
}
.soc-ring-inner .value{
  font-size:33px;
}
.bms-main-grid{
  display:grid;
  grid-template-columns:repeat(3,1fr);
  gap:9px;
}
.bms-kpi{
  background:rgba(9,18,34,.76);
  border:1px solid rgba(126,161,206,.16);
  border-radius:15px;
  padding:10px;
  min-height:82px;
}
.bms-kpi .label{font-size:10px}
.bms-kpi .value{font-size:23px}
.bms-kpi .small{font-size:11px}
.bms-positive{border-color:rgba(36,224,109,.42)}
.bms-negative{border-color:rgba(255,95,122,.42)}
.bms-warn{border-color:rgba(255,159,67,.44)}
.bms-blue{border-color:rgba(46,199,255,.42)}
.bms-cells{
  position:relative;
  z-index:1;
  display:grid;
  grid-template-columns:repeat(4,1fr);
  gap:8px;
  margin-top:12px;
}
.cell-card{
  background:rgba(9,18,34,.72);
  border:1px solid rgba(126,161,206,.14);
  border-radius:14px;
  padding:9px;
}
.cell-card .value{font-size:21px}
.bms-temp-strip{
  position:relative;
  z-index:1;
  display:grid;
  grid-template-columns:repeat(5,1fr);
  gap:8px;
  margin-top:10px;
}
.temp-chip{
  display:flex;
  align-items:center;
  justify-content:space-between;
  gap:6px;
  background:rgba(255,159,67,.09);
  border:1px solid rgba(255,159,67,.25);
  border-radius:12px;
  padding:8px 9px;
  font-weight:900;
}
.temp-chip span{
  color:var(--muted);
  font-size:11px;
  text-transform:uppercase;
  letter-spacing:.5px;
}
.temp-chip b{
  font-size:15px;
}
.bms-alert{
  position:relative;
  z-index:1;
  margin-top:10px;
  padding:9px 10px;
  border-radius:13px;
  background:rgba(46,199,255,.08);
  border:1px solid rgba(46,199,255,.20);
  color:#cfeeff;
  font-size:12px;
  display:flex;
  justify-content:space-between;
  gap:10px;
}
@media(max-width:1200px){
  .bms-wall,.bms-body,.bms-main-grid,.bms-cells,.bms-temp-strip{grid-template-columns:1fr}
  .soc-ring{margin:auto}
}

@media(max-width:1200px){.bms-top,.bms-metrics,.cell-grid,.temp-grid{grid-template-columns:1fr}.soc-ring{width:150px;height:150px}}

@media(max-width:1200px){.shell,.dash-grid,.energy-area,.cards4,.cards5,.cards3,.cards2,.donut-row,.gauge-row{grid-template-columns:1fr}.sidebar{min-height:auto}.flowbox{height:auto;min-height:900px;padding:12px}.node,.mppt,.solar-total,.n-grid,.n-load,.n-bat,.inverter-core{position:relative;left:auto;right:auto;top:auto;bottom:auto;transform:none;width:auto;margin:10px}svg.flow{display:none}}


