  count:['sensor.voltronic_global_inverter_count']
};

function $(id){return document.getElementById(id)}
function n(v){const x=parseFloat(v);return Number.isFinite(x)?x:0}
function bad(v){return v==null||['unknown','unavailable','none',''].includes(String(v).toLowerCase())}
function valid(id){return STATES[id]&&!bad(STATES[id].state)}
function state(ids,d='--'){for(const id of ids){if(valid(id))return STATES[id].state}return d}
function num(ids){return n(state(ids,0))}
function set(id,v){const e=$(id);if(e)e.textContent=v}
function sensor(i,s){return `sensor.voltronic_inv${i}_${s}`}
function number(i,s){return `number.voltronic_inv${i}_param_${s}`}
function select(i,s){return `select.voltronic_inv${i}_param_${s}`}
function invNum(i,s,a=[]){return num([sensor(i,s),...a.map(x=>sensor(i,x))])}
function invState(i,s,a=[]){return state([sensor(i,s),...a.map(x=>sensor(i,x))])}
function bmsEntity(i,slug){return `sensor.bms_${i}_${slug}`}
function bmsState(i,slug,def='--'){return state([bmsEntity(i,slug)],def)}
function bmsNum(i,slug){return n(bmsState(i,slug,0))}
function fmt(v,d=2){return Number.isFinite(v)?v.toFixed(d):'--'}
function pctSafe(v,total){return total>0?(v/total*100):0}
function entityAttr(id,attr,def=null){return STATES[id]?.attributes?.[attr] ?? def}

function moreInfo(entityId){
  showMiniHistory(entityId);
}
function closeMiniHistory(){
  const m=$('history_modal'); if(m)m.classList.remove('open');
}
function entityName(entityId){
  if(entityId==='sv://core_v')return 'Tension onduleur';
  if(entityId==='sv://core_hz')return 'Fréquence onduleur';
  if(entityId==='sv://core_a')return 'Courant sortie onduleur';
  const st=STATES[entityId];
  return st?.attributes?.friendly_name || entityId;
}
function historyNumber(v){
  const m=String(v ?? '').replace(',','.').match(/-?\d+(?:\.\d+)?/);
  return m?parseFloat(m[0]):NaN;
}
function historyTime(row){
  let raw;
  if(Array.isArray(row)) raw=row[0];
  else raw=row?.last_changed ?? row?.last_updated ?? row?.lu ?? row?.lc ?? row?.t ?? row?.time;
  if(typeof raw==='number'){
    const ms=raw<20000000000?raw*1000:raw;
    return Number.isFinite(ms)?ms:NaN;
  }
  const ms=new Date(raw).getTime();
  return Number.isFinite(ms)?ms:NaN;
}
function historyState(row){
  return Array.isArray(row)?row[1]:(row?.state ?? row?.s ?? row?.value ?? row?.v);
}
function parseHistoryRows(json){
  const rows=(Array.isArray(json)&&Array.isArray(json[0]))?json[0]:(Array.isArray(json)?json:[]);
  return rows.map(r=>[historyTime(r), historyNumber(historyState(r))]).filter(p=>Number.isFinite(p[0])&&Number.isFinite(p[1]));
}
function getHaApiObject(){
  const tries=[];
  try{tries.push(window.hass)}catch(e){}
  try{if(window.parent&&window.parent!==window) tries.push(window.parent.hass)}catch(e){}
  try{if(window.top&&window.top!==window) tries.push(window.top.hass)}catch(e){}
  try{tries.push(window.parent?.document?.querySelector('home-assistant')?.hass)}catch(e){}
  try{tries.push(window.top?.document?.querySelector('home-assistant')?.hass)}catch(e){}
  try{tries.push(window.parent?.__smartEnergyFindHassObject?.())}catch(e){}
  return tries.find(h=>h&&typeof h==='object'&&typeof h.callApi==='function') || null;
}
function callHaApiViaShell(path, method='GET', timeout=9000){
  return new Promise((resolve,reject)=>{
    let done=false;
    const id='svha_'+Date.now()+'_'+Math.random().toString(16).slice(2);
    const timer=setTimeout(()=>{if(done)return;done=true;window.removeEventListener('message',onMsg);reject(new Error('ha_bridge_timeout'));},timeout);
    function onMsg(ev){
      const d=ev&&ev.data;
      if(!d || d.type!=='smart-energy-ha-api-response' || d.id!==id) return;
      if(done)return;done=true;clearTimeout(timer);window.removeEventListener('message',onMsg);
      if(d.ok) resolve(d.json); else reject(new Error(d.error||'ha_bridge_error'));
    }
    window.addEventListener('message',onMsg);
    try{
      if(!window.parent || window.parent===window) throw new Error('no_parent_bridge');
      window.parent.postMessage({type:'smart-energy-ha-api-request',id,method,path},'*');
    }catch(e){
      if(done)return;done=true;clearTimeout(timer);window.removeEventListener('message',onMsg);reject(e);
    }
  });
}
async function historyFetchPoints(entityId,start,end){
  const path=`history/period/${encodeURIComponent(start.toISOString())}?filter_entity_id=${encodeURIComponent(entityId)}&end_time=${encodeURIComponent(end.toISOString())}&minimal_response`;
  const hassObj=getHaApiObject();
  if(hassObj){
    try{
      const json=await hassObj.callApi('GET', path);
      const pts=parseHistoryRows(json);
      if(pts.length) return pts;
    }catch(e){ console.warn('Historique HA callApi direct indisponible', e); }
  }
  try{
    const json=await callHaApiViaShell(path,'GET',9000);
    const pts=parseHistoryRows(json);
    if(pts.length) return pts;
  }catch(e){ console.warn('Historique HA bridge shell indisponible', e); }
  if(HA_TOKEN){
    try{
      const res=await fetch('/api/'+path,{headers:{Authorization:`Bearer ${HA_TOKEN}`}});
      if(res.ok){
        const pts=parseHistoryRows(await res.json());
        if(pts.length) return pts;
      }
    }catch(e){ console.warn('Historique HA fetch token indisponible', e); }
  }
  return [];
}
function historyBmsIds(){
  const ids=Object.keys(STATES||{}).map(id=>{
    const m=id.match(/^sensor\.bms_(\d+)_soc_pourcentage$/i);
    return m?Number(m[1]):null;
  }).filter(Number.isFinite);
  if(!ids.length){
    Object.keys(STATES||{}).forEach(id=>{
      const m=id.match(/^(?:sensor|binary_sensor|number|switch)\.bms_(\d+)_/i);
      if(m)ids.push(Number(m[1]));
    });
  }
  return ids.length?[...new Set(ids)].sort((a,b)=>a-b):[1,2,3,4];
}
async function historyBmsAverage(slug,start,end){
  const all=[];
  for(const i of historyBmsIds()){
    try{all.push(...(await historyFetchPoints(`sensor.bms_${i}_${slug}`,start,end)))}catch(e){}
  }
  const buckets=new Map();
  all.forEach(([t,v])=>{
    const k=Math.round(t/300000)*300000;
    const b=buckets.get(k)||[0,0];
    b[0]+=v;b[1]+=1;buckets.set(k,b);
  });
  return [...buckets.entries()].map(([t,b])=>[Number(t),b[0]/b[1]]).sort((a,b)=>a[0]-b[0]);
}
async function showMiniHistory(entityId){
  if(!entityId) return;
  const modal=$('history_modal'), title=$('history_title'), sub=$('history_sub'), body=$('history_body');
  if(!modal||!body) return;
  modal.classList.add('open');
  if(title) title.textContent=entityName(entityId);
  if(sub) sub.textContent=entityId+' · dernières 24h';
  body.innerHTML='<div class="history-empty">Chargement de l historique...</div>';
  try{
    const syntheticCore={
      'sv://core_v':{label:'Tension onduleur',el:'core_v',unit:'V'},
      'sv://core_hz':{label:'Fréquence onduleur',el:'core_hz',unit:'Hz'},
      'sv://core_a':{label:'Courant sortie onduleur',el:'core_a',unit:'A'}
    };
    if(syntheticCore[entityId]){
      const c=syntheticCore[entityId];
      const cur=historyNumber(document.getElementById(c.el)?.textContent);
      if(title) title.textContent=c.label;
      if(sub) sub.textContent=c.label+' · valeur instantanée';
      if(Number.isFinite(cur)){
        const now=Date.now();
        const pts=Array.from({length:25},(_,i)=>[now-(24-i)*3600000,cur]);
        window.__svSyntheticHistoryUnit=Object.assign(window.__svSyntheticHistoryUnit||{},{[entityId]:c.unit});
        renderMiniHistory(entityId,pts);
        return;
      }
    }
