  if(pts.length>420){const step=Math.ceil(pts.length/420),last=pts[pts.length-1];pts=pts.filter((_,i)=>i%step===0);if(pts[pts.length-1]!==last)pts.push(last)}
  const w=1120,h=430,padL=70,padR=28,padT=48,padB=58;
  const plotW=w-padL-padR, plotH=h-padT-padB;
  const minT=Math.min(...pts.map(p=>p[0])), maxT=Math.max(...pts.map(p=>p[0]));
  const unit=(window.__svSyntheticHistoryUnit&&window.__svSyntheticHistoryUnit[entityId]) || STATES[entityId]?.attributes?.unit_of_measurement || '';
  const rawMax=Math.max(...pts.map(p=>p[1]));
  const niceMax=v=>{if(!Number.isFinite(v)||v<=0)return 1;const p=Math.pow(10,Math.floor(Math.log10(v)));const n=v/p;const step=n<=1?1:n<=2?2:n<=5?5:10;return step*p};
  const lowEnt=String(entityId).toLowerCase();
  const isPower=String(unit).trim().toUpperCase()==='W' || /power|puissance|load|pv|grid|battery/i.test(entityId);
  const isBmsCellVoltage=/^sensor\.bms_\d+_(cell_\d+_(volt|voltage)|cell_voltage_(min_value|max_value|average))$/i.test(entityId);
  const isCellDelta=/cell_voltage_delta/i.test(entityId);
  const isSoc=/(^|_)soc(_|$)|pourcentage|capacity|capacite/i.test(entityId)&&!isPower;
  const isSoh=/soh/i.test(entityId);
  const isCycle=/nombre_cycle|cycles?|cycle_/i.test(entityId);
  const isBatteryVoltage=/battery.*voltage|tension_totale_volt|global_battery_voltage|bat_voltage|bms_globales_tension_moyenne/i.test(lowEnt)&&!isBmsCellVoltage&&!isCellDelta;
  const isCurrent=/courant|current|ampere|_a$/i.test(entityId)&&!isPower;
  const isTemp=/temp|temperature|heat_sink|mos_temp|sonde/i.test(entityId);
  let minV=Math.min(0,...pts.map(p=>p[1])), maxV=isPower?(rawMax<=15000?15000:niceMax(rawMax*1.15)):niceMax(rawMax*1.35);
  if(isBmsCellVoltage){minV=2.30;maxV=3.80}
  else if(isCellDelta){minV=0;maxV=0.300}
  else if(isSoh||isSoc){minV=0;maxV=100}
  else if(isCycle){minV=0;maxV=8000}
  else if(isBatteryVoltage){minV=44;maxV=60}
