  if(minV===maxV){minV-=1;maxV+=1}
  const x=t=>padL+(t-minT)/(maxT-minT||1)*plotW;
  const y=v=>padT+plotH-(v-minV)/(maxV-minV||1)*plotH;
  const line=pts.map((p,i)=>(i?'L':'M')+x(p[0]).toFixed(1)+' '+y(p[1]).toFixed(1)).join(' ');
  const cur=pts[pts.length-1][1];
  const fmtTime=t=>new Date(t).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'});
  const fmtAxis=v=>isCellDelta?v.toFixed(3):(Math.abs(v)<10&&!Number.isInteger(v)?v.toFixed(2):v.toFixed(0));
  const yTicks=[1,.75,.5,.25,0].map(r=>{
    const yy=padT+plotH*(1-r), val=minV+(maxV-minV)*r;
    return `<line x1="${padL}" y1="${yy.toFixed(1)}" x2="${(w-padR).toFixed(1)}" y2="${yy.toFixed(1)}" stroke="rgba(126,161,206,.16)" stroke-width="1"/><text x="${padL-12}" y="${(yy+5).toFixed(1)}" fill="#b8c7dd" font-size="13" font-weight="900" text-anchor="end">${fmtAxis(val)}</text>`;
  }).join('');
  const xTicks=[0,.25,.5,.75,1].map(r=>{
    const xx=padL+plotW*r, tt=minT+(maxT-minT)*r;
    return `<line x1="${xx.toFixed(1)}" y1="${padT}" x2="${xx.toFixed(1)}" y2="${padT+plotH}" stroke="rgba(126,161,206,.11)" stroke-width="1"/><text x="${xx.toFixed(1)}" y="${h-17}" fill="#b8c7dd" font-size="13" font-weight="900" text-anchor="${r===0?'start':r===1?'end':'middle'}">${fmtTime(tt)}</text>`;
  }).join('');
  const lastLabel=new Date(pts[pts.length-1][0]).toLocaleString([], {day:'2-digit',month:'2-digit',hour:'2-digit',minute:'2-digit'});
  body.innerHTML=`<svg class="history-svg sv-history-clean" viewBox="0 0 ${w} ${h}" preserveAspectRatio="none">
    <defs><filter id="histCyanGlow"><feGaussianBlur stdDeviation="1.8" result="b"/><feMerge><feMergeNode in="b"/><feMergeNode in="SourceGraphic"/></feMerge></filter></defs>
    <rect x="0" y="0" width="${w}" height="${h}" fill="#06101d"/>
    ${yTicks}${xTicks}
    <path d="${line}" fill="none" stroke="rgba(46,199,255,.22)" stroke-width="7" stroke-linecap="round" stroke-linejoin="round" filter="url(#histCyanGlow)"></path>
    <path d="${line}" fill="none" stroke="#2ec7ff" stroke-width="3.8" stroke-linecap="round" stroke-linejoin="round"></path>
    <rect class="history-hit" x="${padL}" y="${padT}" width="${plotW}" height="${plotH}" fill="transparent" onmousemove="historyTooltip(event,'${lastLabel}',${cur},'${unit}')" onmouseleave="hideHistoryTooltip()"/>
    <text x="${w-28}" y="36" fill="#edf5ff" font-size="27" font-weight="1000" text-anchor="end">${cur.toFixed(2)}${unit?' '+unit:''}</text>
  </svg>`;
}
