function svgHistory(data){
  const W=920,H=320,padL=48,padB=38,top=24,plotW=W-padL-24,plotH=H-padB-top;
  const max=Math.max(...data.flatMap(d=>[d.solar+d.battery,d.total]),1);
  const step=plotW/(data.length||1), bw=Math.max(9,Math.min(30,step*.56));
  let bars='', line='', dots='', labels='', hit='';
  data.forEach((d,i)=>{
    const x=padL+step*i+step/2; const base=top+plotH;
    const hs=Math.max(0,d.solar/max*plotH), hb=Math.max(0,d.battery/max*plotH);
    const ySolar=base-hs, yBat=base-hs-hb, total=d.total || d.solar+d.battery, yLine=base-(total/max*plotH);
    bars+=`<rect x="${x-bw/2}" y="${ySolar}" width="${bw}" height="${hs}" rx="6" fill="#ffc928" opacity=".92"/>`;
    bars+=`<rect x="${x-bw/2}" y="${yBat}" width="${bw}" height="${hb}" rx="6" fill="#24e06d" opacity=".94"/>`;
    line+=(i?' L':'M')+x+' '+yLine;
    dots+=`<circle cx="${x}" cy="${yLine}" r="4.5" fill="#38bdf8"/>`;
    hit+=`<rect class="eco-hit" x="${x-step/2}" y="${top}" width="${step}" height="${plotH}" fill="#38bdf8" opacity="0" onmousemove="showEcoTip(event,'${d.label}',${d.solar},${d.battery},${total})" onmouseleave="hideEcoTip()" onclick="moreInfo('sensor.smart_energy_finance_history_archive')"/>`;
    if(i%Math.ceil(data.length/8)===0||i===data.length-1) labels+=`<text x="${x}" y="${H-11}" text-anchor="middle" fill="#91a7c4" font-size="12" font-weight="800">${d.label}</text>`;
  });
  const grid=[0,.25,.5,.75,1].map(t=>{const y=top+plotH*t; const val=max*(1-t); return `<line x1="${padL}" y1="${y}" x2="${W-20}" y2="${y}" stroke="rgba(145,167,196,.15)"/><text x="${padL-8}" y="${y+4}" text-anchor="end" fill="#91a7c4" font-size="11" font-weight="700">${val.toFixed(0)}€</text>`}).join('');
  return `<svg viewBox="0 0 ${W} ${H}" class="svg-chart"><defs><filter id="glow"><feGaussianBlur stdDeviation="3" result="b"/><feMerge><feMergeNode in="b"/><feMergeNode in="SourceGraphic"/></feMerge></filter><linearGradient id="lineGrad" x1="0" x2="1"><stop offset="0" stop-color="#38bdf8"/><stop offset="1" stop-color="#a855f7"/></linearGradient></defs><rect x="0" y="0" width="${W}" height="${H}" fill="transparent"/>${grid}${bars}<path d="${line}" fill="none" stroke="url(#lineGrad)" stroke-width="4" filter="url(#glow)" stroke-linecap="round" stroke-linejoin="round"/>${dots}${labels}${hit}</svg>`;
}
