function websocketUrl(){
  const proto=location.protocol==='https:'?'wss://':'ws://';
  return proto+location.host+'/api/websocket';
}
function connectWebsocket(token){
  try{ if(WS && WS.readyState===WebSocket.OPEN) WS.close(); }catch(e){}
  WS=new WebSocket(websocketUrl());
  WS.onmessage=ev=>{
    let msg; try{msg=JSON.parse(ev.data)}catch(e){return}
    if(msg.type==='auth_required') WS.send(JSON.stringify({type:'auth',access_token:token}));
    if(msg.type==='auth_ok'){
      removeHaTokenNotice();
      WS.send(JSON.stringify({id:1,type:'get_states'}));
      WS.send(JSON.stringify({id:2,type:'subscribe_events',event_type:'state_changed'}));
    }
    if(msg.type==='auth_invalid'){
      console.warn('Authentification HA invalide');
      showHaTokenNotice();
    }
    if(msg.id===1 && msg.type==='result' && Array.isArray(msg.result)){
      msg.result.forEach(e=>STATES[e.entity_id]=e);
      scheduleUpdate();
    }
    if(msg.id===2 && msg.type==='event'){
      const e=msg.event?.data?.new_state;
      if(e){STATES[e.entity_id]=e;scheduleUpdate()}
    }
  };
  WS.onerror=()=>{console.warn('Erreur websocket HA'); showHaTokenNotice();};
  WS.onclose=()=>{setTimeout(async()=>{const t=await getToken(); if(t) connectWebsocket(t);},4000)};
}
let STARTING=false;
async function start(){
  if(STARTING) return;
  STARTING=true;
  try{
    setInterval(()=>set('clock',new Date().toLocaleTimeString()),1000);
    try{renderInverters()}catch(e){console.error(e)}
    try{updateEcoCharts()}catch(e){console.error(e)}
    const token=await getToken();
    HA_TOKEN=token;
    if(!token){
      console.warn('Token HA introuvable. Affichage du panneau de connexion manuelle.');
      showHaTokenNotice();
      try{update()}catch(e){console.error(e)}
      return;
    }
    connectWebsocket(token);
  } finally {
    setTimeout(()=>{STARTING=false},500);
  }
}


