  const isMissing=v=>{const l=low(v);return !l||['--','unknown','unavailable','null','undefined'].includes(l)};
  const numberFrom=v=>{const n=parseFloat(txt(v).replace(',','.'));return Number.isFinite(n)?n:null};
  const stateNumber=id=>{const st=state(id);if(!st||isMissing(st.state))return null;return numberFrom(st.state)};
  const stateText=id=>{const st=state(id);return st&&!isMissing(st.state)?txt(st.state):''};
  const textNumber=id=>{const el=$(id);const n=numberFrom(el?.textContent);return n===null?null:n};
