  function batteryCurrentValue(){const v=exactNumber('sensor.voltronic_global_battery_global_current');if(v!==null)return v;const p=batteryPowerValue(),bv=calcBatV();return p!==null&&bv?Math.abs(p/bv):null}
  function findWarnEntity(i){
