  }
  function directFaultStatus(i){const raw=stateText(`sensor.voltronic_inv${i}_diag_fault_state`);return isOk(raw)?{level:0,cls:'alarm-ok',txt:'OK',entity:`sensor.voltronic_inv${i}_diag_fault_state`}:{level:2,cls:'alarm-fault',txt:raw||'ALARME',entity:`sensor.voltronic_inv${i}_diag_fault_state`}}
