    try{const p=window.parent&&window.parent!==window?window.parent:null;if(p&&p.document){const btn=[...p.document.querySelectorAll('button,a,.tab,.nav button,.sidebar button')].find(e=>/JK\-?BMS/i.test((e.textContent||'')));if(btn)btn.click();setTimeout(()=>{try{const frames=[...p.document.querySelectorAll('iframe')];for(const fr of frames){try{if(fr&&fr.contentWindow){fr.contentWindow.postMessage({type:'smart_energy_open_bms_alarm',bms:i,view:'alarms'},'*');if(typeof fr.contentWindow.openBms==='function')fr.contentWindow.openBms(i);if(typeof fr.contentWindow.setBmsView==='function')fr.contentWindow.setBmsView('battery',i);if(typeof fr.contentWindow.setBmsTab==='function')fr.contentWindow.setBmsTab(i,'alarms');if(typeof fr.contentWindow.updateBms==='function')fr.contentWindow.updateBms()}}catch(e){}}}catch(e){}},300)}}catch(e){}
  }
