  }
  const ent={
    load:()=>first(['sensor.voltronic_global_load_power','sensor.voltronic_global_ac_output_active_power'],[['voltronic','global','load','power']],'sensor'),
    loadDay:()=>first(['sensor.voltronic_global_load_today_kwh','sensor.voltronic_global_load_energy_day_kwh','sensor.voltronic_global_load_today'],[['voltronic','global','load','today']],'sensor'),
