    chargeDay:()=>first(['sensor.voltronic_global_battery_charge_today_kwh','sensor.voltronic_global_battery_charge_day_kwh','sensor.voltronic_global_battery_charge_today'],[['voltronic','battery','charge','today']],'sensor'),
