  function tempInvValue(i){const direct=stateNumber(`sensor.voltronic_inv${i}_inverter_heat_sink_temp`);if(direct!==null)return direct;if(typeof tempInv==='function'){const v=numberFrom(tempInv(i));if(v!==null&&v!==0)return v}return firstNumber([`sensor.voltronic_inv${i}_heat_sink_temperature`,`sensor.voltronic_inv${i}_inverter_temperature`,`sensor.voltronic_inv${i}_internal_temperature`,`sensor.voltronic_inv${i}_q1_internal_temperature`],[['voltronic','inv'+i,'heat','sink'],['voltronic','inverter',String(i),'temperature']],'sensor')}
  function bmsTempEntity(){const preferred=['sensor.bms_1_sonde_1_temp','sensor.bms_1_sonde_2_temp','sensor.bms_1_mos_temp','sensor.bms_1_bms_temperature','sensor.bms_1_temperature','sensor.bms_1_temp','sensor.bms_1_temperature_1'];for(const id of preferred){if(state(id))return id}return Object.keys(states()).find(id=>id.startsWith('sensor.bms_1')&&id.toLowerCase().includes('temp')&&!/min|max|limit|protect|warning|alarm|delta|diff/.test(id.toLowerCase()))||preferred[0]}
  function bmsTempValue(){
