<script>
(function(){
  if(window.__SV_MOBILE_NATIVE_PIEUVRE_HISTORY__) return;
  window.__SV_MOBILE_NATIVE_PIEUVRE_HISTORY__ = true;
  function isMobile(){
    try{return !!((window.matchMedia&&window.matchMedia('(max-width: 760px)').matches)||(window.matchMedia&&window.matchMedia('(pointer: coarse)').matches));}catch(e){return false;}
  }
  function findHass(){
    var tries=[];
    function add(x){try{if(x&&tries.indexOf(x)<0)tries.push(x);}catch(e){}}
    function scan(root,depth){
      if(!root||depth>5) return;
      try{add(root.hass);}catch(e){}
      var sels=['home-assistant','home-assistant-main','ha-panel-lovelace','hui-root','partial-panel-resolver'];
      for(var i=0;i<sels.length;i++){
        try{var el=root.querySelector&&root.querySelector(sels[i]); if(el){add(el.hass); if(el.shadowRoot)scan(el.shadowRoot,depth+1);}}catch(e){}
      }
    }
    try{add(window.hass);}catch(e){}
    try{add(window.parent&&window.parent.hass);}catch(e){}
    try{add(window.top&&window.top.hass);}catch(e){}
    try{scan(document,0);}catch(e){}
    try{if(window.parent&&window.parent!==window)scan(window.parent.document,0);}catch(e){}
    try{if(window.top&&window.top!==window)scan(window.top.document,0);}catch(e){}
    return tries.find(function(h){return h&&typeof h==='object';})||null;
  }
  function fireMoreInfo(entityId){
    var h=findHass();
    try{ if(h&&typeof h.moreInfo==='function'){ h.moreInfo(entityId); return true; } }catch(e){}
    var ev;
    try{ ev=new CustomEvent('hass-more-info',{detail:{entityId:entityId},bubbles:true,composed:true}); document.dispatchEvent(ev); }catch(e){}
    try{ ev=new CustomEvent('hass-more-info',{detail:{entityId:entityId},bubbles:true,composed:true}); if(window.parent&&window.parent.document) window.parent.document.dispatchEvent(ev); }catch(e){}
    try{ ev=new CustomEvent('hass-more-info',{detail:{entityId:entityId},bubbles:true,composed:true}); if(window.top&&window.top.document) window.top.document.dispatchEvent(ev); return true; }catch(e){}
    return false;
  }
  function entityForPieuvre(el){
    if(!el) return '';
    if(el.matches('.mppt-1-1')) return 'sensor.voltronic_inv1_pv1_power';
    if(el.matches('.mppt-1-2')) return 'sensor.voltronic_inv1_pv2_power';
    if(el.matches('.mppt-2-1')) return 'sensor.voltronic_inv2_pv1_power';
