    return m?m[1]:'';
  }
  function bind(){
    var root=document.querySelector('.flowbox');
    if(!root||root.__svNativePieuvreBound) return;
    root.__svNativePieuvreBound=true;
    ['click','pointerup'].forEach(function(type){
      root.addEventListener(type,function(ev){
        if(!isMobile()) return;
        var target=ev.target&&ev.target.closest?ev.target.closest('.node,.inverter-core'):null;
        if(!target||!root.contains(target)) return;
