const MOBILE_FLOW_FULL_FIT_PATCH = `<script>
(function(){
  const BASE_W = 1020;
  const BASE_H = 680;
  const POS = {
    '.left1':       {left:'18px',  top:'44px',  width:'205px'},
    '.left2':       {left:'18px',  top:'180px', width:'205px'},
    '.right1':      {right:'18px', top:'44px',  width:'205px'},
    '.right2':      {right:'18px', top:'180px', width:'205px'},
    '.solar-total': {left:'50%',   top:'16px',  width:'250px', transform:'translateX(-50%)'},
    '.n-grid':      {left:'18px',  top:'380px', width:'205px'},
    '.n-load':      {right:'18px', top:'380px', width:'220px'},
    '.n-bat':       {left:'50%',   bottom:'8px',width:'300px', transform:'translateX(-50%)'}
  };
  function imp(el,k,v){ if(el) el.style.setProperty(k,v,'important'); }
  function clean(el,k){ if(el) el.style.removeProperty(k); }
  function isMobile(){ return window.matchMedia && window.matchMedia('(max-width: 760px)').matches; }
  function restoreMobilePieuvre(){
    if(window.__SV_MOBILE_FLOW_V62_ACTIVE__) return;
    const flow = document.querySelector('#global .flowbox');
    if(!flow) return;
    const panel = flow.closest('.panel') || flow.parentElement;
    if(!isMobile()){
      flow.classList.remove('sv-mobile-full-pieuvre');
      ['width','height','min-height','max-width','overflow','transform','transform-origin','margin','margin-bottom','display','position'].forEach(k=>clean(flow,k));
      if(panel) clean(panel,'overflow');
      return;
    }
    const available = Math.max(300, Math.min(window.innerWidth - 28, (panel ? panel.clientWidth : window.innerWidth) - 20));
    const scale = Math.max(0.26, Math.min(0.62, available / BASE_W));
    const visualH = Math.ceil(BASE_H * scale);

    flow.classList.add('sv-mobile-full-pieuvre');
    imp(flow,'position','relative');
    imp(flow,'display','block');
    imp(flow,'width',BASE_W+'px');
    imp(flow,'height',BASE_H+'px');
    imp(flow,'min-height',BASE_H+'px');
    imp(flow,'max-width','none');
    imp(flow,'overflow','hidden');
    imp(flow,'transform','scale('+scale+')');
    imp(flow,'transform-origin','top left');
    imp(flow,'margin','0 0 '+(-BASE_H + visualH + 8)+'px 0');
    if(panel) imp(panel,'overflow','hidden');

    const svg = flow.querySelector('svg.flow');
    if(svg){
      imp(svg,'display','block');
      imp(svg,'position','absolute');
      imp(svg,'inset','0');
      imp(svg,'width','100%');
      imp(svg,'height','100%');
    }
    flow.querySelectorAll('.node,.mppt,.solar-total,.n-grid,.n-load,.n-bat').forEach(el=>{
      imp(el,'position','absolute');
      imp(el,'margin','0');
      imp(el,'max-width','none');
    });
    Object.keys(POS).forEach(sel=>{
      const el = flow.querySelector(sel);
      if(!el) return;
      const p = POS[sel];
      ['left','right','top','bottom','width','transform'].forEach(k=>{
        if(p[k]) imp(el,k,p[k]); else clean(el,k);
      });
    });
    const core = flow.querySelector('.inverter-core');
    if(core){
      imp(core,'position','absolute');
      imp(core,'left','50%');
      imp(core,'top','45%');
      imp(core,'transform','translate(-50%,-50%)');
      imp(core,'width','225px');
      imp(core,'height','285px');
      imp(core,'margin','0');
    }
  }
  window.svRestoreMobilePieuvre = restoreMobilePieuvre;
  window.addEventListener('resize', restoreMobilePieuvre, {passive:true});
  window.addEventListener('orientationchange', function(){ setTimeout(restoreMobilePieuvre,250); }, {passive:true});
  document.addEventListener('DOMContentLoaded', function(){ setTimeout(restoreMobilePieuvre,300); setTimeout(restoreMobilePieuvre,1000); });
  const oldUpdate = window.update;
  if(typeof oldUpdate === 'function' && !oldUpdate.__svMobilePieuvreWrapped){
    const wrapped = function(){ const r = oldUpdate.apply(this, arguments); setTimeout(restoreMobilePieuvre,0); return r; };
    wrapped.__svMobilePieuvreWrapped = true;
    window.update = wrapped;
  }
  setInterval(restoreMobilePieuvre, 1500);
  restoreMobilePieuvre();
})();
</script>`;
