            "Écriture fs incomplète : " + JSON.stringify({
                index_file: INDEX_FILE,
                index_exists: indexExists,
                index_size: indexSize,
                voltronic_file: VOLTRONIC_FILE,
                voltronic_exists: voltronicExists,
                voltronic_size: voltronicSize
            }),
            msg
        );
        return null;
    }

    node.status({
        fill: "green",
        shape: "dot",
        text: `Voltronic HTML v71.4 mobile inverter pv va bigger OK : ${voltronicSize} o`
    });

} catch (e) {
    node.error("Erreur écriture fs dashboard HTML : " + e.message, msg);
    return null;
}

// Une seule sortie : déclenche uniquement BUILD SHARED IFRAME DASHBOARD
return msgIframe;

const inputEnv = msg.payload.toString().trim();

let configPath;
let statusColor;
let bip;

switch(inputEnv) {
    case 'HAOS':
        configPath = '/data/options.json';
        msg.environment = 'Home Assistant OS';
        bip = 1;
        statusColor = 'green';
        break;
    case 'Docker':
        configPath = '/data/options.json';
        msg.environment = 'Docker (autre)';
        bip = 2;
        statusColor = 'blue';
        break;
    case 'Linux':
        configPath = '/data/options.json';
        msg.environment = 'Linux barebone';
        bip = 3;
        statusColor = 'yellow';
        break;
    case 'Windows':
        configPath = 'C:\\data\\options.json';
        msg.environment = 'Windows';
        bip = 4;
        statusColor = 'purple';
        break;
    default:
        configPath = './data/options.json';
        msg.environment = 'Inconnu';
        bip = 5;
        statusColor = 'red';
}

// 2ème digit : premium actif ou non
const premium = global.get('premium') || {};
const premiumDigit = (premium.status === 'active') ? '1' : '0';

msg.filename = configPath;
msg.payload = { "bip": String(bip) + premiumDigit };  // ex: "11", "10", "21"...
msg.headers = { "Content-Type": "application/json" };
node.status({fill: statusColor, shape: "dot", text: msg.environment});
return msg;
